INSERT INTO public.photos VALUES (24122, 'Plaza de Espa‚îú‚ñía 1938', 'Imagen capturada en las escaleras del acceso principal a la Diputaci‚îú‚îÇn provincial, con un posado colectivo tras la ceremonia que tuvo como escenario el sal‚îú‚îÇn de sesiones consistente en la imposici‚îú‚îÇn de medallas y brazales a las "Damas enfermeras" de la Cruz Roja de la provincia (107 de Zaragoza, presentes en el acto, adem‚îú√≠s de 45 de Ejea, 11 de Gallur y 11 de Tauste) el domingo 23 de octubre del "Tercer A‚îú‚ñío Triunfal". En primera fila y en el centro, la "Seren‚îú¬°sima" Infanta de Espa‚îú‚ñía, Mercedes de Baviera y Borb‚îú‚îÇn. Junto a ella y a la siniestra, el conde de Vallellano, Jefe Supremo de la Cruz Roja Espa‚îú‚ñíola, el obispo de Cumana (Venezuela) y el doctor ‚îú√¨‚îú‚ñíigo, jefe provincial de la Cruz Roja. Tras la infanta y en altura, la marquesa de Valdeiglesias, la duquesa de la Victoria, la marquesa de B‚îú‚îÇveda de Limia, la condesa de Castilfal‚îú¬Æ y M‚î¨¬¨ Escudero de Allu‚îú¬Æ Salvador. Completan el encuadre diversas autoridades de Zaragoza con el alcalde Antonio Parellada, el presidente de la Diputaci‚îú‚îÇn Miguel Allu‚îú¬Æ Salvador, y representantes de la 5‚î¨¬¨ Regi‚îú‚îÇn Militar, FET-JONS, Audiencia provincial, Universidad, Cruz Roja local y Gobierno militar. Los discursos que adornaron el evento loaron el papel de estas "damas del Buen Amor" como "dignas descendientes de Agustina de Arag‚îú‚îÇn y la condesa de Bureta", cuya misi‚îú‚îÇn es complementaria con la del m‚îú¬Ædico, "debiendo comprender la diferencia que hay entre sus limitados conocimientos y los del m‚îú¬Ædico, plenos de ciencia y estudio", y siempre con "absoluta sumisi‚îú‚îÇn al Caudillo, porque decir Franco es decir Espa‚îú‚ñía". No se dej‚îú‚îÇ pasar la ocasi‚îú‚îÇn para diferenciar "entre la mujer femenina, virtuosa y espa‚îú‚ñíola, es decir cristiana, de las viragos (vulgo marimachos), las desgre‚îú‚ñíadas, las milicianas procaces que incorporadas a la chusma recorren las calles de las poblaciones dominadas por la canalla marxista". El simp‚îú√≠tico evento termin‚îú‚îÇ con los preceptivos vivas al Ej‚îú¬Ærcito, a Espa‚îú‚ñía, a Franco y el inane latiguillo "‚î¨√≠Arriba Espa‚îú‚ñía!", en un clima de entusiasta', 1938, 1938, 1938, 'Anos 30', 'CENTRO', 41.65210400, -0.88158800, '0101000020E61000003A799109F835ECBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54255969908.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54255969908.webp', 'https://www.flickr.com/photos/zaragozaantigua/54255969908/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24127, 'Plaza de la Constituci‚îú‚îÇn 1916', 'Fotograma de un reportaje dedicado a la multitudinaria comitiva que acompa‚îú‚ñí‚îú‚îÇ a los exploradores zaragozanos (asociaci‚îú‚îÇn constituida unos a‚îú‚ñíos antes e inspirada en los Boy Scouts de Robert Baden-Powell) que en n‚îú‚ïëmero de doce, m‚îú√≠s un jefe instructor fueron andando hasta Madrid para entregar al periodista local Mariano de Cavia ("el Cervantes de la Espa‚îú‚ñía de hoy") un mensaje de felicitaci‚îú‚îÇn acompa‚îú‚ñíado de doce mil firmas con motivo de haberle concedido el Gobierno la gran Cruz de Alfonso XII. Mientras que el viaje de ida fue cubierto con jornadas de 30 kil‚îú‚îÇmetros diarios "en el coche de San Servando", los exploradores realizaron el viaje de vuelta en el r‚îú√≠pido de la tarde del 16 de marzo de ese a‚îú‚ñío, llegando hasta la estaci‚îú‚îÇn de Campo Sepulcro donde fueron recibidos por una multitud que luego les acompa‚îú‚ñí‚îú‚îÇ por el centro de la ciudad y en comitiva hasta el templo del Pilar. La imagen se centra en el paso por la plaza de la Constituci‚îú‚îÇn del autom‚îú‚îÇvil A. Darracq con matr‚îú¬°cula n‚îú‚ïëmero 21 de Zaragoza, integrante de la comitiva y flanqueado por numeroso p‚îú‚ïëblico.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65198400, -0.88127700, '0101000020E610000099F1B6D26B33ECBFF4C1323674D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54709251680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54709251680.webp', 'https://www.flickr.com/photos/zaragozaantigua/54709251680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24161, 'Coso Alto 1925', 'Imagen del Sal‚îú‚îÇn de fiestas del Centro Mercantil, habilitado como escenario expositivo del I Sal‚îú‚îÇn Internacional de Fotograf‚îú¬°a organizado por la Sociedad Fotogr‚îú√≠fica de Zaragoza. En el grupo central, y de espaldas, el fot‚îú‚îÇgrafo Juan Mora Insa. Fuente visual: www.rsfz.es/', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65274200, -0.88126800, '0101000020E6100000CD5CE0F25833ECBFE25CC30C8DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33414861810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33414861810.webp', 'https://www.flickr.com/photos/zaragozaantigua/33414861810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24221, 'Plaza Espa‚îú‚ñía 1958', 'Octubre de 1958. Plaza de Espa‚îú‚ñía de Zaragoza, vista desde su confluencia con el paseo de la Independencia. Se distinguen a la izquierda las barandillas de los urinarios p‚îú‚ïëblicos. Las luces decorativas colocadas con motivo de las fiestas del Pilar compiten con los neones publicitarios. Fuente: Colecci‚îú‚îÇn Jos‚îú¬Æ Vicente Moreno.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65168700, -0.88123200, '0101000020E61000009A0986730D33ECBF3B1DC87A6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15788691876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15788691876.webp', 'https://www.flickr.com/photos/zaragozaantigua/15788691876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24222, 'Congreso cat‚îú‚îÇlico 1890', 'Segundo Congreso Cat‚îú‚îÇlico Nacional Espa‚îú‚ñíol. Zaragoza, octubre de 1890. Entre los actos de este rancio evento, la ilustraci‚îú‚îÇn refleja la actuaci‚îú‚îÇn de una banda de m‚îú‚ïësica militar en la plaza de la Constituci‚îú‚îÇn, aparte de lo que sea que est‚îú¬Æn haciendo en el estrado de la derecha, ante el edificio de la Diputaci‚îú‚îÇn Provincial.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15889916902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15889916902.webp', 'https://www.flickr.com/photos/zaragozaantigua/15889916902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24482, 'Bazar X 1970', 'Foto: Jos‚îú¬Æ Laporta. Situado en el n‚îú‚ïëmero 25 del Coso Alto, el Bazar X cerr‚îú‚îÇ en enero de 1974. En su ubicaci‚îú‚îÇn se levanta hoy el comercio FNAC. Fuente: www.rafaelcastillejo.com', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65299200, -0.88161000, '0101000020E61000002E73BA2C2636ECBF5A46EA3D95D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23219434114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23219434114.webp', 'https://www.flickr.com/photos/zaragozaantigua/23219434114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24518, 'Galer‚îú¬°as Preciados 1971', 'El s‚îú√≠bado 27 de marzo de 1971 a las 19.30 y en la planta sexta se inauguraron los grandes almacenes Galer‚îú¬°as Preciados, en el paseo de la Independencia 13, seg‚îú‚ïën proyecto de 1969 de Francisco Bass‚îú‚îÇ Birul‚îú¬Æs y Javier Mart‚îú¬°nez Feduchi. El acto estuvo presidido por el presidente de la Audiencia Territorial, Jos‚îú¬Æ Hijas Palacios, acompa‚îú‚ñíado del presidente de la Diputaci‚îú‚îÇn Provincial, Pedro Baringo Rosinach, el fiscal de la Audiencia, Luis Mart‚îú¬°n Ballesteros, el rector de la Universidad, Justiniano Casas Pel‚îú√≠ez, el alcalde, Mariano Horno Liria, el delegado de Informaci‚îú‚îÇn y Turismo, Enrique Gonz‚îú√≠lez Albaladejo, el jefe superior de Polic‚îú¬°a, Joaqu‚îú¬°n D‚îú¬°az Moreno, el delegado provincial de Sindicatos, Rafael Ruiz Ortega, el delegado provincial de Trabajo, Camilo Sueiro Rodr‚îú¬°guez, y Jos‚îú¬Æ Manuel Fern‚îú√≠ndez, hijo del due‚îú‚ñío y fundador de Galer‚îú¬°as Preciados, Jos‚îú¬Æ "Pep‚îú¬°n" Fern‚îú√≠ndez Rodr‚îú¬°guez. Asistieron tambi‚îú¬Æn los directores de las emisoras de radio, de la prensa y de las entidades bancarias locales. David Aznar, de la parroquia de San Miguel, bendijo las instalaciones invocando a la Virgen del Pilar, momento que recoge la imagen. Los asistentes rezaron un Ave Mar‚îú¬°a por la prosperidad de ese comercio, cuya casa madre fue fundada en 1943 en Madrid. En 1979 el control pasa al Banco Urquijo, con el que se hab‚îú¬°a endeudado, y en 1981 lo compra Rumasa, empresa del estafador del Opus Dei Jos‚îú¬Æ Mar‚îú¬°a Ruiz-Mateos expropiada en 1983. El multimillonario venezolano Gustavo Cisneros, c‚îú‚îÇmplice del presidente del gobierno Felipe Gonz‚îú√≠lez, lo compr‚îú‚îÇ al Estado por 750 millones de pesetas en 1984, vendi‚îú¬Ændolo por 30.000 millones en 1987. Tras otros cambios de manos, en 1995 fue absorbido por su rival, El Corte Ingl‚îú¬Æs. Fuente: "Bolet‚îú¬°n Galer‚îú¬°as Preciados", abril de 1971. Colecci‚îú‚îÇn particular de Fernando Defboy.', 1971, 1971, 1971, 'Anos 70', 'CENTRO', 41.65099400, -0.88162000, '0101000020E610000011FC6F253B36ECBF34F279C553D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36398335162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36398335162.webp', 'https://www.flickr.com/photos/zaragozaantigua/36398335162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24542, 'P.‚î¨‚ïë de la Independencia 1962', 'In‚îú¬Ædita imagen capturada en el interior de la tienda de "venta de aparatos" electrodom‚îú¬Æsticos de la empresa Gas de Zaragoza SA sita en el n‚îú‚ïëmero 11 del paseo de la Independencia y centrada en una se‚îú‚ñíorita dependienta atendiendo el tel‚îú¬Æfono (tal vez el aparato menos "moderno" de todos los que aparecen en la imagen) tras su mesa de escritorio. Completan el posado publicitario algunos de los aparatos electrodom‚îú¬Æsticos que utilizaban el gas butano como combustible y que pod‚îú¬°an adquirirse en este espacio comercial: cocinas de diversos tama‚îú‚ñíos, termo de agua caliente, etc., e incluso artilugios complementarios como el "Transport‚îú¬°n Ucl‚îú¬Æs" que facilitaba el transporte y manejo de la bombona de butano en el domicilio particular de las usuarias. No muy lejos, en el n‚îú‚ïëmero 10 de la calle de San Miguel, el "Palacio de la Luz" o sede social de esta empresa contaba con otra tienda de estas mismas caracter‚îú¬°sticas. Primeros signos de una sociedad de consumo a la espa‚îú‚ñíola.', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.65109400, -0.88163100, '0101000020E61000000C7904375236ECBF984F560C57D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53158694570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53158694570.webp', 'https://www.flickr.com/photos/zaragozaantigua/53158694570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24546, 'Coso alto c.1948', 'Portada del n‚î¨‚ïë 27 del tramo alto del Coso donde estaba ubicado el establecimiento comercial "Bazar X", con el aspecto tras la reforma proyectada por los arquitectos Teodoro R‚îú¬°os Balaguer y Teodoro R‚îú¬°os Us‚îú‚îÇn a comienzos de los a‚îú‚ñíos 40.', 1948, 1948, 1948, 'Anos 40', 'CENTRO', 41.65287500, -0.88159100, '0101000020E61000007E552E54FE35ECBF21B0726891D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54395670738.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54395670738.webp', 'https://www.flickr.com/photos/zaragozaantigua/54395670738/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24851, 'Calle de la Independencia c.1899', 'Imagen de la calle de la Independencia en su tramo de los pares m‚îú√≠s inmediato a la plaza de la Constituci‚îú‚îÇn, entre los porches y el arbolado and‚îú¬Æn central. La esquina de primer plano mutar‚îú√≠ unas cuantas veces en el siglo venidero. Al fondo, la fachada del Coso a esta plaza. El estacionamiento de veh‚îú¬°culos, libre. Se trata de otra de las postales de la serie de "Laurent" realizada a‚îú‚ñíos despu‚îú¬Æs de la muerte del gran fot‚îú‚îÇgrafo Jean Laurent. Fuente visual: www.delcampe.es/', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65173400, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF7BD80B056CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24556723629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24556723629.webp', 'https://www.flickr.com/photos/zaragozaantigua/24556723629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24852, 'Pl. de Espa‚îú‚ñía 1937', 'Imagen capturada durante las fiestas mayores de la ciudad en octubre y centrada en el ingreso a la plaza de Espa‚îú‚ñía (hasta julio del a‚îú‚ñío anterior, de la Constituci‚îú‚îÇn) de una carroza de militares y bellas se‚îú‚ñíoritas disfrazadas para la ocasi‚îú‚îÇn de forma tradicionalista. Entre los comerciales audiovisuales destaca el del documental propagand‚îú¬°stico "El viaje de Mussolini a Alemania" realizado durante el pasado mes de septiembre, donde se explicitaba la comuni‚îú‚îÇn de intereses del Eje Roma-Berl‚îú¬°n y que se proyectaba por la axial admiraci‚îú‚îÇn que despertaba en la Espa‚îú‚ñía alzada en armas contra la democracia republicana. En la esquina de los porches del paseo de la Independencia se conservaba la placa con la antigua denominaci‚îú‚îÇn de Calle de la Independencia. Al fondo, a la derecha, el Banco de Espa‚îú‚ñía y el caf‚îú¬Æ Salduba. Fuente visual: Michele Francone, en Francone: La mirada de Mussolini en la guerra de Espa‚îú‚ñía (cat‚îú√≠logo exposici‚îú‚îÇn), DGA, 2009.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65170500, -0.88139400, '0101000020E6100000FE7F9C306134ECBFE1D1C6116BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28054895929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28054895929.webp', 'https://www.flickr.com/photos/zaragozaantigua/28054895929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24854, 'Pl. de Espa‚îú‚ñía 1976', 'Imagen de la huelga total de trabajadores de los transportes urbanos durante las fiestas del Pilar. La escena tiene lugar en la parada sita en la plaza de Espa‚îú‚ñía de la l‚îú¬°nea 30. Las Fuentes-Casablanca, en direcci‚îú‚îÇn al barrio de Casablanca. El autob‚îú‚ïës est‚îú√≠ conducido por personal del Parque M‚îú‚îÇvil de los ministerios civiles, escoltados de forma preventiva por dos miembros de la Polic‚îú¬°a Armada. Al fondo, el edificio del Banco de Espa‚îú‚ñía.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65223900, -0.88162100, '0101000020E610000028F04E3E3D36ECBF7F164B917CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30861623802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30861623802.webp', 'https://www.flickr.com/photos/zaragozaantigua/30861623802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25085, 'P.‚î¨‚ïë de la Independencia 1965', 'Imagen capturada con ocasi‚îú‚îÇn de las locales fiestas del mes de octubre, centrada en la art‚îú¬°stica pareja estelar del Circo Atlas: los "Hermanos Tonetti", Jos‚îú¬Æ y Manuel Villa del R‚îú¬°o. Al fondo, el bloque del n‚î¨‚ïë 5 y 7 del paseo, renombrado por albergar la cafeter‚îú¬°a Las Vegas, inaugurada diez a‚îú‚ñíos antes. A la derecha, el emboque a la calle de San Miguel. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65141600, -0.88143700, '0101000020E6100000D07F0F5EBB34ECBFAA0B789961D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30813064823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30813064823.webp', 'https://www.flickr.com/photos/zaragozaantigua/30813064823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25095, 'Sof‚îú¬°a y los ni‚îú‚ñíos 1970', 'Foto: Luis Mompel. Plaza de Espa‚îú‚ñía. La princesa Sof‚îú¬°a de Grecia participa en la ofrenda de flores a la Virgen del Pilar junto a sus tres hijos, ataviados al uso. Una corte de se‚îú‚ñíoras con gr‚îú√≠ciles peinados les acompa‚îú‚ñía. Al fondo, el paseo de la Independencia. Fuente: Heraldo de Arag‚îú‚îÇn.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65193700, -0.88129200, '0101000020E6100000EE3EC7478B33ECBFB306EFAB72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33452957916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33452957916.webp', 'https://www.flickr.com/photos/zaragozaantigua/33452957916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25267, 'Pl. de la Constituci‚îú‚îÇn 1930', 'Diciembre y a la solana en la plaza de la Constituci‚îú‚îÇn, en una imagen tomada desde cierta altura en el edificio de La Catalana. Abajo a la izquierda, junto a los evacuatorios del principio del paseo de la Independencia, terminal de la l‚îú¬°nea 5. Torrero del tranv‚îú¬°a, donde una unidad de la serie 40 est‚îú√≠ a punto de iniciar su recorrido hacia el sur. La inhabitual presencia de guardiaciviles a pie en el paseo y junto a la parada de tranv‚îú¬°a, a caballo ante la Diputaci‚îú‚îÇn Provincial, as‚îú¬° como de tropas regulares desplegadas junto al Monumento a los M‚îú√≠rtires de la Religi‚îú‚îÇn y de la Patria, son ecos de la republicana Sublevaci‚îú‚îÇn de Jaca de unos d‚îú¬°as antes, y de las medidas para asegurar el orden vigente en los puntos estrat‚îú¬Ægicos de la ciudad, con la plaza de la Constituci‚îú‚îÇn como uno de los m‚îú√≠s importantes. Al fondo y a la sombra, la fachada de la Diputaci‚îú‚îÇn Provincial proyectada por Pedro Mart‚îú¬°nez Sangr‚îú‚îÇs.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65234400, -0.88149100, '0101000020E61000009CFC169D2C35ECBFF4DE180280D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14682013000.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14682013000.webp', 'https://www.flickr.com/photos/zaragozaantigua/14682013000/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25270, 'P.‚î¨‚ïë de la Independencia 1966', 'AYUNTAMIENTO DE ZARAGOZA/Gerardo Sancho Ramo. 29/01/1966. Inicialmente denominada "Rue Imp‚îú¬Ærial", despu‚îú¬Æs "Sal‚îú‚îÇn de Santa Engracia", y desde 1860 "Paseo de la Independencia", esta v‚îú¬°a urbana se realiz‚îú‚îÇ seg‚îú‚ïën proyecto de Joaqu‚îú¬°n Asensio, que en 1811 hab‚îú¬°a sido nombrado arquitecto municipal por el gobernador general de Arag‚îú‚îÇn, mariscal Luis Gabriel de Suchet. Algo m‚îú√≠s de un siglo despu‚îú¬Æs de recibir su vigente denominaci‚îú‚îÇn, esta imagen captura el estado de las cosas en la acera de los impares, entre el n‚îú‚ïëmero 11 y el 19. A la izquierda, apenas visible, hac‚îú¬°a esquina con San Miguel un bloque de 8 plantas de oficinas, construido en 1955. Despu‚îú¬Æs, todo el frontal de los n‚îú‚ïëmeros 11, 13, 15 y 17, que se correspond‚îú¬°an con la t‚îú¬°pica tipolog‚îú¬°a de edificios eclecticistade finales del XIX muy zaragozana, en 3-4 alturas, que adem‚îú√≠s no presentaban los arcos o porches que luego caracterizar‚îú¬°an al Paseo. A continuaci‚îú‚îÇn, el edificio de La Equitativa, de 1950, con el colosal cine del mismo nombre en su planta calle. Los edificios de 3 y 4 plantas ser‚îú¬°an luego piqueteados, y en el solar resultante se construir‚îú¬°a en 1971 el edificio de Galer‚îú¬°as Preciados, una de las mecas del consumo de masas de aquellos a‚îú‚ñíos. En 1995 ser‚îú¬°a, a su vez, consumido por una empresa a‚îú‚ïën m‚îú√≠s voraz, que perdura en nuestros d‚îú¬°as. Transita por el Paseo la unidad M107+R107 de la L‚îú¬°nea 5 del tranv‚îú¬°a Venecia-Delicias. Detr‚îú√≠s de ‚îú¬Æl, protoautob‚îú‚ïës urbano listo para torpedearlo. Conseguir‚îú√≠ hundirlo unos a‚îú‚ñíos despu‚îú¬Æs. Moment‚îú√≠neamente.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65131800, -0.88177600, '0101000020E6100000EDB94C4D8237ECBFE8A562635ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852574375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852574375.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852574375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25286, 'Estado de Guerra Febrero 1936', 'Miguel Mar‚îú¬°n Chivite. 17.02.1936. En la imagen, un piquete de infanter‚îú¬°a lee en la plaza de la Constituci‚îú‚îÇn (tras haberlo hecho antes enante el edificio de Capitan‚îú¬°a General) la orden del general Cabanellas que declaraba el "Estado de Guerra" en Zaragoza tras las elecciones ganadas por el Frente Popular. El gobierno en funciones desautorizar‚îú√≠ poco despu‚îú¬Æs la medida. Fuente visual: somoszaragoza.files.wordpress.com/2011/07/zaragoza-20-07-...', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65200800, -0.88146300, '0101000020E61000001F4AB4E4F134ECBF7D5D86FF74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15575939110.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15575939110.webp', 'https://www.flickr.com/photos/zaragozaantigua/15575939110/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25289, 'Plaza Constituci‚îú‚îÇn c.1902', 'Plaza de la Constituci‚îú‚îÇn, hoy de Espa‚îú‚ñía, poblada de veh‚îú¬°culos rodantes, hacia 1902, fecha en la que se electrific‚îú‚îÇ la primera l‚îú¬°nea tranviaria. Al fondo, la entrada al Tubo por la calle M‚îú√≠rtires. Fuente: www.facebook.com/photo.php?fbid=872321992808797&set=o...', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65223200, -0.88128200, '0101000020E61000000BB6114F7633ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15703578160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15703578160.webp', 'https://www.flickr.com/photos/zaragozaantigua/15703578160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25297, 'Pl. de Espa‚îú‚ñía 1987', 'Locomotora Baldwin, llamada Arag‚îú‚îÇn y fabricada en 1920 en Filadelfia (USA). Procedente del dep‚îú‚îÇsito de Andorra (Teruel), fue colocada sobre un pedestal en la plaza de Espa‚îú‚ñía durante la exposici‚îú‚îÇn El tren en Arag‚îú‚îÇn, celebrada en el palacio de S‚îú√≠stago entre el 4 de octubre y el 1 de noviembre de 1987, donde se mostraba adem‚îú√≠s un documental con el proceso de su restauraci‚îú‚îÇn entre 1985 y 1987. Actualmente se encuentra en Casetas, en las instalaciones de la Asociaci‚îú‚îÇn Zaragozana de Amigos del Ferrocarril y el Tranv‚îú¬°a, Azaft, mientras sigue Esperando a Godot, que en este caso es el ut‚îú‚îÇpico Museo del Ferrocarril en Arag‚îú‚îÇn. En la imagen, la locomotora rodeada de nost‚îú√≠lgicos del tren convencional, precedida de una larga cola de espera en las paradas de autob‚îú‚ïës urbano de la plaza durante las fiestas de octubre. En primer t‚îú¬Ærmino y a la derecha, se‚îú‚ñíales indicativas para el tr‚îú√≠fico de la ‚îú¬Æpoca.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19255446562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19255446562.webp', 'https://www.flickr.com/photos/zaragozaantigua/19255446562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25303, 'Urinarios c.1956', 'Escaleras de entrada a los urinarios en la confluencia del paseo de la Independencia con la plaza de Espa‚îú‚ñía, y filas en las paradas de tranv‚îú¬°as. Fuente: rafaelcastillejo.com', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65187800, -0.88131000, '0101000020E610000088687407B133ECBFAF7D01BD70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20519407598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20519407598.webp', 'https://www.flickr.com/photos/zaragozaantigua/20519407598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25306, 'Evacuatorios 1956', 'Foto: Jos‚îú¬Æ Antonio Duce. Escaleras de acceso a los ba‚îú‚ñíos p‚îú‚ïëblicos de la confluencia del paseo de la Independencia con la plaza de Espa‚îú‚ñía de Zaragoza, en 1956. Fuente: rafaelcastillejo.com', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65187800, -0.88131000, '0101000020E610000088687407B133ECBFAF7D01BD70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20703585052.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20703585052.webp', 'https://www.flickr.com/photos/zaragozaantigua/20703585052/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25308, 'Quiosco de la M‚îú‚ïësica 1914', '"Jura de bandera en Zaragoza". Al fondo, tras la plaza de la Constituci‚îú‚îÇn, una torre del Pilar. Fuente: Fotograf‚îú¬°a de Aurelio Grasa publicada en Heraldo de Arag‚îú‚îÇn el d‚îú¬°a 16 de febrero de 1914. En ABC el 17 de febrero de 1914 y en el Blanco y Negro el 22 de febrero de 1914. El peri‚îú‚îÇdico ABC conserva una copia de esa fotograf‚îú¬°a de Aurelio Grasa que el mismo envi‚îú‚îÇ para su publicaci‚îú‚îÇn. El Archivo Barboza Grasa conserva m‚îú√≠s im‚îú√≠genes del acontecimiento. www.aureliograsa.es', 1914, 1914, 1914, 'Anos 10', 'CENTRO', 41.65124500, -0.88181400, '0101000020E61000004DF564FED137ECBF7E5704FF5BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21413701855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21413701855.webp', 'https://www.flickr.com/photos/zaragozaantigua/21413701855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25326, 'Elecciones 1936', 'En febrero de 1936 se celebraron en Espa‚îú‚ñía las terceras y ‚îú‚ïëltimas elecciones generales de la Segunda Rep‚îú‚ïëblica. Las siguientes tuvieron que esperar 41 a‚îú‚ñíos. En la imagen, entre el paseo de la Independencia a la izquierda y la plaza de la Constituci‚îú‚îÇn a la derecha, pilar de los porches como soporte de carteles electorales y comerciales. Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag‚îú‚îÇn", UGT, 2000.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65197400, -0.88157800, '0101000020E610000056F0DB10E335ECBFD1EB4FE273D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24061552696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24061552696.webp', 'https://www.flickr.com/photos/zaragozaantigua/24061552696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25334, 'Plaza de Espa‚îú‚ñía 1955', 'Excepcional e ins‚îú‚îÇlita imagen desde la plaza de Espa‚îú‚ñía, centrada en un tramo de la antigua fachada que iluminaba la vista entre los n‚îú‚ïëmeros impares 27 y 33 del Coso Alto, en torno al edificio del Casino Mercantil, construido a principios del siglo XX ("de toda la vida") sobre la antigua casa de Juan Coloma. Este pedazo de lienzo urbano ser‚îú¬°a notablemente modificado m‚îú√≠s tarde, pero, de momento, todav‚îú¬°a era posible ver, en el n‚î¨‚ïë 27, la antigua casa de Mart‚îú¬°n Zapater (‚îú¬°ntimo de Goya); en el n‚î¨‚ïë 29, el modernista Centro Mercantil, Industrial y Agr‚îú¬°cola, a‚îú‚ïën con su "minarete" de funciones columb‚îú‚îÇfilas; en el n‚î¨‚ïë 31, la antigua casa de los marqueses de Nibbiano, remodelada con destacable decoraci‚îú‚îÇn historicista, que perdurar‚îú√≠ hasta que sea radicalmente transformada por la entidad bancaria que se anuncia en sus bajos. Notable es la presencia, en este edificio, del estudio fotogr‚îú√≠fico de Carlos Skogler. Inmediato, para terminar, el veterano n‚î¨‚ïë 33, otra antigua casa de los Nibbiano que fue pasando de manos en manos hasta terminar en las de otra entidad bancaria, y desde 1936, como vistosa y c‚îú¬Æntrica delegaci‚îú‚îÇn provincial del partido pol‚îú¬°tico Falange Espa‚îú‚ñíola de las JONS, como parte del autoproclamado "Movimiento Nacional" franquista. En sus caracter‚îú¬°sticos colores, transita hacia el Coso la unidad 33 de la tranviaria l‚îú¬°nea 7, o del Ayuntamiento, en su trayecto desde la plaza de Espa‚îú‚ñía, hasta el Portillo. Esta unidad tuvo una (hoy) inimaginable y longeva vida ‚îú‚ïëtil: desde 1918, y hasta su forzado desguace en 1971. Esta joya visual fue realizada por el fot‚îú‚îÇgrafo franc‚îú¬Æs Jean Paul Margnac en el verano de 1955, durante su paso por la pen‚îú¬°nsula Ib‚îú¬Ærica, desde Par‚îú¬°s, y con destino hacia tierras m‚îú√≠s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/26658972851/in/al...', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65255900, -0.88123500, '0101000020E6100000DEE522BE1333ECBFF0DAA50D87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26694889163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26694889163.webp', 'https://www.flickr.com/photos/zaragozaantigua/26694889163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25337, 'Pl. de Espa‚îú‚ñía 1965', 'Tranv‚îú¬°a de la l‚îú¬°nea 15 "Casablanca", en la plaza de Espa‚îú‚ñía, enfilado hacia ese perif‚îú¬Ærico destino. Al fondo, la fachada del Coso y sus anuncios luminosos (de noche). Fuente: "Trenes y tranv‚îú¬°as en el este de Espa‚îú‚ñía", Jeremy Wiseman, Ediciones Treca SL, Gij‚îú‚îÇn 2009, a trav‚îú¬Æs de www.facebook.com/photo.php?fbid=648401765324491&set=g...', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65199800, -0.88132100, '0101000020E610000082E50819C833ECBF5987A3AB74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27785196316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27785196316.webp', 'https://www.flickr.com/photos/zaragozaantigua/27785196316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25338, 'Plaza de la Constituci‚îú‚îÇn 1899', 'Imagen de la fachada oeste de la plaza de la Constituci‚îú‚îÇn, esquinera con el Coso alto (a la derecha), donde destaca la imponente y albina presencia del palacio de la Diputaci‚îú‚îÇn Provincial dise‚îú‚ñíado por Mart‚îú¬°nez Sangr‚îú‚îÇs. A su lado, el edificio de viviendas del n‚î¨‚ïë 1 de la plaza, que apenas un par de a‚îú‚ñíos antes hab‚îú¬°a sido remozado por Fernando de Yarza Fern‚îú√≠ndez Trevi‚îú‚ñío, y en cuyos bajos estaba el referente establecimiento "Gambrinus", que comenz‚îú‚îÇ siendo cervecer‚îú¬°a, y luego se especializ‚îú‚îÇ como destacado caf‚îú¬Æ. Este edificio ser‚îú¬°a notablemente modificado (y recrecido) al comienzo de los a‚îú‚ñíos 20, con proyecto de Teodoro R‚îú¬°os Balaguer. La Diputaci‚îú‚îÇn mutar‚îú¬°a radicalmente (tambi‚îú¬Æn en apariencia) en los a‚îú‚ñíos 40, con proyecto del mismo arquitecto. Fuente visual: Francisco G‚îú‚îÇrriz, Archivo Municipal de Zaragoza', 1899, 1899, 1899, 'Siglo XIX', 'CENTRO', 41.65241000, -0.88146900, '0101000020E6100000A702EE79FE34ECBFACCABE2B82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28056865723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28056865723.webp', 'https://www.flickr.com/photos/zaragozaantigua/28056865723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25339, 'P.‚î¨‚ïë Independencia 1936', '"Machine gun in a Sarragossa street 1936 Spanish Civil War. Paris, Biblioth‚îú¬øque Nationale". Soldados golpistas posando con su armamento en el inicio del paseo de la Independencia. Fuiente: www.alamy.com/', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65179700, -0.88150400, '0101000020E6100000C36169E04735ECBFC25087156ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28489155745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28489155745.webp', 'https://www.flickr.com/photos/zaragozaantigua/28489155745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25346, 'Pl. de la Constituci‚îú‚îÇn 1936', 'Imagen de las traseras del antiguo edificio de la Diputaci‚îú‚îÇn Provincial, centrada en el alabeado front‚îú‚îÇn que lo remataba, donde se ubicaba su famoso reloj activo desde 1858, cuando fue instalado tras un interesante viaje desde Par‚îú¬°s, donde fue compuesto. La esfera de este reloj ten‚îú¬°a dos metros de di‚îú√≠metro, y estaba flanqueada por dos representaciones aleg‚îú‚îÇricas de la Noche y el D‚îú¬°a. Tras el derribo del edificio, parece ser que el reloj fue transferido a la fachada del Hospital de Gracia. Las alegor‚îú¬°as, y dem‚îú√≠s motivos decorativos, parece que sucumbieron a la ley de la gravedad. Al fondo, a la derecha, la reconocible c‚îú‚ïëpula del Banco Zaragozano, esquinera con la calle de Don Jaime I. Fuente visual: diario "El Noticiero". Archivo Jos‚îú¬Æ Mar‚îú¬°a Ballest‚îú¬°n Miguel.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65222100, -0.88155800, '0101000020E61000008FDE701FB935ECBFD8614CFA7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31691763403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31691763403.webp', 'https://www.flickr.com/photos/zaragozaantigua/31691763403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25347, 'Pl. de Espa‚îú‚ñía 1955', 'Imagen capturada desde el andador central del paseo de la Independencia, en direcci‚îú‚îÇn hacia el principio de la calle de Don Jaime I. Destaca el vivo movimiento en torno a los evacuatorios subterr‚îú√≠neos, a la derecha, bajo un comercial que anuncia la bolera "Strike" de la calle San Miguel n‚î¨‚ïë 16. A la izquierda, los comerciales de ne‚îú‚îÇn que caracterizaron con sus luces y colores la nocturnidad de la fachada de los veteranos edificios recayentes a la plaza. Fuente visual: postal de Garc‚îú¬°a Garrabella, en www.todocoleccion.net/', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65199800, -0.88132100, '0101000020E610000082E50819C833ECBF5987A3AB74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32064248495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32064248495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32064248495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25349, 'Cafeter‚îú¬°a Gambrinus c.1930', 'Terraza de la cafeter‚îú¬°a Gambrinus, en la plaza de la Constituci‚îú‚îÇn, junto a la Diputaci‚îú‚îÇn Provincial. Fuente visual de la imagen: Heraldo de Arag‚îú‚îÇn.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65246100, -0.88146100, '0101000020E6100000F261F6B2ED34ECBF2E7590D783D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32707946636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32707946636.webp', 'https://www.flickr.com/photos/zaragozaantigua/32707946636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25365, 'Plaza de la Constituci‚îú‚îÇn 1936', 'Imagen centrada en un pelot‚îú‚îÇn de la sublevada 5‚î¨¬¨ Divisi‚îú‚îÇn Org‚îú√≠nica, armado con una ametralladora Hotchkiss M1914 y apostado en la plaza de la Constituci‚îú‚îÇn durante la ma‚îú‚ñíana del 19 de julio de 1936. Al fondo, fachada del edificio de la Diputaci‚îú‚îÇn Provincial.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65194300, -0.88121200, '0101000020E6100000D3F71A82E332ECBF96ED43DE72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49793035567.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49793035567.webp', 'https://www.flickr.com/photos/zaragozaantigua/49793035567/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25366, 'P.‚î¨‚ïë de la Independencia c.1901', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 8 del paseo de la Independencia con una refrescante escena del paseo y de la plaza de la Constituci‚îú‚îÇn, al fondo, en la que destaca la nieve acumulada en el firme y los tejados. Algunos operarios retiran la helada precipitaci‚îú‚îÇn del and‚îú¬Æn central del paseo, y en primer t‚îú¬Ærmino, el paso transversal que conecta por el paseo la calle del Cinco de Marzo y la de San Miguel. Flanqueando el arranque del paseo, las p‚îú¬Ætreas estructuras de los urinarios de la ‚îú¬Æpoca, antecedidos por sendos quioscos. En la plaza, Neptuno en pa‚îú‚ñíos menores e indiferente a la temperatura ambiente. De tel‚îú‚îÇn esc‚îú¬Ænico, el tramo del Coso comprendido entre la calle de los M‚îú√≠rtires y la de Don Jaime I, por encima del cual emerge levemente el remate de la torre de la iglesia parroquial de San Gil Abad, y el m‚îú√≠s lejano y elevado de la torre de la Seo.', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.65164700, -0.88152400, '0101000020E61000008A73D4D17135ECBFACC43C2B69D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50115369656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50115369656.webp', 'https://www.flickr.com/photos/zaragozaantigua/50115369656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25369, 'Pl. de la Constituci‚îú‚îÇn 1936', 'Un cami‚îú‚îÇn lleno de j‚îú‚îÇvenes de la Secci‚îú‚îÇn Femenina de Falange posiblemente celebran el golpe de estado del 18-19 de julio de 1936 triunfante en Zaragoza, en una in‚îú¬Ædita imagen capturada desde las escaleras de ingreso a la Diputaci‚îú‚îÇn Provincial de la plaza de la Constituci‚îú‚îÇn. Junto a ellas, guardias de asalto y personal afecto. En la plaza, la unidad tranviaria 74 aguarda en la terminal de la l‚îú¬°nea de Delicias. Al fondo, el reci‚îú¬Æn inaugurado Banco de Espa‚îú‚ñía.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65225600, -0.88145900, '0101000020E6100000C4793881E934ECBF554FE61F7DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51155841951.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51155841951.webp', 'https://www.flickr.com/photos/zaragozaantigua/51155841951/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22427, 'Parque Primo de Rivera c.1968', 'Fuentes del paseo de San Sebasti‚îú√≠n del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27418277115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27418277115.webp', 'https://www.flickr.com/photos/zaragozaantigua/27418277115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22516, 'Canal Imperial c.1965', 'Familiar imagen capturada en la penunbra del paseo de Col‚îú‚îÇn a la altura del acceso al parque de Primo de Rivera que hacia la izquierda lleva al cabezo de Buenavista, y junto al Canal Imperial de Arag‚îú‚îÇn poco antes de la pronunciada curva que hacia la derecha lleva al recto tramo que conduce al puente de Am‚îú¬Ærica. Al fondo y entre los pl‚îú√≠tanos de sombra, fachada de la veterana f‚îú√≠brica de harinas "La Imperial de Arag‚îú‚îÇn".', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.63328600, -0.89171700, '0101000020E610000001310917F288ECBFE08101840FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51671813411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51671813411.webp', 'https://www.flickr.com/photos/zaragozaantigua/51671813411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25505, 'Calle de la Independencia 1903', 'Fot‚îú‚îÇgrafo Yanguas, Arco de la Real Maestranza. 1903. Alfonso XIII fue declarado mayor de edad a los 16 a‚îú‚ñíos de edad para poder acceder al trono en 1902. Al a‚îú‚ñío siguiente, entre el 16 y el 19 de octubre, y durante las fiestas del Pilar de 1903, visit‚îú‚îÇ una ciudad engalanada para la ocasi‚îú‚îÇn. Entre otros ornatos, se levantaron tres arcos de triunfo en el espacio p‚îú‚ïëblico m‚îú√≠s importante de la ciudad: el paseo de Santa Engracia-calle de la Independencia. Quinta Regi‚îú‚îÇn militar, Ayuntamiento y Real Maestranza encargaron la erecci‚îú‚îÇn temporal de estos arcos. La aristocracia local organizada en torno a la Real Maestranza encarg‚îú‚îÇ su arco al ingeniero Manuel de Isasi Isasmendi, en la entrada al paseo desde la plaza de la Constituci‚îú‚îÇn, frente por frente con el a‚îú‚ïën sin terminar monumento a los M‚îú√≠rtires de la Religi‚îú‚îÇn (cat‚îú‚îÇlica) y de la Patria (espa‚îú‚ñíola). Este arco imitaba en madera una obra de cemento armado y bronce, en estilo modernista, y su remate era copia casi literal de las barandillas del Metro de Par‚îú¬°s, entre artorchas y figuras de maceros y trompeteros locales. El gran arco ultrasemicircular abocinado fue decorado con bic‚îú¬Æfalas ‚îú√≠guilas imperiales, y leones. Tras los fastos, este arco fue desmontado. En la imagen, el Arco ubicado a la entrada del Paseo de Santa Engracia. Al fondo, fachada de los edificios que hacen esquina con la calle Cinco de Marzo. Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004. Fuente textual: M‚î¨¬¨ Pilar Poblador Muga, "Arquitecturas ef‚îú¬°meras en la Zaragoza de comienzos del siglo XX", 1998.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65168700, -0.88123200, '0101000020E61000009A0986730D33ECBF3B1DC87A6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16174533128.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16174533128.webp', 'https://www.flickr.com/photos/zaragozaantigua/16174533128/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25508, 'Arco conmemorativo 1908', 'Arco conmemorativo levantado en el arranque del paseo de la Independencia con motivo de la visita del rey Alfonso XIII a la Exposici‚îú‚îÇn Hispano Francesa de ese a‚îú‚ñío. Fuente visual: foto Ignacio Coyne, en Zaragoza 1908-2008, FCC.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65168700, -0.88123200, '0101000020E61000009A0986730D33ECBF3B1DC87A6AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19392772069.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19392772069.webp', 'https://www.flickr.com/photos/zaragozaantigua/19392772069/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25522, 'Calle de la Independencia 1882', 'Dibujo de Juan Comba y dise‚îú‚ñío de Bernardo Rico basado en una fotograf‚îú¬°a perdida de Anselmo Mar‚îú¬°a Coyne, que ilustra el ef‚îú¬°mero arco de triunfo erigido en la calle de la Independencia durante los festejos por el comienzo de las obras del "camino de hierro que ha de enlazar ‚îú√≠ Espa‚îú‚ñía con Francia por el valle de Canfranc". En esta nocturna escena, el imponente arco aparece iluminado con la luz el‚îú¬Æctrica de las farolas de la calle. Adem‚îú√≠s, el agua de la art‚îú¬°stica fuente de su vano flu‚îú¬°a tornasolada en diversos colores con el sistema de luz de Drummond. Al fondo, la plaza de la Constituci‚îú‚îÇn, la fachada del Coso, y la embocadura a la calle de los M‚îú√≠rtires. A la derecha, fuera de cuadro, el comienzo de la calle de San Miguel, en cuya esquina estaba la Casa de Correos y Tel‚îú¬Ægrafos.', 1882, 1882, 1882, 'Siglo XIX', 'CENTRO', 41.65134900, -0.88165300, '0101000020E610000000732D5A8036ECBF23A46E675FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34721739086.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34721739086.webp', 'https://www.flickr.com/photos/zaragozaantigua/34721739086/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25910, 'Pl. de Espa‚îú‚ñía 1970', 'Colorista imagen de la plaza de Espa‚îú‚ñía con el tel‚îú‚îÇn de fondo del edificio de la Diputaci‚îú‚îÇn Provincial. Estacionada delante, la veterana composici‚îú‚îÇn motor-remolque 103+103 de la tranviaria l‚îú¬°nea 5 (Venecia-Delicias) orientada hacia la plaza de las Canteras. El sol pega bien duro. Esta captura fue realizada por la australiana Lindsay Bridge un luminoso d‚îú¬°a de junio de 1970, en su paso por la ciudad durante su viaje a Europa de ese a‚îú‚ñío. Fuente visual: www.flickr.com/photos/intervene/1995723942/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65211400, -0.88132900, '0101000020E6100000388600E0D833ECBFC2A1B77878D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27279160111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27279160111.webp', 'https://www.flickr.com/photos/zaragozaantigua/27279160111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25922, 'Plaza de la Constituci‚îú‚îÇn 1905', 'Imagen de la antigua plaza de la Constituci‚îú‚îÇn, capturada como base para una comercial postal por la fototipia Hauser y Menet (Madrid). La fachada oeste se perfila con los edificios de la ‚îú¬Æpoca como fondo esc‚îú¬Ænico de un espacio de movilidad compartida por peatones y un tranv‚îú¬°a, a la izquierda, de la el‚îú¬Æctrica serie de los "Primitivos" de la l‚îú¬°nea "Madrid", volviendo por la calle de C‚îú√≠diz desde las estaciones de ferrocarril de Cari‚îú‚ñíena y Campo Sepulcro, o Madrid. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65213300, -0.88147200, '0101000020E6100000ECDE8AC40435ECBF39D2191879D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32752605973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32752605973.webp', 'https://www.flickr.com/photos/zaragozaantigua/32752605973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25985, 'Paseo Independencia c.1958', 'Vista tomada desde lo alto de uno de los primeros n‚îú‚ïëmeros pares de la calle M‚îú√≠rtires de Zaragoza. En primer plano, la plaza de Espa‚îú‚ñía con el Monumento a los M‚îú√≠rtires y al fondo el arbolado paseo de la Independencia hasta la plaza de Para‚îú¬°so. Fuente visual: AMZ.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65172200, -0.88129100, '0101000020E6100000D84AE82E8933ECBFB70A62A06BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476296991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476296991.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476296991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21547, 'Licorera 1922', 'A comienzos de la d‚îú¬Æcada de los a‚îú‚ñíos 20 del s. XX, se instal‚îú‚îÇ en el Camino de San Jos‚îú¬Æ n‚î¨‚ïë 155 la "Industrial Licorera Espa‚îú‚ñíola", sobre lo que hasta entonces hab‚îú¬°an sido feraces campos de cultivo de la antigua huerta de Miraflores. Fue inaugurada el 8 de julio de 1922 bajo la direcci‚îú‚îÇn de Fernando L‚îú‚îÇpez Cordoncillo, con entrada localizada casi enfrente de la calle Carb‚îú‚îÇ (luego denominada "Uni‚îú‚îÇn", y "Privilegio de la Uni‚îú‚îÇn"), pero en el lado derecho, su instalaci‚îú‚îÇn determin‚îú‚îÇ el desarrollo urban‚îú¬°stico de toda esa zona. Tal es as‚îú¬°, que con esta calle de acceso pas‚îú‚îÇ a denominarse de "La Licorera", hasta que tras el desmontaje de la f‚îú√≠brica y la reurbanizaci‚îú‚îÇn de la zona, la calle pas‚îú‚îÇ a denominarse "Escultor F‚îú¬Ælix Burriel". Fuente visual: Colecci‚îú‚îÇn particular.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64233100, -0.87320900, '0101000020E6100000E754320054F1EBBF7E1AF7E637D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20231650405.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20231650405.webp', 'https://www.flickr.com/photos/zaragozaantigua/20231650405/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22556, 'Tren chu-ch‚îú‚ïë 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 25/07/1974. Tren del Parque, tren tur‚îú¬°stico, tren chu-ch‚îú‚ïë, trenecito, tren infantil... Uno de los pocos trenes supervivientes de la ciudad. Tras m‚îú√≠s de cuarenta a‚îú‚ñíos de servicio, sigue activo en el Parque Grande. Aunque no va sobre ra‚îú¬°les.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15127383147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15127383147.webp', 'https://www.flickr.com/photos/zaragozaantigua/15127383147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21859, 'C.‚î¨‚ïë de San Jos‚îú¬Æ 1933', 'Imagen capturada en el interior de las instalaciones de la Industrial Licorera Espa‚îú‚ñíola de Salvador Bello, sita en el camino de San Jos‚îú¬Æ en el lado de los impares, entre la calle de la Licorera y el callej‚îú‚îÇn de la acequia de la Mengrana. En ella se produc‚îú¬°a hielo (hasta 15 toneladas diarias), gaseosas, sifones, espumosos, "Orange Crush", "Sinalco", y un notable repertorio de licores de reconocido prestigio y consumo. La imagen se ha realizado junto al acceso a la factor‚îú¬°a desde el camino de San Jos‚îú¬Æ. A la derecha, edificios recayentes a la calle de la Licorera, Al fondo, a la izquierda, la moderna f‚îú√≠brica de hielo. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64233100, -0.87320900, '0101000020E6100000E754320054F1EBBF7E1AF7E637D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36237782152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36237782152.webp', 'https://www.flickr.com/photos/zaragozaantigua/36237782152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24465, '&quot;La Licorera&quot; 1984', 'Imagen capturada desde Ces‚îú√≠reo Alierta de lo que hoy se denomina "Patio de la Licorera", en recuerdo m‚îú¬°nimo de las instalaciones industriales de tratamiento de l‚îú¬°quidos espirituosos que aqu‚îú¬° hubo, en lo que ahora apenas era un solar al que daban las traseras de los antiguos edificios de la izquierda (hoy derribados) de la calle Escultor Burriel (antigua calle Licorera), y las traseras frontales de los trillizos bloques de viviendas de la Avenida S. Jos‚îú¬Æ (n‚î¨‚ïë 62, 64 y 66), de 1964. En 1988 la zona fue finalmente urbanizada completamente, con el derribo de las parcelas, restos de naves y edificaciones de la imagen, y la construcci‚îú‚îÇn sobre ellas de los actuales bloques n‚î¨‚ïë 54, 56, 58 de la Avenida de S. Jos‚îú¬Æ, y los bloques n‚î¨‚ïë 1, 3, 5, 7 y 9 de la calle Escultor Burriel. Al cerramiento de la manzana y la configuraci‚îú‚îÇn del actual "Patio de la Licorera" contribuyeron tambi‚îú¬Æn los nuevos bloques de Ces‚îú√≠reo Alierta n‚î¨‚ïë 39-41, 43, 45, 47, 49 y 53. Fuente visual: AVV San Jos‚îú¬Æ', 1984, 1984, 1984, 'Anos 80', 'CENTRO', 41.64169800, -0.87403500, '0101000020E610000047E6913F18F8EBBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20063142570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20063142570.webp', 'https://www.flickr.com/photos/zaragozaantigua/20063142570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24477, 'La Licorera 1988', 'Antiguo ingreso a La Licorera, Industrial Licorera Espa‚îú‚ñíola de Salvador Bello, durante la temporal convivencia con la entrada/salida de garajes del bloque de viviendas del n‚î¨‚ïë 5 de la calle del Escultor F‚îú¬Ælix Burriel, en construcci‚îú‚îÇn al fondo de la imagen. Esta espirituosa factor‚îú¬°a estuvo activa desde principios del siglo, produciendo entre otros productos el reconocible ron que se anuncia en la puerta, adem‚îú√≠s de gaseosas, sifones, espumosos, y una moderna f‚îú√≠brica de hielo. Fuente: "Memoria de las calles de Zaragoza", Juli‚îú√≠n Ruiz Mar‚îú¬°n, Librer‚îú¬°a General, 2003.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.64169800, -0.87403500, '0101000020E610000047E6913F18F8EBBF4DF4F92823D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21545379408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21545379408.webp', 'https://www.flickr.com/photos/zaragozaantigua/21545379408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25766, 'Calle Licorera 1976', 'Calle de la Licorera, centrada en primer t‚îú¬Ærmino en una f‚îú√≠brica de colas, esmaltes y pinturas. A la izquierda, la Industrial Licorera Espa‚îú‚ñíola que dio su nombre a este vial, productora de anisados, licores, jarabes espumosos y hielo cristalino desde principios de siglo. Desde 1979 esta es la calle del Escultor F‚îú¬Ælix Burriel. Al fondo, parcelas de los n‚îú‚ïëmeros 53-55 de la avenida de San Jos‚îú¬Æ, esquineros con la calle del Privilegio de la Uni‚îú‚îÇn.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.64229300, -0.87428000, '0101000020E61000000A80F10C1AFAEBBF91B932A836D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32961830920.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32961830920.webp', 'https://www.flickr.com/photos/zaragozaantigua/32961830920/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20970, 'Plano de Santa Fe y alrededores 1853', '"Plano en el que se demarca los Trece solares vencidos por la Excma. Diputaci‚îú‚îÇn Provincial y la continuaci‚îú‚îÇn de la calle de San Miguel hasta la Iglesia de San Ildefonso". Juan Gimeno, arquitecto, 1853. Fuente: Archivo Municipal de Zaragoza.', 1853, 1853, 1853, 'Siglo XIX', 'CENTRO', 41.65243200, -0.88380900, '0101000020E61000008522DDCF2948ECBF936E4BE482D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19134215638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19134215638.webp', 'https://www.flickr.com/photos/zaragozaantigua/19134215638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21068, 'Convento de Santa Fe 1878', 'Imagen del claustro alto del desaparecido Convento de Santa Fe, en la plaza del mismo nombre (luego de Salamero), en la ‚îú¬Æpoca en que era sede del Museo Provincial de Zaragoza y Academia de Bellas Artes (1848-1896). En origen fue convento de MM. Religiosas de Santa Fe de la Penitencia, o Arrepentidas, de la Orden de Santo Domingo, fundado a mediados del XVI en la calle Azoque de la "Morer‚îú¬°a", con el prop‚îú‚îÇsito de ‚î¨¬Ωreorientar‚î¨‚ïó la vida de las mujeres que hab‚îú¬°an errado hacia el "buen camino", reencauzando su vida al "servicio divino". Desempe‚îú‚ñíar‚îú¬°a esta oximor‚îú‚îÇnica funci‚îú‚îÇn hasta 1834. En la imagen, aspecto parcial del claustro alto del antiguo convento, con una hilera un tanto descompuesta, para ser un Museo, de modillones en madera desmontados de alguno de esos aleros volados de las palaciegas y nobiliarias casas desaparecidas. En 1908, a‚îú‚ñío de notables prodigios urban‚îú¬°sticos en la ciudad, la piqueta se llev‚îú‚îÇ por delante este edificio, para ensanchar la calle. Tal cual. Este notable claustro renacentista tard‚îú¬°o, como no hab‚îú¬°a otro en la ciudad, al menos qued‚îú‚îÇ inmortalizado en algunas fotos hechas por franceses. Fuente Visual: www.mcu.es/ Fototeca del Patrimonio (Archivo Ruiz Vernacci), Jean Laurent y C‚îú¬°a. 1872-1879. "Patio del Museo Provincial".', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.65251300, -0.88444200, '0101000020E6100000C0AE264F594DECBF809BC58B85D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17444001766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17444001766.webp', 'https://www.flickr.com/photos/zaragozaantigua/17444001766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21416, 'Calle de Alfonso I 1915', 'Paso de la carroza del Ayuntamiento por el primer tramo de la calle de Alfonso I, durante la cabalgata anunciadora de las fiestas del Pilar, el domingo 10 de octubre de 1915. A la izquierda, marquesina del Caf‚îú¬Æ Moderno esquinero con el Coso Alto. En el centro de la imagen, el antiguo inmueble del n‚î¨‚ïë 3 de la calle, luego derribado y sobre cuyo solar se construir‚îú¬°a poco despu‚îú¬Æs, con la l‚îú¬°nea de fachada ya homologada respecto a su vecino de la derecha, el referencial edificio de los almacenes El ‚îú√ºguila. En primer t‚îú¬Ærmino, uno de los j‚îú‚îÇvenes exploradores abanderados que formaban parte de la cabalgata.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65333500, -0.88197600, '0101000020E6100000B16B7BBB2539ECBF842A357BA0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30450950142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30450950142.webp', 'https://www.flickr.com/photos/zaragozaantigua/30450950142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21418, 'Procesi‚îú‚îÇn en el Coso 1915', 'Procesi‚îú‚îÇn del Corpus Christi, festividad que se celebra el jueves que sigue al noveno domingo despu‚îú¬Æs de la primera luna llena de primavera del hemisferio norte; en este caso el 3 de junio de 1915. Est‚îú√≠ pasando por el Coso Alto, ante el edificio que ocup‚îú‚îÇ el palacio de Fuentes y que entonces albergaba el cine Ena Victoria (con entrada a la izquierda, fuera de plano), el Hotel Continental y la sucursal de la Sociedad Espa‚îú‚ñíola de Papeler‚îú¬°a. A la derecha, y tambi‚îú¬Æn fuera de plano, el arco de San Roque.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65311100, -0.88239500, '0101000020E6100000EAEC6470943CECBF35D4282499D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30880511161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30880511161.webp', 'https://www.flickr.com/photos/zaragozaantigua/30880511161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21472, 'Calle de Alfonso I, 1913', 'Imagen de la calle de Alfonso I desde el Coso alto, cuyo ingreso aparece flanqueado a la izquierda por el caf‚îú¬Æ Moderno y a la derecha por la joyer‚îú¬°a El Trust.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.65317000, -0.88211400, '0101000020E6100000F3FFAA23473AECBF3A5D16139BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53587004457.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53587004457.webp', 'https://www.flickr.com/photos/zaragozaantigua/53587004457/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21479, 'P.‚î¨‚ïë de la Independencia 1923', 'Apenas tres meses de "Dictadura con Rey", de "Orden, trabajo y econom‚îú¬°a", y oficialmente todo son sonrisas. Tambi‚îú¬Æn en esta invernal visita a Zaragoza, acompa‚îú‚ñíado el monarca de la reina, y los generales Sanjurjo, y Primo de Rivera. Recorrido y lugares visitados desde la llegada de Barcelona a la estaci‚îú‚îÇn Campo Sepulcro: paseo M‚î¨¬¨ Agust‚îú¬°n, paseo de Pamplona, Facultades de Medicina y Ciencias, paseo de la Independencia, plaza de la Constituci‚îú‚îÇn, Coso, calle Alfonso I, metropolitano del Pilar, paseo por el paseo de la Independencia (momento que captura la imagen) hasta la Capitan‚îú¬°a General. Visita a la Diputaci‚îú‚îÇn Provincial, a la Lonja, al Campo de Maniobras Alfonso XIII, al Hospicio, a la Caridad, al Teatro Principal, al Cuartel del Cid, y desde nuevamente la estaci‚îú‚îÇn Campo Sepulcro, partida en direcci‚îú‚îÇn Madrid. Fin de visita. Y todo, sin perder la compostura, la impostura. Acaso, la claridad y definici‚îú‚îÇn real de la instant‚îú√≠nea. El germ‚îú√≠nico "pickelhaube" tras su majestad, deslumbra naturalmente entre deslumbrantes sonrisas de cart‚îú‚îÇn piedra. Fuente visual: Julio Requejo (AHPZ-DARA)', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65103800, -0.88201700, '0101000020E6100000568330B77B39ECBF043A933655D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14936020770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14936020770.webp', 'https://www.flickr.com/photos/zaragozaantigua/14936020770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21512, 'Quiosco de la M‚îú‚ïësica 1925', 'Paseo de la Independencia, con el Quiosco de la M‚îú‚ïësica en su centro. Proven‚îú¬°a de la plaza de Castelar, a donde volver‚îú¬°a en 1928. Fuente: Zaragoza 1908-2008. FCC.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65101000, -0.88202100, '0101000020E6100000B153AC1A8439ECBF3AAFB14B54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15711491352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15711491352.webp', 'https://www.flickr.com/photos/zaragozaantigua/15711491352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21525, 'Calle de Alfonso I 1925', 'Acusado claroscuro, en altura, de la calle Alfonso I, desde su embocadura por el Coso Alto. Al fondo, la brumosa c‚îú‚ïëpula central del templo de El Pilar. Fuente visual: Fundaci‚îú‚îÇn Telef‚îú‚îÇnica', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65311700, -0.88194800, '0101000020E610000034B91803EB38ECBF17BB7D5699D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16995560466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16995560466.webp', 'https://www.flickr.com/photos/zaragozaantigua/16995560466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21573, 'P.‚î¨‚ïë de la Independencia 1926', 'El aviador Ram‚îú‚îÇn Franco, hermano del que despu‚îú¬Æs fuera dictador, realiz‚îú‚îÇ un vuelo transoce‚îú√≠nico en 1926 en el hidroavi‚îú‚îÇn Plus Ultra, que le convirti‚îú‚îÇ en una figura popular. En la foto, manifestaci‚îú‚îÇn patri‚îú‚îÇtica celebrando la haza‚îú‚ñía, en el paseo de la Independencia de Zaragoza, con la plaza de la Constituci‚îú‚îÇn al fondo. Fuente visual: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag‚îú‚îÇn", UGT, 2000.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24183625396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24183625396.webp', 'https://www.flickr.com/photos/zaragozaantigua/24183625396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21585, 'P.‚î¨‚ïë de la Independencia c.1920', 'Vista del interior de los porches del paseo de la Independencia, desde la calle del Cinco de Marzo. Al fondo, la plaza de la Constituci‚îú‚îÇn. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65151700, -0.88188900, '0101000020E6100000F777B6476F38ECBFDEE4B7E864D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619791570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619791570.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619791570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21648, 'Pl. de Miguel Salamero 1923', 'Imagen capturada en los jardines de la plaza de Miguel Salamero (antigua de Santa Fe) en el angular espacio que a la derecha conservaba algunos antiguos inmuebles esquineros entre las antiguas calles de la Morer‚îú¬°a Cerrada (desde 1923 del Teniente Coronel Valenzuela) y del Ba‚îú‚ñío (desde 1923 de la Morer‚îú¬°a, a secas). El de la imagen se corresponde con el edificio del n‚î¨‚ïë 9 de la calle de la Morer‚îú¬°a. A la derecha de ‚îú¬Æl y fuera de plano perduraba la casa que desde 1736 y hasta 1757 acogi‚îú‚îÇ a la familia paterna de Francisco Goya Lucientes. Todos ellos ser‚îú¬°an derribados a principios de los a‚îú‚ñíos 40. Al frente de la imagen, fachada del colegio de las MM. escolapias con el original aspecto neo-medieval dado en 1915 por el arquitecto Miguel ‚îú√ºngel Navarro P‚îú¬Ærez, luego bastante modificado a finales de los a‚îú‚ñíos 40. Hacia la izquierda, la calle del Azoque.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65263300, -0.88360500, '0101000020E610000066A032FE7D46ECBF2BA5677A89D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51370350442.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51370350442.webp', 'https://www.flickr.com/photos/zaragozaantigua/51370350442/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21669, 'Calle de Alfonso I c.1932', 'Vista de la rectil‚îú¬°nea calle de Alfonso I tomada desde su arranque en el Coso Alto. Junto al veh‚îú¬°culo aparcado, los grandes Almacenes El ‚îú√ºguila, emblem‚îú√≠ticos del car‚îú√≠cter comercial de esta calle desde su apertura en 1865. El entorno se pobl‚îú‚îÇ de familias adineradas. Al fondo, la recoleta plaza del Pilar, con la vista de la gran c‚îú‚ïëpula central del templo.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65321800, -0.88223200, '0101000020E61000006F826F9A3E3BECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725820468.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725820468.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725820468/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22580, 'Julio Cejador Frauca 1977', 'Imagen de la calle Julio Cejador Frauca (antiguo Camino Viejo de Cuarte) en su primer tramo, donde arranca del Paseo de Ruise‚îú‚ñíores (al fondo). El muro de la derecha serv‚îú¬°a tanto para delimitar a la F‚îú√≠brica de Harinas "La Imperial", como a salvar el importante desnivel entre esta calle, y el paseo del Canal, situado una terraza m‚îú√≠s arriba. A la izquierda, muro que delimita los hotelitos vecinos del Colegio Pompiliano (al fondo, a la izquierda). Fuente visual: "La evoluci‚îú‚îÇn urbana de Zaragoza al este del Huerva", Carmen Santos Vich, 1978.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63526700, -0.89123300, '0101000020E610000003B68311FB84ECBF309DD66D50D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15565558869.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15565558869.webp', 'https://www.flickr.com/photos/zaragozaantigua/15565558869/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21715, 'Coso Alto 1936', 'La llegada de alg‚îú‚ïën contingente de tropa (voluntaria o regular) a la ciudad se convert‚îú¬°a en una "espont‚îú√≠nea" muestra de adhesi‚îú‚îÇn popular al "Movimiento" nacionalista. En este caso, estamos en el Coso Alto, con el fondo esc‚îú¬Ænico de los n‚îú‚ïëmeros pares, desde la plaza de la Constituci‚îú‚îÇn (luego, de Espa‚îú‚ñía), y el arco de San Roque. Este era el arco de mayor tr‚îú√≠fico humano de la ciudad, antiguo lugar de paso para la circulaci‚îú‚îÇn de personas y mercanc‚îú¬°as entre el Coso y la "Morer‚îú¬°a", por la plazuela de San Roque, la calle de Palomeque, la plazuela de Sant‚îú√≠ngel, y la calle del Azoque. Este arco que aparece en la imagen fue remozado no hac‚îú¬°a muchos a‚îú‚ñíos, para darle una apariencia m‚îú√≠s "medieval", aunque nunca pretendi‚îú‚îÇ ser m‚îú√≠s que un funcional paso cubierto con viviendas en su parte superior. Ser‚îú√≠ derribado en 1942 para ensanche al tr‚îú√≠fico rodado, lo que supondr‚îú√≠ el derribo de buena parte de lo que en la imagen aparece. Un tranv‚îú¬°a de la l‚îú¬°nea 7, posiblemente el n‚îú‚ïëmero 41, aguarda pacientemente para seguir su recorrido desde la plaza de la Constituci‚îú‚îÇn hasta el Portillo. Fuente: Foto Lozano, Archivo Campos, "La guerra civil en Arag‚îú‚îÇn", ed. Delsan, 2010', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65321000, -0.88286500, '0101000020E6100000AA0EB9196E40ECBFC8B5A1629CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19407328325.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19407328325.webp', 'https://www.flickr.com/photos/zaragozaantigua/19407328325/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21762, 'Coso Alto 1930', 'Coso Alto desde un balc‚îú‚îÇn del antiguo palacio del Conde de Fuentes, junto al Banco de Arag‚îú‚îÇn. Al fondo, la plaza de la Constituci‚îú‚îÇn. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22619780504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22619780504.webp', 'https://www.flickr.com/photos/zaragozaantigua/22619780504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21763, 'Plaza de Salamero 1934', 'Plaza de Salamero. Al fondo, la iglesia parroquial de Santiago el Mayor.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65246300, -0.88418500, '0101000020E6100000ECA353573E4BECBFCE6C57E883D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22619862053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22619862053.webp', 'https://www.flickr.com/photos/zaragozaantigua/22619862053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21771, 'Coso Alto 1930', 'Desde las alturas del Casino Mercantil, imagen del Coso Alto. Al fondo, la iglesia parroquial de Santiago el Mayor. M‚îú√≠s lejos a‚îú‚ïën, la Casa-Hospicio, antigua Real Casa de Misericordia. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65318500, -0.88243700, '0101000020E6100000A5F8F884EC3CECBF6F9EEA909BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22854404727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22854404727.webp', 'https://www.flickr.com/photos/zaragozaantigua/22854404727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21809, 'Calle de Alfonso I c.1933', 'Imagen de calle Alfonso I en los comienzos de la d‚îú¬Æcada de los a‚îú‚ñíos 30, comercializada como postal por la editorial Arribas, y circulada en 1939. Se trata de una ya cl‚îú√≠sica mirada a esta calle, desde la altura de la original sede del Banco de Arag‚îú‚îÇn, en la intersecci‚îú‚îÇn del Coso alto con esta decimon‚îú‚îÇnica calle. Fuente visual: www.delcampe.net/', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28765808751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28765808751.webp', 'https://www.flickr.com/photos/zaragozaantigua/28765808751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21834, 'Paseo Independencia 1933', 'La Guardia de Asalto cachea a un viandante en el paseo de la Independencia, ante el n‚îú‚ïëmero 8. All‚îú¬° se aloja el Caf‚îú¬Æ Central, antes Matossi. Este establecimiento hab‚îú¬°a sido el Gran Caf‚îú¬Æ Suizo y luego fue el Caf‚îú¬Æ Alaska. A la derecha, fuera de plano, la calle del Cinco de Marzo. Fuente visual: Heraldo de Arag‚îú‚îÇn.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65099400, -0.88247000, '0101000020E6100000936FB6B9313DECBF34F279C553D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33492591446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33492591446.webp', 'https://www.flickr.com/photos/zaragozaantigua/33492591446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21840, 'Calle de Alfonso I 1931', 'Imagen capturada en el Coso Alto y centrada en el arranque de la moderna calle de Alfonso I, vertebrada intencionalmente como acceso directo a la plaza del Pilar, al fondo, y como escaparate comercial y residencial privilegiado de las clases altas zaragozanas. Tras el fot‚îú‚îÇgrafo, fuera de plano, tendido tranviario de la l‚îú¬°nea de Circunvalaci‚îú‚îÇn y de la l‚îú¬°nea del Ayuntamiento. Fuente visual: foto Josep Maria Co i de Triola, en Arxiu Fotogr‚îú√°fic del Centre Excursionista de Catalunya.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65315100, -0.88207300, '0101000020E61000004FE8F527F139ECBFC32CB4739AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35059360486.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35059360486.webp', 'https://www.flickr.com/photos/zaragozaantigua/35059360486/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21849, 'P.‚î¨‚ïë Independencia 1934', 'Imagen de la fachada del moderno y nov‚îú¬°simo Caf‚îú¬Æ Alaska, resultado de la profunda reforma acometida con dise‚îú‚ñío de los hermanos Borobio en el preexistente Caf‚îú¬Æ Central. El resultado, apabullante para la Zaragoza del momento, despert‚îú‚îÇ inusitada expectaci‚îú‚îÇn y energ‚îú¬Æticos comentarios a favor. En la imagen, la abundante parroquia congregada en la inauguraci‚îú‚îÇn deja amablemente espacio para que la captura fotogr‚îú√≠fica luzca despejada y caballera. Al fondo, a la derecha, la calle del Cinco de Marzo desemboca en el paseo. Fuente visual original: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65142400, -0.88205900, '0101000020E6100000118FC4CBD339ECBF2DEA93DC61D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35697653373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35697653373.webp', 'https://www.flickr.com/photos/zaragozaantigua/35697653373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21852, 'Calle de Valenzuela 1934', 'Imagen con la imponente fachada, tras reciente reforma, del Hotel Lafuente sito desde los a‚îú‚ñíos veinte en la antigua calle de la Morer‚îú¬°a Cerrada n‚î¨‚ïë 3, luego redenominada de Valenzuela. La captura desde cierta altura posiblemente se ha realizado desde el desaparecido edificio esquinero cuyas traseras reca‚îú¬°an en la plaza de Salamero (antigua de Santa Fe), inmueble en el que vivi‚îú‚îÇ la familia paterna del joven Francisco Goya desde 1736 hasta 1757, y que desde 1928 ten‚îú¬°a una placa conmemorativa. A la izquierda, vista parcial del antiguo n‚î¨‚ïë 1 de la estrecha calle de Valenzuela, que arrancaba en la irregular y angulosa plaza de San Roque, que fuera antigua plazuela de San Camilo o de la Manter‚îú¬°a, entre el Arco de San Roque, el colegio de Santo Tom‚îú√≠s de Villanueva (luego colegio de las MM. Escolapias), el convento de los PP. Agonizantes y la casa de los condes de Fuentes. A‚îú‚ñíos despu‚îú¬Æs, este entorno ser‚îú¬°a radicalmente reurbanizado, perdurando el hotel. Transitoriamente. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65269900, -0.88310000, '0101000020E61000008A1F63EE5A42ECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35795712264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35795712264.webp', 'https://www.flickr.com/photos/zaragozaantigua/35795712264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21872, 'Coso Alto c.1935', 'Imagen capturada en altura desde uno de los balcones de la casa del siglo XVI del conde de S‚îú√≠stago, centrada en el tramo alto del Coso y el emboque a la calle de Alfonso I. Al fondo, el edificio de las Escuelas P‚îú¬°as. Por una de las dos v‚îú¬°as tranviarias traquetea hacia la terminal de la plaza de la Constituci‚îú‚îÇn la unidad 40 de la l‚îú¬°nea 7 Ayuntamiento-Portillo. Fuente visual: Archivo Arribas, AMZ.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65315100, -0.88207300, '0101000020E61000004FE8F527F139ECBFC32CB4739AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38228750422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38228750422.webp', 'https://www.flickr.com/photos/zaragozaantigua/38228750422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21890, 'Coso Alto 1939', 'Imagen capturada bajo el Arco de San Roque y centrada en el paso de una procesi‚îú‚îÇn el d‚îú¬°a del Corpus por el Coso Alto y encaminada hacia la plaza de Espa‚îú‚ñía. Entre le p‚îú‚ïëblico destaca un alto n‚îú‚ïëmero de tropa militar. Al fondo, fachada del Coso correspondiente a los n‚îú‚ïëmeros 13, con el Hotel Oriente y la perfumer‚îú¬°a de Jenaro Lafita, y el n‚î¨‚ïë 15, sede de la Central Obrera Nacionalsindicalista que editaba desde 1936 "Obrerismo. Semanario pro justicia social", ‚îú‚îÇrgano de los sindicatos obreros nacional-sindicalistas. Adem‚îú√≠s, y en local comercial, los almacenes de Gaspar Crespo de material de escritorio, papeler‚îú¬°a, y aparatos de precisi‚îú‚îÇn.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.65322600, -0.88262900, '0101000020E6100000B309302C7F3EECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49901768962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49901768962.webp', 'https://www.flickr.com/photos/zaragozaantigua/49901768962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21907, 'Plaza de Salamero c.1934', 'Interesant‚îú¬°sima e in‚îú¬Ædita imagen capturada a la sombra de los arbolados jardines de la plaza de Salamero (antigua de Santa Fe) y a espaldas del monumento a Joaqu‚îú¬°n Dicenta ubicado en el centro de este espacio desde 1928 y desplazado tras el 18 de julio de 1936 al Parque de Primo de Rivera por presiones de Falange. El objetivo se centra en la zona suroccidental de la plaza, con el tel‚îú‚îÇn de fondo edilicio de la calle del Azoque entre los n‚îú‚ïëmeros 80 y 90. En el centro se abre la calle de la Biblioteca, que conduce al Hospital Militar y a la iglesia parroquial de Santiago, que daba nombre al hom‚îú‚îÇnimo barrio que aqu‚îú¬° llegaba desde la calle del Caballo. En los bajos comerciales de este tramo de la calle del Azoque, vista de la carboner‚îú¬°a de Pedro Soriano, el establecimiento de ultramarinos de Modesto Condor, y la carnicer‚îú¬°a de Pedro Perib‚îú√≠‚îú‚ñíez. Antes y ubicado en la plaza, un "fruit stand" (puesto de frutas) ambulante llama la atenci‚îú‚îÇn del fot‚îú‚îÇgrafo.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.65229600, -0.88423800, '0101000020E6100000A12C7C7DAD4BECBFE3A7716F7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51740621980.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51740621980.webp', 'https://www.flickr.com/photos/zaragozaantigua/51740621980/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21948, 'Paseo Independencia c.1949', 'La Instituci‚îú‚îÇn Teresiana, una deriva de la Instituci‚îú‚îÇn Cat‚îú‚îÇlica de Ense‚îú‚ñíanza, abri‚îú‚îÇ en 1932 una residencia universitaria para chicas en la Calle del Temple n‚î¨‚ïë 20, y como sus balcones daban a la calle Sta. Isabel, ese fue el nombre con que se qued‚îú‚îÇ. Tras el fallido golpe de estado de julio de 1936 contra la Rep‚îú‚ïëblica, y hasta 1939, permaneci‚îú‚îÇ cerrada. En 1944 el nuevo Ministerio de Educaci‚îú‚îÇn concede a la Instituci‚îú‚îÇn Teresiana la direcci‚îú‚îÇn y gesti‚îú‚îÇn del CMUF Santa Isabel, en su nueva ubicaci‚îú‚îÇn del Paseo de la Independencia n‚î¨‚ïë 10. En 1951 se traslad‚îú‚îÇ a unas instalaciones m‚îú√≠s amplias en el redenominado paseo de Fernando El Cat‚îú‚îÇlico n‚î¨‚ïë 2, y en el curso 1972-1973 inaugur‚îú‚îÇ el vigente edificio de la Ciudad Universitaria, con espacio para casi 200 internas. Desde octubre de 1990 depende directamente de la Universidad p‚îú‚ïëblica de Zaragoza, con lo que pas‚îú‚îÇ de ser un colegio exclusivamente femenino, a mixto. En la imagen, el CMUF Sta. Isabel en su ubicaci‚îú‚îÇn del paseo de la Independencia n‚î¨‚ïë 10, en uno de esos historicistas edificios que pretend‚îú¬°an reflejar la rue de Rivoli en Zaragoza, pero que termin‚îú‚îÇ piqueteado para crecer en verticalidad, modernidad, y bancarismo. Fuente: cmusantaisabel.unizar.es/', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65106000, -0.88239400, '0101000020E6100000D3F88557923CECBFECDD1FEF55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16783290750.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16783290750.webp', 'https://www.flickr.com/photos/zaragozaantigua/16783290750/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22012, 'Calle de Alfonso I c.1945', 'Canicular imagen de la decimon‚îú‚îÇnica calle de Alfonso I capturada desde la altura de la original sede del Banco de Arag‚îú‚îÇn en el n‚î¨‚ïë 42 del Coso. A la izquierda, el veterano caf‚îú¬Æ Moderno poco antes de su cierre, ubicado desde principios de siglo en los bajos del n‚î¨‚ïë 17 del Coso angular con el n‚î¨‚ïë 1 de Alfonso I, y a continuaci‚îú‚îÇn los referenciales almacenes El ‚îú√ºguila. Al fondo, la c‚îú‚ïëpula central del metropolitano templo del Pilar. Fuente visual: ediciones Garc‚îú¬°a Garrabella, en www.delcampe.es', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.65305500, -0.88215700, '0101000020E6100000C5FF1D51A13AECBFA1BE654E97D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42576582714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42576582714.webp', 'https://www.flickr.com/photos/zaragozaantigua/42576582714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22058, 'Banco de Arag‚îú‚îÇn 1951', '1951. Edificio del Banco de Arag‚îú‚îÇn, en Coso n‚îú‚ïëm. 42, proyectado en 1913 e inaugurado en 1917 seg‚îú‚ïën dise‚îú‚ñío del arquitecto Manuel del Busto. Fue segunda sede central de la entidad en Zaragoza, entre 1917 y 1951. Fuente: Recuerdo de la inauguraci‚îú‚îÇn del nuevo edificio del Banco de Arag‚îú‚îÇn en Zaragoza, 1951.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65288900, -0.88206500, '0101000020E61000009947FE60E039ECBF8675E3DD91D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14925082941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14925082941.webp', 'https://www.flickr.com/photos/zaragozaantigua/14925082941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22092, 'Banco de Arag‚îú‚îÇn 1951', 'Edificio del Banco de Arag‚îú‚îÇn inaugurado en 1951, en el Coso 36-40 de Zaragoza, esquina con la del Teniente Coronel Valenzuela, seg‚îú‚ïën proyecto de Juli‚îú√≠n Laguna. El solar hab‚îú¬°a sido ocupado por el Palacio de los marqueses de Villasimpliz (s. XVI) y por el cine Ena Victoria (s. XX). Fue tercera y ‚îú‚ïëltima sede de esa entidad, hasta ser absorbida por el Banco Central en 1970. Fuente: Recuerdo de la inauguraci‚îú‚îÇn del nuevo edificio del Banco de Arag‚îú‚îÇn en Zaragoza, 1951.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65322500, -0.88264000, '0101000020E6100000AD86C43D963EECBFFDF675E09CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19443981149.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19443981149.webp', 'https://www.flickr.com/photos/zaragozaantigua/19443981149/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22125, 'Calle de Alfonso I c.1950', 'Hogar Moderno, establecimiento comercial situado en el n‚î¨‚ïë 6 de la calle de Alfonso I desde el a‚îú‚ñío 1920, dedicado a la venta de vajilla y menaje dom‚îú¬Æstico que fue cerrado en 2014. Un veh‚îú¬°culo permanece estacionado junto a la acera de los impares. Al fondo, el Coso Alto y el antiguo edificio del Banco de Arag‚îú‚îÇn. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65324100, -0.88194300, '0101000020E6100000C3F4BD86E038ECBF03B4AD669DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22779028039.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22779028039.webp', 'https://www.flickr.com/photos/zaragozaantigua/22779028039/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22140, 'Restaurante Savoy c.1950', 'Fotograf‚îú¬°a publicitaria del Restaurante Savoy, ubicado hasta 2004 en el antiguo edificio del Banco de Arag‚îú‚îÇn del Coso 42, frente a la calle de Alfonso I. Fuente: www.todocoleccion.net', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65300800, -0.88217900, '0101000020E6100000BAF94674CF3AECBF600322C495D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24899772806.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24899772806.webp', 'https://www.flickr.com/photos/zaragozaantigua/24899772806/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22146, 'Cine Rex 1953', 'Imagen capturada durante la construcci‚îú‚îÇn del nuevo cinemat‚îú‚îÇgrafo Rex proyectado por los arquitectos Jos‚îú¬Æ de Yarza Garc‚îú¬°a y Teodoro R‚îú¬°os Us‚îú‚îÇn como parte integrante de un gran complejo que inclu‚îú¬°a un hotel, dos salas de cine, un pasaje comercial y viviendas entre el paseo de la Independencia y la calle del Requet‚îú¬Æ Aragon‚îú¬Æs. El Rex era el segundo cine en tama‚îú‚ñío de este proyecto, compartiendo medianera con el cine Palafox o cine principal (a la izquierda de la imagen). Ser‚îú¬°a inaugurado en 1954. Al fondo, el colegio de Santa Rosa de la Orden de Predicadores y la medianera con el n‚î¨‚ïë 7 de la calle del Requet‚îú¬Æ Aragon‚îú¬Æs. Fuente visual: arch. J. de Yarza', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65157700, -0.88302400, '0101000020E6100000CAA8328CBB41ECBFB4E908E066D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26317818299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26317818299.webp', 'https://www.flickr.com/photos/zaragozaantigua/26317818299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22311, 'Coso Alto 1969', 'Tramo del Coso alto entre la calle del Teniente Coronel Valenzuela (a la derecha) y la plaza de Espa‚îú‚ñía (al fondo). En el cine Coso se proyecta el filme "Cerveza para todos" (Frank Tashlin, 1968). Fuente visual: Foto Kolor - Zerkowitz, Barcelona, 1969; Postal colecci‚îú‚îÇn Miguel Pascual Laborda. www.facebook.com/photo.php?fbid=407008862797117&set=p...', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.65322500, -0.88237200, '0101000020E6100000DFFE5C34643CECBFFDF675E09CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15718787768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15718787768.webp', 'https://www.flickr.com/photos/zaragozaantigua/15718787768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22314, 'Blasco Ijazo 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Noviembre Junio 1968. Nacido cuando derribaron la Torre Nueva, muy pronto mostr‚îú‚îÇ inclinaciones period‚îú¬°sticas, participando en publicaciones escolares dirigidas por Jos‚îú¬Æ Calvo Sotelo. Colabor‚îú‚îÇ con "El Noticiero" y con la "Hoja del Lunes", editada por la Asociaci‚îú‚îÇn de la Prensa, de la que fue presidente desde el 18 de julio de 1936, hasta 1968. El pleno municipal de 1954 le nombr‚îú‚îÇ cronista oficial de la ciudad reconociendo, como hombre de orden y del r‚îú¬Ægimen, su divulgaci‚îú‚îÇn de aspectos de la historia zaragozana. Produjo muchas obras sobre Zaragoza: "Las calles de la ciudad y significado de sus nombres" (1944, actualizada en 1962); "Zaragoza y sus locales de espect‚îú√≠culos. Los que fueron y los que son... 1764-1945" (1945), "Historia de la prensa zaragozana 1683-1947" (1947), y el sexteto "‚î¨√≠Aqu‚îú¬°... Zaragoza!" (1948-1960). En la imagen, Blasco Ijazo gesticula en un homenaje de sus colegas periodistas al dejar la presidencia de la Asociaci‚îú‚îÇn de la Prensa de Arag‚îú‚îÇn, en la sede de la misma (calle Requet‚îú¬Æ Aragon‚îú¬Æs, 9). Su discurso est‚îú√≠ respaldado por un tridente letal para las fuerzas del mal: Franco, Jos‚îú¬Æ Antonio, y la virgen del Pilar. Ser‚îú√≠ sustituido por Antonio Bruned Mompe‚îú‚îÇn, el joven a la izquierda de la virgen.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65189500, -0.88332600, '0101000020E61000009D9B36E33444ECBF85B69C4B71D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15754697952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15754697952.webp', 'https://www.flickr.com/photos/zaragozaantigua/15754697952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22319, 'Paseo Independencia 1965', 'En primer plano, solar anunciado para la construcci‚îú‚îÇn del SEPU, en la esquina con la calle Requet‚îú¬Æ Aragon‚îú¬Æs, inaugurado en 1969. Al fondo, la plaza de Espa‚îú‚ñía, con el Pilar detr‚îú√≠s. Fuente: www.facebook.com/photo.php?fbid=765588400178578&set=o...', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65133300, -0.88191100, '0101000020E6100000EB71DF6A9D38ECBF1DE736E15ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15859257352.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15859257352.webp', 'https://www.flickr.com/photos/zaragozaantigua/15859257352/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22412, 'Requet‚îú¬Æ Aragon‚îú¬Æs 1968', 'Imagen superproducida en el entorno del Hotel Goya, n‚î¨‚ïë 5 de la calle Requet‚îú¬Æ Aragon‚îú¬Æs (antigua del Cinco de Marzo), horas antes del encuentro de f‚îú‚ïëtbol de 1‚î¨¬¨ Divisi‚îú‚îÇn, correspondiente a la jornada 22 de la Liga, entre los equipos Real Zaragoza C.D., y la U.D. Las Palmas. Dos peloteros foranos (posiblemente, Mart‚îú¬°n Marrero, y Gilberto) posan leyendo atentamente, en la vastedad del diario m‚îú√≠s antiguo de la regi‚îú‚îÇn aragonesa, las ‚îú‚ïëltimas noticias difundidas por la prensa libre sobre los tremendos combates en la Ciudadela de Hu‚îú¬Æ (Vietnam), como escenario b‚îú¬Ælico destacado durante la comunista ofensiva del Tet. A su izquierda, Catherine Deneuve ilumina con su turbadora sonrisa desde la portada de la revista "Elle" donde anunciaba su pr‚îú‚îÇxima pel‚îú¬°cula, "Manon 70", de tem‚îú√≠tica muy atrevidamente francesa, compartiendo p‚îú√≠ginas con un adelanto de la maravillosa moda "pr‚îú¬¨t-‚îú√°-porter" que se lucir‚îú¬°a en la tranquila primavera de ese a‚îú‚ñío. Las preciosas postales expuestas, un cat‚îú√≠logo de diversos iconos tur‚îú¬°sticos que incluyen vistas de la moderna Zaragoza, pertenecen a un quiosco incrustado entre el Hotel Goya y el Pasaje Palafox, con las ascendentes escaleras hacia el Cine Rex, despu‚îú¬Æs. En la otra acera, un cartel indicador orienta hacia el veterano establecimiento del "Jai-Alai" en su segunda etapa como front‚îú‚îÇn de pelota, tras haber ejercido durante casi treinta a‚îú‚ñíos como sala de proyecciones del Front‚îú‚îÇn Cinema. Al fondo, la plaza de Salamero, antigua de Santa Fe. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65172100, -0.88263800, '0101000020E6100000809E060C923EECBFE78EFE976BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25053256141.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25053256141.webp', 'https://www.flickr.com/photos/zaragozaantigua/25053256141/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22417, 'Vista 1968', '"Vista desde el torre‚îú‚îÇn", tinta china y gouache sobre papel, Gonzalo de Diego, 1968. Con las torres del Banco de Arag‚îú‚îÇn y del Pilar al fondo, ofrece un caser‚îú¬°o en gran parte desaparecido, en el entorno de las plazas de Salamero y del Carmen. El torre‚îú‚îÇn al que alude el t‚îú¬°tulo es, quiz‚îú√≠s, el remate del edificio del paseo de Pamplona 1, esquinero con la calle del Doctor Cerrada. Fuente visual: zaragozacool.wordpress.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65149100, -0.88370200, '0101000020E6100000041DAD6A4947ECBFB5519D0E64D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26245096647.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26245096647.webp', 'https://www.flickr.com/photos/zaragozaantigua/26245096647/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22523, 'Calle de Alfonso I 1960', 'Fotograma de la pel‚îú¬°cula "Alerta en el cielo" rodada en Zaragoza en el oto‚îú‚ñío de 1960. Aqu‚îú¬° se muestra la "iluminaci‚îú‚îÇn art‚îú¬°stica" de la calle de Alfonso I incluida en el programa oficial de las fiestas del Pilar de ese a‚îú‚ñío. Esta tradicional moda de poner iluminaci‚îú‚îÇn extra a contadas y selectas calles de la ciudad en fechas tan se‚îú‚ñíaladas comenz‚îú‚îÇ un par de a‚îú‚ñíos antes, si bien en 1959 brillaron por su ausencia. Las de este a‚îú‚ñío eran consideradas menos "pueblerinas", si bien esta moda ni ten‚îú¬°a ese origen ni hab‚îú¬°a pueblo que se las pudiera costear. En la imagen, emboque a la calle de Alfonso I desde el Coso.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65310600, -0.88201700, '0101000020E6100000568330B77B39ECBF236937FA98D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55095008013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55095008013.webp', 'https://www.flickr.com/photos/zaragozaantigua/55095008013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22620, 'Recogidas Pza. del Carmen 1978', 'Inicio del derribo del antiguo convento de las "Recogidas" que se extend‚îú¬°a entre la calle de C‚îú√≠diz (a la izquierda) y la plaza del Carmen. La imagen ha sido capturada precisamente desde esta plaza, con detalle de los espacios conventuales que en 1964 hab‚îú¬°an sido alquilados a varios establecimientos comerciales. Fuente: Gerardo Sancho Ramo, Archivo P‚îú‚ïëblico Municipal.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.65098100, -0.88437700, '0101000020E6100000FAB48AFED04CECBFA0A86C5853D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19551809090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19551809090.webp', 'https://www.flickr.com/photos/zaragozaantigua/19551809090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22692, 'P.‚î¨‚ïë de la Independencia 1970', 'Interesante, colorista, e ins‚îú‚îÇlita imagen del paseo de la Independencia, como moderna v‚îú¬°a de alta capacidad para circulaci‚îú‚îÇn rodada, con tranv‚îú¬°as en los m‚îú√≠rgenes. A la izquierda, el recient‚îú¬°simo y moderno edificio del gran centro comercial vertical "SEPU", y enfrente suyo, al otro lado del paseo, el solar sobre el que pronto se edificar‚îú¬°a su clon en forma de "Galer‚îú¬°as Preciados". A la izquierda extrema, inmediato, el solar sobre el que se levantar‚îú√≠ el nuevo y no menos impactante n‚î¨‚ïë 22 del paseo, en tiempos en que esas cosas no importaban demasiado. Sobre la medianera del bloque del n‚î¨‚ïë 18, rastros del derribado edificio, de los tiempos de la antigua calle de la Independencia Esta captura fue realizada por la australiana Lindsay Bridge un luminoso d‚îú¬°a de junio de 1970, en su paso por la ciudad. Fuente visual: www.flickr.com/photos/intervene/4158456835/in/album-72157...', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27073290990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27073290990.webp', 'https://www.flickr.com/photos/zaragozaantigua/27073290990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22733, 'Plaza del Carmen 1973', 'Imagen de la antigua plaza del Carmen centrada en el caser‚îú‚îÇn del n‚î¨‚ïë 9, esquinero con la calle de la Vieja Guardia, donde destaca la gran estructura del bloque en construcci‚îú‚îÇn que, con el n‚î¨‚ïë 2, se levanta sobre parte del enorme cuartel del Carmen. El referido caser‚îú‚îÇn es renombrado, sobre todo, por albergar en sus bajos un bar de nombre insular. El edificio era una antigua construcci‚îú‚îÇn, posiblemente del siglo XVII, profundamente remodelada en el XVIII cuando su propietario fue Francisco Montemayor, y a finales de siglo fue de Pedro Cort‚îú¬Æs y Larraz, obispo de Guatemala, y luego de Tortosa. Unos a‚îú‚ñíos despu‚îú¬Æs, fue derribado y homologado con su vecino del otro lado de la calle. Fuente visual: foto Gerardo Sancho Ramo AMZ', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65152900, -0.88420500, '0101000020E6100000B3B5BE48684BECBFA2B2614D65D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31167796974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31167796974.webp', 'https://www.flickr.com/photos/zaragozaantigua/31167796974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22773, 'Calle del Doctor G‚îú‚îÇmez Ulla 1975', 'Imagen a‚îú¬Ærea de la calle del Doctor G‚îú‚îÇmez Ulla y centrada en el tramo de los inmuebles, ya deshabitados y a la espera del derribo de los n‚îú‚ïëmeros 3-7, y el solar del ya derribado inmueble del n‚î¨‚ïë 9, entre la calle del Azoque, a la izquierda, y la avenida Imperial, a la derecha. Esta calle estaba abocada a la desaparici‚îú‚îÇn al estar incluida en el Plan Parcial Especial de San Ildefonso, que afect‚îú‚îÇ al per‚îú¬°metro delimitado por la plaza de Sant‚îú√≠ngel, las calles de Pignatelli, Ram‚îú‚îÇn y Cajal, Capit‚îú√≠n Portol‚îú¬Æs, Azoque, Teniente General Valenzuela, y Palomeque. El provisional muro de ladrillo de primer t‚îú¬Ærmino, convertido en provisional soporte publicitario, se‚îú‚ñíala el nuevo alineamiento recayente a la reformada plaza de Miguel Salamero, que a‚îú‚ñíos m‚îú√≠s tarde guardar‚îú√≠n los nuevos edificios aqu‚îú¬° construidos, tras el derribo de los de la imagen. A la izquierda, los inmuebles de los n‚îú‚ïëmeros 50-56 de la calle del Azoque. Al fondo y a la derecha, tras el gran solar se levanta el muro medianil del Teatro Fleta.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65215200, -0.88451700, '0101000020E61000006A317898F64DECBFB0027CB779D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33974070708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33974070708.webp', 'https://www.flickr.com/photos/zaragozaantigua/33974070708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22800, 'Calle del Dr. G‚îú‚îÇmez Ulla 1975', 'Imagen, hasta ahora sin identificar, capturada en la calle del Doctor G‚îú‚îÇmez Ulla y centrada en el tramo de los inmuebles, ya deshabitados y a la espera del derribo, de los n‚îú‚ïëmeros 3-7, entre la calle del Azoque y la avenida Imperial, al fondo. Esta calle estaba abocada a la desaparici‚îú‚îÇn, tras el previo despeje del lado de los pares, a la derecha. El provisional muro de ladrillo de primer t‚îú¬Ærmino, con carteles promocionales del Circo Atlas, se‚îú‚ñíala el nuevo alineamiento recayente a la reformada plaza de Miguel Salamero, y el antiguo acceso a la calle es ahora un "paso cortado", como indica el r‚îú‚îÇtulo bocarriba. Los modernos edificios de viviendas que aqu‚îú¬° se construyeron m‚îú√≠s tarde tienen su ingreso por el n‚î¨‚ïë 30 de la avenida de C‚îú¬Æsar Augusto. Esta fue la antigua y recoleta calle de la Biblioteca, que conduc‚îú¬°a hasta el Hospital Militar y la iglesia de San Ildefonso. Ninguno de los nuevos y abundantes viales abiertos en la ciudad desde entonces han tomado el relevo de estas dos denominaciones perdidas.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65220000, -0.88451700, '0101000020E61000006A317898F64DECBFC139234A7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46727179095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46727179095.webp', 'https://www.flickr.com/photos/zaragozaantigua/46727179095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22801, 'Calle del Requet‚îú¬Æ Aragon‚îú¬Æs 1973', 'Colorista imagen de la pista de hielo El Ib‚îú‚îÇn en una vista interior capturada desde la zona de ingreso por la calle del Requet‚îú¬Æ Aragon‚îú¬Æs. En 1932 se inaugur‚îú‚îÇ el Front‚îú‚îÇn Emendek en en la calle del Cinco de Marzo n‚î¨‚ïë 3-5, con proyecto del arquitecto Ignacio Mendiz‚îú√≠bal Lujambio. Desde 1934 y hasta los a‚îú‚ñíos 50 fue reconvertido en el Front‚îú‚îÇn Cinema, con 1.250 localidades, y luego albergar‚îú¬°a la sala de fiestas R‚îú¬°o Club. Desde 1963 fue otra vez front‚îú‚îÇn, ahora denominado Jai Alai, hasta que en 1973 se instal‚îú‚îÇ una pista de hielo para la pr‚îú√≠ctica multitudinaria del patinaje desde una perspectiva l‚îú‚ïëdica, de vida breve.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65210400, -0.88286500, '0101000020E6100000AA0EB9196E40ECBF9FCBD42478D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47524131481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47524131481.webp', 'https://www.flickr.com/photos/zaragozaantigua/47524131481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23033, 'Calle de Alfonso I 1992', 'Nocturna imagen del arranque de la calle de Alfonso I capturada desde el tramo alto del Coso. En primer t‚îú¬Ærmino, barandillas reforzadas para evitar que los peatones estrangulen esta importante v‚îú¬°a para el tr‚îú√≠fico rodado. A la izquierda, el Banco de Fomento radicado en el antiguo inmueble de los Almacenes El ‚îú√ºguila. Al fondo, la c‚îú‚ïëpula mayor del templo del Pilar.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65321800, -0.88198500, '0101000020E61000007E00529B3839ECBF4B94BDA59CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207940452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207940452.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207940452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23071, 'P.‚î¨‚ïë de la Independencia 2007', 'Paseo de la Independencia de Zaragoza, con sus seis carriles viarios, tras la remodelaci‚îú‚îÇn de 2002 y antes de la de 2011, esta ‚îú‚ïëltima para el paso del tranv‚îú¬°a. Al fondo, la plaza de Arag‚îú‚îÇn. Fuente: Wikipedia, 2007.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65113900, -0.88188300, '0101000020E61000006EBF7CB26238ECBF3813D38558D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012100399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012100399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012100399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24470, 'Camino de San Jos‚îú¬Æ 1924', 'Talleres del yesaire y decorador Enrique Cubero. Edificio obra de Francisco Albi‚îú‚ñíana, en el antiguo camino de San Jos‚îú¬Æ 155.', 1924, 1924, 1924, 'Anos 20', 'SAN JOS‚îú√´', 41.63579500, -0.87930400, '0101000020E610000055BE67244223ECBFECFA05BB61D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20201933306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20201933306.webp', 'https://www.flickr.com/photos/zaragozaantigua/20201933306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23158, 'Convento de San Francisco 2007', 'Contrafuertes del Sal‚îú‚îÇn de Quintas del convento de San Francisco, durante las obras de ampliaci‚îú‚îÇn de la Diputaci‚îú‚îÇn Provincial (2007-2011). Este convento, fundado en 1219, fue muy da‚îú‚ñíado en el Sitio de 1809. En 1843 se construy‚îú‚îÇ sobre su solar el palacio de la Diputaci‚îú‚îÇn. La imagen muestra el acceso desde la calle del Cinco de Marzo 8 (al fondo, fuera de plano). Fuente visual: Heraldo de Arag‚îú‚îÇn.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65194800, -0.88226600, '0101000020E610000074ED0BE8853BECBFA758350873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32474943101.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32474943101.webp', 'https://www.flickr.com/photos/zaragozaantigua/32474943101/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23244, 'P.‚î¨‚ïë de la Independencia  2002', 'A‚îú¬Ærea visual del paseo de la Independencia durante las obras de remodelaci‚îú‚îÇn cuyo proyecto inclu‚îú¬°a un subterr‚îú√≠neo aparcamiento de cuatro plantas, descartado tras toparse con los medievales restos de una parte del sure‚îú‚ñío arrabal musulm‚îú√≠n de Sinhaya (siglos XI y XII) de la ciudad de Saraqusta. Al fondo, la plaza de Espa‚îú‚ñía. Fuente visual: AMZ', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65101800, -0.88220200, '0101000020E6100000C5E74EB0FF3AECBFBD8DCD8E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25512926027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25512926027.webp', 'https://www.flickr.com/photos/zaragozaantigua/25512926027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23284, 'Calle de Alfonso I 1908', '', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65293800, -0.88220000, '0101000020E610000097FF907EFB3AECBF6728EE7893D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14912896942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14912896942.webp', 'https://www.flickr.com/photos/zaragozaantigua/14912896942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23296, 'Calle de Alfonso I c.1895', 'Imagen del arranque de la calle Alfonso I capturada desde cierta altura de lo que fuera el antiguo palacio del marqu‚îú¬Æs de Campo Franco, situado en el Coso Alto entre el palacio de S‚îú√≠stago, y el de Fuentes. A la izquierda, imagen parcial de la antigua casa solariega de los marqueses de Tosos en la ciudad, desde su establecimiento en ella a mediados del siglo XVII, en lo que entonces era la esquina del Coso con el Trenque del Arzobispo, y hasta 1833, en que fue vendida a un particular como n‚î¨‚ïë 7 del Coso. Reformada varias veces, cuando en la d‚îú¬Æcada de los 60 fue abierta la calle Alfonso I, este edificio mantuvo su alineamiento original, hasta que en 1902 fue remodelado profundamente, ya como n‚î¨‚ïë 17 del Coso: realineado, se levant‚îú‚îÇ una nueva planta, se homologaron las alturas de sus bajos a las de los comercios que caracterizaban la calle, se le achaflan‚îú‚îÇ la esquina, y se le dio un estilo m‚îú√≠s profusamente decorativo, con balconadas y rejer‚îú¬°as m‚îú√≠s "modernas". En la imagen, la antigua casona conserva su esquina en ‚îú√≠ngulo y un estilo m‚îú√≠s austero de mediados del XIX, donde en sus bajos destaca la prestigiosa tienda de sombreros de Gaspar Lamarque. Al otro lado de la calle de Alfonso I, inmueble construido expresamente tras la apertura de la calle para el confitero Eusebio Molins, que en sus bajos habilit‚îú‚îÇ una confiter‚îú¬°a, con el caracter‚îú¬°stico chafl‚îú√≠n de los edificios de la burguesa calle, donde se destaca la publicidad de la golosa f‚îú√≠brica "La Gemela del Buen Gusto", sita junto a la antigua carretera de Valencia. Este edificio tambi‚îú¬Æn fue remodelado en 1902, con proyecto de Fernando de Yarza, dej‚îú√≠ndole su actual aspecto modernista. Aunque esta imagen viene datada en varias fuentes como de "Jarke", C‚îú¬Æsar Gracia Jarque naci‚îú‚îÇ en 1905, y su actividad como fot‚îú‚îÇgrafo, iniciador de la saga "Jarke", comienza al final de la segunda d‚îú¬Æcada del siglo XX. La captura posiblemnete tiene como autor a Anselmo Mar‚îú¬°a Coyne, o tal vez Ignacio.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22739744680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22739744680.webp', 'https://www.flickr.com/photos/zaragozaantigua/22739744680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23298, 'Calle de Alfonso I c.1959', 'Calle Alfonso I. A la izquierda, almacenes √î√á¬£El ‚îú√ºguila√î√á√ò. En la esquina con la calle Fuenclara, unos a‚îú‚ñíos despu‚îú¬Æs ser‚îú√≠n construidos los modernos √î√á¬£Almacenes Gay√î√á√ò. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65324100, -0.88194300, '0101000020E6100000C3F4BD86E038ECBF03B4AD669DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23147083345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23147083345.webp', 'https://www.flickr.com/photos/zaragozaantigua/23147083345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23303, 'Calle de Alfonso I 1958', 'Instant‚îú√≠nea nocturna de una abarrotada calle Alfonso I, tomada desde su confluencia con el Coso Alto. La ornamentaci‚îú‚îÇn luminosa corresponde a las tradicionalistas celebraciones del mes de octubre. Fuente: Agencia EFE.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65330400, -0.88206200, '0101000020E6100000556B6116DA39ECBF492C29779FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24506380742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24506380742.webp', 'https://www.flickr.com/photos/zaragozaantigua/24506380742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23306, 'Calle de Alfonso I 1965', 'Imagen del emboque de la calle Alfonso I desde el Coso Alto, cuando la procesionaria de la Solemnidad del Cuerpo y la Sangre de Cristo, escoltada, pasa ante el objetivo de la c‚îú√≠mara. Sobrevuela la calle Alfonso I una a‚îú¬Ærea pancarta de la IX‚î¨¬¨ Operaci‚îú‚îÇn Papel de la organizaci‚îú‚îÇn apost‚îú‚îÇlica creada por don Abundio Garc‚îú¬°a. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza. Referencia: ES. 50297. AM 04.01.02.11 Carpeta 27858', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65300800, -0.88217900, '0101000020E6100000BAF94674CF3AECBF600322C495D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26548392656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26548392656.webp', 'https://www.flickr.com/photos/zaragozaantigua/26548392656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23310, 'Calle de Alfonso I 1908', 'Foto: Aurelio Grasa. Vista de la confluencia de la calle de Alfonso I con el Coso Alto. Al fondo, el palacio de S‚îú√≠stago. Fuente: Archivo de Aurelio Grasa. Archivo Barboza Grasa (www.aureliograsa.es, www.barbozagrasa.es). Forma parte de un reportaje cedido a la revista Sombras Foto de la RSFZ en 2008.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65310300, -0.88197600, '0101000020E6100000B16B7BBB2539ECBFB2F50CE198D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31993760184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31993760184.webp', 'https://www.flickr.com/photos/zaragozaantigua/31993760184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23311, 'Calle de Alfonso I 1908', 'Foto: Aurelio Grasa. Arco conmemorativo del Centenario de los Sitios, colocado a la entrada de la calle de Alfonso I en 1908. Fuente: Archivo Barboza-Grasa, a trav‚îú¬Æs de Heraldo de Arag‚îú‚îÇn.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65315100, -0.88207300, '0101000020E61000004FE8F527F139ECBFC32CB4739AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32505799200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32505799200.webp', 'https://www.flickr.com/photos/zaragozaantigua/32505799200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24932, 'Tren del Parque 1972', 'El Tren del Parque de Primo de Rivera junto a su estaci‚îú‚îÇn a la entrada del paseo de los Pl‚îú√≠tanos, actual de Manuel Aza‚îú‚ñía. En activo desde finales de los a‚îú‚ñíos 20, se trata de un tractor de recreo con apariencia de locomotora que tira dos vagones de pasajeros, cuyo dise‚îú‚ñío se ha mantenido con fidelidad al original de comienzos del siglo XX, si bien los veh‚îú¬°culos se han ido sustituyendo, en funci‚îú‚îÇn de su vida ‚îú‚ïëtil. El de la imagen es de los a‚îú‚ñíos 60.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63633900, -0.89787600, '0101000020E61000001FA0FB7266BBECBFAD156D8E73D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15239008624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15239008624.webp', 'https://www.flickr.com/photos/zaragozaantigua/15239008624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20867, 'El Batallador a‚îú‚ñíos 20', 'AHPZ. Estudio Coyne. (SF). "Parque Primo de Rivera. Monumento al Rey Alfonso I el Batallador." Obra de Jos‚îú¬Æ Bueno, esta escultura fue realizada con motivo del aniversario 800 de la conquista cristiana de la ciudad de Saraqusta, en 1118.', 1920, 1920, 1929, 'Anos 20', 'UNIVERSIDAD', 41.63359100, -0.89335200, '0101000020E61000003F1EFAEE5696ECBF1D05888219D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754143588.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754143588.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754143588/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23314, 'Calle de Alfonso I c.1895', 'In‚îú¬Ædita imagen capturada a nivel de calle en el Coso Alto y centrada en el arranque de la calle de Alfonso I hasta el desemboque, al fondo, en la plaza del Pilar. A la izquierda, imagen parcial de la antigua casa solariega de los marqueses de Tosos, que en 1833 fue vendida a un particular como inmueble del n‚î¨‚ïë 7 del Coso Alto. Reformada varias veces, cuando en la d‚îú¬Æcada de los 60 fue abierta la calle Alfonso I, este edificio mantuvo su alineamiento original, el de la imagen, hasta que en 1902 fue remodelado profundamente, ya como n‚î¨‚ïë 17 del Coso: realineado, se levant‚îú‚îÇ una nueva planta, se homologaron las alturas de sus bajos a las de los comercios que caracterizaban la calle, se le achaflan‚îú‚îÇ la esquina, y se le dio un estilo m‚îú√≠s profusamente decorativo, con balconadas y rejer‚îú¬°as m‚îú√≠s "modernas". A la derecha, inmueble del n‚î¨‚ïë 1 de Alfonso I y del n‚î¨‚ïë 23 del Coso Alto, construido en 1869 con proyecto del arquitecto Juan Antonio Atienza, tras la apertura de la nueva calle de Alfonso I, para el confitero Eusebio Molins, que en sus bajos habilit‚îú‚îÇ la "Confiter‚îú¬°a y reposter‚îú¬°a El Buen Gusto", con el caracter‚îú¬°stico chafl‚îú√≠n de los edificios de la burguesa calle, donde se daba salida a las pastas, dulces, bombones, caramelos y chocolates producidos en la golosa f‚îú√≠brica "La Gemela del Buen Gusto", sita junto a la antigua carretera de Valencia. Este edificio tambi‚îú¬Æn fue remodelado en 1902, con proyecto de Fernando de Yarza, dej‚îú√≠ndole su actual aspecto modernista.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65314600, -0.88207100, '0101000020E6100000220038F6EC39ECBFB1C1C2499AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48066993067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48066993067.webp', 'https://www.flickr.com/photos/zaragozaantigua/48066993067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23498, 'Palacio de S‚îú√≠stago 1861', 'Vista del Palacio de S‚îú√≠stago en el Coso Alto, construida por don Artal de Alag‚îú‚îÇn, III conde de S‚îú√≠stago y virrey de Arag‚îú‚îÇn. Desde 1843, Joaqu‚îú¬°n M‚î¨¬¨ Fern‚îú√≠ndez de C‚îú‚îÇrdoba, ‚îú‚ïëltimo conde de S‚îú√≠stago, arrend‚îú‚îÇ parte del palacio al Casino Principal de Zaragoza. A la derecha e inmediata, la casa del Marqu‚îú¬Æs de Campo Franco y a continuaci‚îú‚îÇn la casa de la condesa de Fuentes. Fuente: Mariano J‚îú‚ïëdez y Ortiz. ‚îú√ºlbum de Andr‚îú¬Æs Mart‚îú¬°n e Ip‚îú√≠s. Colecci‚îú‚îÇn Mariano Mart‚îú¬°n Casalderrey. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.65272400, -0.88186000, '0101000020E610000063D174763238ECBF3BA8C4758CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710512790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710512790.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710512790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23508, 'Arco de San Roque c.1932', 'Imagen del Arco de San Roque desde la plazuela de San Roque, como confluencia de las calles Palomeque (izquierda), y Valenzuela (derecha), con el Coso y el Hotel Oriente de tel‚îú‚îÇn de fondo. Con motivo de la peste de Marsella del a‚îú‚ñío 1721, sobre este arco se instal‚îú‚îÇ una imagen de San Roque y su perro, ya que seg‚îú‚ïën la santa madre iglesia cat‚îú‚îÇlica este es el santo protector en caso de darse esta y otras epidemias, sobre las que tendr‚îú¬°a mano (de santo). Al perro no se le han reconocido otros poderes que el del acompa‚îú‚ñíamiento y la contemplaci‚îú‚îÇn, y los resultados efectivos de la religiosa protecci‚îú‚îÇn a‚îú‚ïën no han sido demostrados de forma objetiva. Este arco daba acceso a la antigua Morer‚îú¬°a de la ciudad, o gueto de los musulmanes hasta su expulsi‚îú‚îÇn en 1610. En 1942 el arco y las viviendas inmediatas fueron piqueteadas para abrir una calle m‚îú√≠s cristiana y espaciosa, ampliar la plaza, y elevar nuevos y altos edificios de bancos y seguros con que flanquear a la barroca iglesia del antiguo Convento de Santo Tom‚îú√≠s de Villanueva.', 1932, 1932, 1932, 'Anos 30', 'CENTRO', 41.65321000, -0.88286500, '0101000020E6100000AA0EB9196E40ECBFC8B5A1629CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16556750848.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16556750848.webp', 'https://www.flickr.com/photos/zaragozaantigua/16556750848/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23511, 'Plaza de San Roque c.1930', 'Imagen de la portada de la barroca iglesia de Santo Tom‚îú√≠s de Villanueva, tambi‚îú¬Æn llamada de la Manter‚îú¬°a, en la plaza de San Roque. A la derecha queda la calle de Palomeque, antigua de la Manter‚îú¬°a. A la izquierda, restos del antiguo colegio de Santo Tom‚îú√≠s y San Jorge. La imagen se ha capturado junto al arco de San Roque. Fuente visual: Archivo fotogr‚îú√≠fico Jos‚îú¬Æ Galiay Sara‚îú‚ñíana (DARA-AHPZ).', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65317200, -0.88306700, '0101000020E61000009CA8A5B91542ECBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22523155070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22523155070.webp', 'https://www.flickr.com/photos/zaragozaantigua/22523155070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23513, 'Plaza de San Roque c.1936', 'Imagen capturada bajo el Arco de San Roque, de la irregular y antigua plaza de San Roque, como espacio de confluencia del final de la calle Palomeque (a la derecha), el arranque de la calle de Valenzuela (antigua de la Morer‚îú¬°a Cerrada), hacia la izquierda, y el acceso desde el Coso Alto por el propio Arco. Justo a la derecha, fuera de plano, quedaba la barroca fachada de la iglesia de la Manter‚îú¬°a, antigua de Santo Tom‚îú√≠s de Villanueva del convento de los Agustinos Observantes. Hacia la izquierda, por donde se encamina el grupo de personas, y torciendo la esquina, se llegaba al n‚î¨‚ïë 12 de la Morer‚îú¬°a, donde residiera la familia del joven Francisco Goya desde 1736 hasta 1757, aproximadamente. Al comienzo de los a‚îú‚ñíos 40, el Arco de San Roque ser‚îú¬°a derribado, y despu‚îú¬Æs le tocar‚îú¬°a el turno al resto de edificios de la imagen, para reordenar la zona de forma adecuada. Sic transit gloria Urbis. Fuente visual: Joaqu‚îú¬°n Gil Marraco (Cat‚îú√≠logo Exposici‚îú‚îÇn grupo "Calle a Calle", Colegio de Arquitectos de Zaragoza, abril/mayo de 1980). Amable aportaci‚îú‚îÇn de Jos‚îú¬Æ Luis Cintora.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65317200, -0.88306700, '0101000020E61000009CA8A5B91542ECBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24567643425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24567643425.webp', 'https://www.flickr.com/photos/zaragozaantigua/24567643425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23517, 'Calle de Palomeque c. 1935', 'Desde la relativa altura de una balconera en el antiguo n‚î¨‚ïë 29 de la calle de Palomeque, un vistazo integral de esa calle desde la inmediata plaza de San Roque, y hasta su arranque en la plaza de Sant‚îú√≠ngel, al fondo, y la antigua calle del Azoque. Justo a la espalda del fot‚îú‚îÇgrafo perduraba el arco de San Roque, nacido a esa advocaci‚îú‚îÇn como inane profilaxis a la peste marsellesa de principios de la d‚îú¬Æcada de los a‚îú‚ñíos veinte, en la diez y ocho centuria. A la izquierda, reconocible esquina de la barroca f‚îú√≠brica en ladrillo de la iglesia de la Manter‚îú¬°a, del antiguo colegio de Santo Tom‚îú√≠s de Villanueva. De esta iglesia el vial tom‚îú‚îÇ su nombre hasta que fue redenominado en homenaje al arzobispo que desde entonces le da nombre. Fuente visual: Archivo Juan Mora (Archivo Municipal de Zaragoza).', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65317200, -0.88306700, '0101000020E61000009CA8A5B91542ECBFDA54DD239BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28838648350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28838648350.webp', 'https://www.flickr.com/photos/zaragozaantigua/28838648350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23520, 'Gerardo Sancho 2002', 'Imagen del fot‚îú‚îÇgrafo Gerardo Sancho Ramo (Navarrete del R‚îú¬°o, Teruel, 1911), tomada en 2002 en el hotel Alfonso I. Disc‚îú¬°pulo de Miguel Mar‚îú¬°n Chivite, trabaj‚îú‚îÇ en Heraldo de Arag‚îú‚îÇn, Amanecer, El Noticiero y Europa Press. Tras realizar decenas de miles de fotograf‚îú¬°as de Zaragoza, que atesora el Archivo Municipal, se retir‚îú‚îÇ en 1981. Falleci‚îú‚îÇ en Valencia el 14 de diciembre de 2006. Fuente: Heraldo de Arag‚îú‚îÇn.', 2002, 2002, 2002, 'Siglo XXI', 'CENTRO', 41.65326300, -0.88223400, '0101000020E61000009C6A2DCC423BECBFEB573A1F9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31879664240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31879664240.webp', 'https://www.flickr.com/photos/zaragozaantigua/31879664240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23956, 'P.‚î¨‚ïë de la Independencia 1931', 'Tarde del 14 de abril de 1931. Celebraci‚îú‚îÇn, en el paseo de la Independencia, de la proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica Espa‚îú‚ñíola. Al fondo, la plaza de la Constituci‚îú‚îÇn. A la izquierda, la calle del Cinco de Marzo. Las "Mariannes" y la gran bandera de la Agrupaci‚îú‚îÇn Republicana del Arrabal, sobre una furgoneta de plataforma abierta Daimler-Mercedes U 2 T. Fuente: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65128100, -0.88210400, '0101000020E61000001077F52A323AECBFCAC0012D5DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14813401299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14813401299.webp', 'https://www.flickr.com/photos/zaragozaantigua/14813401299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23961, '&quot;El Ib‚îú‚îÇn&quot; 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 05/01/1974. El 12.10.1932 se inaugur‚îú‚îÇ el "Front‚îú‚îÇn Emendek" en la calle del Cinco de Marzo. Menos de dos a‚îú‚ñíos despu‚îú¬Æs, y hasta loa a‚îú‚ñíos 50, pasar‚îú¬°a a ser el gigantesco Cinema Front‚îú‚îÇn, con 1.250 localidades, y luego albergar‚îú¬°a la sala de Fiestas R‚îú¬°o Club. En abril de 1963 se volvi‚îú‚îÇ a utilizar como front‚îú‚îÇn de pelota vasca, hasta que en 1973, se instal‚îú‚îÇ una pista de hielo (‚î¨¬ΩEl Ib‚îú‚îÇn‚î¨‚ïó), concebida para la pr‚îú√≠ctica multitudinaria del patinaje desde una perspectiva exclusivamente l‚îú‚ïëdica. Pero se derriti‚îú‚îÇ enseguida.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65206400, -0.88280600, '0101000020E61000006CCD565EF23FECBF117349D576D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14936712681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14936712681.webp', 'https://www.flickr.com/photos/zaragozaantigua/14936712681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24021, 'Coso Alto 1917', 'Abril de 1917. Comitiva del entierro del torero zaragozano Florentino Ballesteros (1893-1917), a su paso por el Coso Alto en direcci‚îú‚îÇn a la plaza de la Constituci‚îú‚îÇn. En la parte superior y tras el palacio de S‚îú√≠stago, el reci‚îú¬Æn levantado edificio del Banco de Arag‚îú‚îÇn, con un andamio. Despu‚îú¬Æs, el cine Ena Victoria, donde la antigua casa de la Condesa de Fuentes. M‚îú√≠s all‚îú√≠, el Arco de San Roque.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.65309200, -0.88215500, '0101000020E61000009817601F9D3AECBFBEA3C68498D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24721067012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24721067012.webp', 'https://www.flickr.com/photos/zaragozaantigua/24721067012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24028, 'Quiosco de la M‚îú‚ïësica 1916', 'Jura de bandera en el paseo de la Independencia de Zaragoza, el 5 de marzo de 1916. Aspecto del Quiosco de la M‚îú‚ïësica durante la misa de campa‚îú‚ñía. Al fondo, la plaza de Espa‚îú‚ñía. A la derecha, el convento de Jes‚îú‚ïës. En primer plano, militares feligreses. Fuente: Archivo ABC.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.65115700, -0.88192200, '0101000020E6100000E5EE737CB438ECBFDEC7D11C59D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24841740425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24841740425.webp', 'https://www.flickr.com/photos/zaragozaantigua/24841740425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24031, 'P.‚î¨‚ïë de la Independencia 1931', 'Foto: Miguel Mar‚îú¬°n Chivite. Celebraci‚îú‚îÇn de la proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica, el 14 de abril de 1931. Un grupo de mujeres sobre un carro portan un retrato del fundador del PSOE, Pablo Iglesias. Al fondo, comercios en los porches del paseo Independencia, como la Camiser‚îú¬°a Jos‚îú¬Æ Barril, en el n‚îú‚ïëmero 10. Fuente: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26299814620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26299814620.webp', 'https://www.flickr.com/photos/zaragozaantigua/26299814620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24045, 'Tarz‚îú√≠n 1959', 'Imagen parcial, capturada en el segundo tramo del paseo de la Independencia, del callejeo publicitario realizado por el holand‚îú¬Æs "Circo Espa‚îú‚ñíol" venido al calor de las fiestas de octubre. Un elefante m‚îú√≠s asi‚îú√≠tico que africano es cabalgado por un actor que representa al personaje de Tarz‚îú√≠n, que conduce sin Cheeta, ni Jane. Fuente visual: www.todocoleccion.net/', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30975296975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30975296975.webp', 'https://www.flickr.com/photos/zaragozaantigua/30975296975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24069, 'Coso Alto 1974', 'Imagen del Coso alto capturada durante las fiestas mayores de la ciudad. Los personajes del "Verrug‚îú‚îÇn" (izquierda) y el "Forano" (derecha), integrantes de la comparsa de cabezudos, encorren a la chiquiller‚îú¬°a delante del acceso al cine Coso, que proyecta "El calzonazos", dom‚îú¬Æstica comedia ligera de Mariano Ozores protanizada por Paco Mart‚îú¬°nez Soria y Florinda Chico. Fuente visual: foto Antonio ‚îú√¨‚îú‚ñíiguez Valls, en www.todocoleccion.net/', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65328400, -0.88257400, '0101000020E6100000D09849D40B3EECBF028063CF9ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34050601131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34050601131.webp', 'https://www.flickr.com/photos/zaragozaantigua/34050601131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24095, 'Calle del Cinco de Marzo 1936', 'Imagen capturada en el interior del gran Front‚îú‚îÇn Cinema militarizado para acoger a algunos de los 1.200 requet‚îú¬Æs navarros llegados a la ciudad para consolidar y reforzar la defensa nacionalista de la ciudad ante las ofensivas republicanas para tratar de tomarla, durante las primeras semanas de la guerra. Causalmente, la nueva Corporaci‚îú‚îÇn Municipal redenominar‚îú¬°a esta calle poco despu‚îú¬Æs como homenaje a esta organizaci‚îú‚îÇn paramilitar carlista.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65212800, -0.88275700, '0101000020E61000001215AA9B8B3FECBF276728EE78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49669039592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49669039592.webp', 'https://www.flickr.com/photos/zaragozaantigua/49669039592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24243, 'P‚î¨‚ïë Independencia 1950', 'Bipolar imagen capturada en el antiguo Paseo de la Independencia n‚î¨‚ïë 12. A la derecha, escaparate del estudio de Miguel Mar‚îú¬°n Chivite, art‚îú¬°culos fotogr‚îú√≠ficos "Para fotos perfectas". A la izquierda, cartel del encuentro de f‚îú‚ïëtbol entre el Arenas S.D. y el C.D. Logro‚îú‚ñí‚îú¬Æs, correspondiente a la jornada 19 de la Liga de la Tercera Divisi‚îú‚îÇn, en el Campo de Deportes de San Jos‚îú¬Æ. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65101200, -0.88222200, '0101000020E61000008BF9B9A1293BECBFDBA6785C54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30207865902.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30207865902.webp', 'https://www.flickr.com/photos/zaragozaantigua/30207865902/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24247, 'Gustavo Freudenthal 1917', 'Gustavo Freudenthal (1869-1948), prusiano de Hannover, abri‚îú‚îÇ un estudio fotogr‚îú√≠fico en el Coso 31 de Zaragoza en 1906. Entre 1917 y 1930, se instal‚îú‚îÇ en el ‚îú√≠tico del Banco de Arag‚îú‚îÇn en el Coso 42, frente a la calle de Alfonso I. De 1914 a 1941, fue C‚îú‚îÇnsul Honorario de Alemania. Public‚îú‚îÇ sus fotos en ABC, La Ilustraci‚îú‚îÇn Espa‚îú‚ñíola y Americana o Heraldo de Arag‚îú‚îÇn. En la imagen, Freudenthal (al fondo a la derecha), posa con unos amigos en su reci‚îú¬Æn estrenado ‚îú√≠tico. M‚îú√≠s all‚îú√≠, despunta la torre de San Pablo.', 1917, 1917, 1917, 'Anos 10', 'CENTRO', 41.65296600, -0.88223400, '0101000020E61000009C6A2DCC423BECBF31B3CF6394D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32960238336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32960238336.webp', 'https://www.flickr.com/photos/zaragozaantigua/32960238336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24382, 'Colegio Escolapias c.1930', '"Patio del antiguo convento de los escolapios" (sic). Imagen del antiguo patio del colegio de Santo Tom‚îú√≠s de Villanueva y San Jorge, de los PP. Agustinos Observantes, sito en la plazuela de la Manter‚îú¬°a. Asociado a la f‚îú√≠brica de la iglesia y dem‚îú√≠s dependencias colegiales de esta Orden, fue realizado a finales del siglo XVII en limpias formas barrocas, y ladrillo como material fundamental. Desde 1883, en que fue adquirido por las MM. Escolapias para habilitarlo como colegio, fue objeto de varias intervenciones. La m‚îú√≠s radical estuvo asociada con el derribo del arco de San Roque y la ampliaci‚îú‚îÇn de la plaza del mismo nombre, el ensanchamiento de la antigua calle de la Morer‚îú¬°a Cerrada, y el despeje de la plaza de Salamero, a finales de los a‚îú‚ñíos 40 del pasado siglo. El nuevo edificio colegial resultante, dise‚îú‚ñíado por Teodoro R‚îú¬°os, ya no contaba con este patio. Sic transit gloria mundi. Fuente visual: Archivo Moreno, Fototeca del Patrimonio Hist‚îú‚îÇrico (www.mcu.es/)', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65301200, -0.88323900, '0101000020E6100000E3A7716F7E43ECBFA1F2AFE595D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22618247892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22618247892.webp', 'https://www.flickr.com/photos/zaragozaantigua/22618247892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24448, 'P.‚î¨‚ïë de la Independencia 1966', 'Tras la piqueta, los nuevos materiales constructivos aceleran el proceso de levantar el armaz‚îú‚îÇn met‚îú√≠lico del nuevo edificio del n‚î¨‚ïë 8 del paseo de la Independencia. Su revestimiento acristalado ser‚îú√≠ tambi‚îú¬Æn se‚îú‚ñía de identidad de los nuevos tiempos. Su funci‚îú‚îÇn: unos grandes almacenes. A su izquierda, el n‚î¨‚ïë 10 tambi‚îú¬Æn ser‚îú√≠ piquetado y construido bajo par‚îú√≠metros constructivos similares, aunque los cristales del exterior tendr‚îú√≠n un te‚îú‚ñíido un poco m‚îú√≠s oscuro, en l‚îú¬°nea corporativa con la entidad bancaria que lo posee. A su derecha, la calle Requet‚îú¬Æ Aragon‚îú¬Æs, que permite una visual parcial de la Iglesia de Santiago el Mayor. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65127200, -0.88217800, '0101000020E6100000A305685BCD3AECBF776682E15CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217618591.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217618591.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217618591/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24525, 'Calle del Requet‚îú¬Æ Aragon‚îú¬Æs c.1960', 'Imagen centrada en la fachada del antiguo caf‚îú¬Æ Nik‚îú¬Æ, con proyecto de los arquitectos Regino y Jos‚îú¬Æ Borobio, abierto en 1940 en el local comercial del n‚î¨‚ïë 10 de la calle del Requet‚îú¬Æ Aragon‚îú¬Æs (antiguo n‚î¨‚ïë 7 de la calle del 5 de Marzo), flanqueado por el Front‚îú‚îÇn Cinema (izquierda) y un patio de ingreso a la Diputaci‚îú‚îÇn Provincial (a la derecha, fuera de plano). Este establecimiento ha quedado incorporado a la historia de la cultura zaragozana de mediados del siglo XX por servir de sede, primero, de la Pe‚îú‚ñía Nik‚îú¬Æ, que en los a‚îú‚ñíos cuarenta reuni‚îú‚îÇ una destacada pluralidad de personalidades del mundillo cultural local de la ‚îú¬Æpoca. En la d‚îú¬Æcada de los cincuenta el Nik‚îú¬Æ se convirti‚îú‚îÇ en el domicilio social de la Oficina Po‚îú¬Ætica Internacional por la iniciativa del poeta Miguel Labordeta, que tuvo de "oficinistas" a algunos de los m‚îú√≠s floridos representantes de la cultura zaragozana de la ‚îú¬Æpoca, con poetas, pintores, novelistas, cineastas, dramaturgos, actores, cr‚îú¬°ticos, cient‚îú¬°ficos, activistas culturales, diletantes y entusiastas de la cultura en general. Este antiguo caf‚îú¬Æ Nik‚îú¬Æ fue clausurado en 1969. Fuente visual: javierbarreiro.wordpress.com', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.65185700, -0.88286300, '0101000020E61000007C26FBE76940ECBF9755D80C70D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41071417531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41071417531.webp', 'https://www.flickr.com/photos/zaragozaantigua/41071417531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24528, 'P.‚î¨‚ïë de la Independencia 1975', 'Nocturna imagen capturada en el paseo de la Independencia durante las inciertas navidades del a‚îú‚ñío 1975, las primeras tras la reciente muerte del dictador Franco. Lucen esplendorosos los neones con motivos tradicionales de la festividad impostada al natural solsticio de invierno, destacando por su tama‚îú‚ñío los luminosos adosados a la fachada de los grandes almacenes Galer‚îú¬°as Preciados. Por la autopista ruge la automovil‚îú¬°stica marabunta, paseo arriba, paseo abajo.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65115800, -0.88191000, '0101000020E6100000D47D00529B38ECBFAF43352559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47961471822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47961471822.webp', 'https://www.flickr.com/photos/zaragozaantigua/47961471822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25055, 'Cardenal y Alcalde 1961', 'Ayuntamiento de Zaragoza/Foto Lozano. Setiembre 1961. Con motivo del V Congreso Eucar‚îú¬°stico Nacional, el zaragozano Cardenal de Sevilla, Jos‚îú¬Æ Mar‚îú¬°a Bueno Monreal y el Alcalde de Zaragoza entre 1954 y 1966, Luis G‚îú‚îÇmez Laguna, desfilan en coche descubierto por la ciudad, con nocturnidad y disparidad de actitudes. La chaqueta blanca del mun‚îú¬°cipe era parte del uniforme del partido gobernante: el Movimiento Nacional. El Mercedes est‚îú√≠ pasando ante el n‚îú‚ïëmero 9 del Coso Alto, a la altura de Calzados Segarra.', 1961, 1961, 1961, 'Anos 60', 'CENTRO', 41.65341800, -0.88290500, '0101000020E610000038328FFCC140ECBF124F7633A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14758105399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14758105399.webp', 'https://www.flickr.com/photos/zaragozaantigua/14758105399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25089, 'Coso Alto 1908', 'Paso de la carroza de Alfonso XIII por el Coso Alto, a la altura del palacio de S‚îú√≠stago, con el Gran Caf‚îú¬Æ de Par‚îú¬°s en sus bajos. Poco despu‚îú¬Æs la comitiva ingresar‚îú√≠ en la calle Alfonso I. Fuente visual: revista "Ilustraci‚îú‚îÇn militar. Ej‚îú¬Ærcito y Marina".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65291000, -0.88188000, '0101000020E61000002AE3DF675C38ECBF9D9D0C8E92D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32431683413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32431683413.webp', 'https://www.flickr.com/photos/zaragozaantigua/32431683413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25113, 'Alegor‚îú¬°a de Zaragoza 1889', 'Ars Catalogi/DPZ "Alegor‚îú¬°a de Zaragoza", de Alejandro Ferrant. En la planta "noble" del Palacio de los Condes de S‚îú√≠stago se encuentran los salones VIP. El arquitecto Ricardo Magdalena, responsable de recuperar el edificio, encarg‚îú‚îÇ en 1889 al pintor Alejandro Ferrant Fischermans una alegor‚îú¬°a de Zaragoza para ilustrar el abovedado techo del sal‚îú‚îÇn principal. Y ah‚îú¬° sobrevuela la estancia esta joven llamada Zaragoza, simbolizada como madre de insignes personas representadas a los lados; como resistente antiafrancesada a su pesar; como lugar cristianamente empoderado tras la Venida de la Virgen en carne mortal sobre columnam‚îú‚îÇvil; y como amante mel‚îú‚îÇmana de la jota que le est‚îú√≠ echando un terrenal jotero, justo debajo de la nube en la que aposenta sus reales. Una Zaragoza convencional, confesional, sumante de t‚îú‚îÇpicos tradicionalistas.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65272400, -0.88186000, '0101000020E610000063D174763238ECBF3BA8C4758CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14946140527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14946140527.webp', 'https://www.flickr.com/photos/zaragozaantigua/14946140527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25126, 'Toma de Zaragoza 1809', '"Si‚îú¬øge et Prise de Saragosse- Guerre d''Espagne (1807-1814)" : [estampe] ‚îú√´diteur : Paris chez la V.ve Ch‚îú¬Æreau Mde d''Estampes Rue St Jacques N‚î¨‚ñë 10. En un entorno irreal, se pretende representar el momento en que las tropas imperiales francesas irrumpen en la ciudad durante el Segundo Sitio, en febrero de 1809, tras la ruptura de las l‚îú¬°neas de defensa, mientras los defensores huyen y se precipitan en una iglesia, que podr‚îú¬°a ser desde la del convento de San Ildefonso, hasta la de los Inv‚îú√≠lidos de Par‚îú¬°s. Fuente visual: catalogue.bnf.fr/ark:/12148/cb415145946.', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.65230400, -0.88452800, '0101000020E610000064AE0CAA0D4EECBF66868DB27ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16334501623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16334501623.webp', 'https://www.flickr.com/photos/zaragozaantigua/16334501623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25166, 'Calle del Ser‚îú‚îÇn a‚îú‚ñíos 30', 'Acuarela de Ambrosio del Ruste identificada como "Calle del Ser‚îú‚îÇn". Este callej‚îú‚îÇn part‚îú¬°a de la calle de Azoque, en las inmediaciones de la de Ram‚îú‚îÇn Pignatelli. Desapareci‚îú‚îÇ con la apertura de la V‚îú¬°a Imperial. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.65304700, -0.88352100, '0101000020E6100000F0880AD5CD45ECBF1EE0490B97D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32399494456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32399494456.webp', 'https://www.flickr.com/photos/zaragozaantigua/32399494456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25188, 'Plaza de Miguel Salamero 1980', 'Dibujo centrado en una vista panor‚îú√≠mica orientada hacia el noreste de la plaza de Miguel Salamero (antigua de Santa Fe). De izquierda a derecha, el ingreso a la calle del Azoque, la iglesia parroquial de Santiago el Mayor, la mole descontextualizada del Edificio Salamero, el colegio de las Escolapias y la anexa iglesia de la Manter‚îú¬°a, la torre angular del edificio del Banco de Arag‚îú‚îÇn, y el desemboque de la calle del Cinco de Marzo. En el centro de la plaza, aspecto de su arbolada isleta central establecida tras la construcci‚îú‚îÇn del aparcamiento habilitado en su subterr‚îú√≠neo. Este fue el aspecto de la plaza hasta su m‚îú√≠s reciente reforma, que le confiri‚îú‚îÇ su actual aspecto a finales del mes de marzo del presente a‚îú‚ñío 2023.', 1980, 1980, 1980, 'Anos 80', 'CENTRO', 41.65229600, -0.88423800, '0101000020E6100000A12C7C7DAD4BECBFE3A7716F7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53268033853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53268033853.webp', 'https://www.flickr.com/photos/zaragozaantigua/53268033853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25277, 'Cine Rex 1955', 'Cine propiedad de la empresa Zaragoza Urbana S.A., situado en la Calle de Requet‚îú¬Æ Aragon‚îú¬Æs n‚î¨‚ïë 5, fue dise‚îú‚ñíado por los arquitectos Jos‚îú¬Æ de Yarza y Teodoro R‚îú¬°os. Se inaugur‚îú‚îÇ en mayo de 1954 con la hollywoodiense cinta de cine fant‚îú√≠stico "La t‚îú‚ïënica sagrada", siendo la primera sala de la ciudad que incorpor‚îú‚îÇ el novedoso sistema de proyecci‚îú‚îÇn cinemascope. Fue reformado en 1966, y en 1994 fue reconvertido en multicines, con tres espacios donde antes hab‚îú¬°a uno, denominados "Palafox-Las Salas". En la imagen, aspecto exterior de la entrada al cine desde Requet‚îú¬Æ Aragon‚îú¬Æs en el verano de 1955, cuando se proyectaba la mediocre cinta norteamericana "L‚îú¬°nea secreta". Fuente visual: Foto Heraldo.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65174900, -0.88300800, '0101000020E61000005E6743FE9941ECBFB119E0826CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020029406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020029406.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020029406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25287, 'Sara Montiel 1957', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1957. Imagen de Mar‚îú¬°a Antonia Abad Fern‚îú√≠ndez en su habitaci‚îú‚îÇn del hotel "Goya", durante la visita a la ciudad con motivo del estreno del filme "El ‚îú‚ïëltimo cupl‚îú¬Æ" (dirigida por Juan de Ordu‚îú‚ñía). El recibimiento a la estrella fue apote‚îú‚îÇsico, e incluso un joven cadete de la AGM de 19 a‚îú‚ñíos de edad, llamado Juan Carlos, se acerc‚îú‚îÇ al evento. Aunque en la imagen parece a punto de ponerse a hablar por el zapat‚îú‚îÇfono, s‚îú‚îÇlo estaba descansando los pies sentada sobre su cama, en el transcurso de una entrevista a los medios locales. Ella era as‚îú¬° de natural.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.65167100, -0.88286500, '0101000020E6100000AA0EB9196E40ECBF356090F469D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15595965147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15595965147.webp', 'https://www.flickr.com/photos/zaragozaantigua/15595965147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25300, 'P.‚î¨‚ïë de la Independencia 1988', 'Foto Eduardo Zamarripa, 1988. Vista a‚îú¬Ærea del paseo de la Independencia de Zaragoza en 1988. Fuente: Arag‚îú‚îÇn desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CENTRO', 41.65106000, -0.88239400, '0101000020E6100000D3F88557923CECBFECDD1FEF55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20293631286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20293631286.webp', 'https://www.flickr.com/photos/zaragozaantigua/20293631286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25320, 'Pasaje Palafox 1968', 'Foto: Jos‚îú¬Æ Antonio Duce. Pasaje Palafox, entre el paseo de la Independencia (a la espalda del fot‚îú‚îÇgrafo) y la calle del Requet‚îú¬Æ Aragon‚îú¬Æs. Fuente visual: www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65111600, -0.88275800, '0101000020E6100000290989B48D3FECBF80F3E2C457D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23427693650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23427693650.webp', 'https://www.flickr.com/photos/zaragozaantigua/23427693650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25360, 'P.‚î¨‚ïë de la Independencia 1966', 'Luminosa imagen capturada en el paseo de la Independencia y centrada en el tramo comprendido entre las calles de Fray Diego Murillo (izquierda) y Requet‚îú¬Æ Aragon‚îú¬Æs (derecha), durante la construcci‚îú‚îÇn de la moderna gran superficie comercial vertical destinada a la Sociedad Espa‚îú‚ñíola de Precios ‚îú√únicos, levantada sobre el solar dejado por el antiguo n‚î¨‚ïë 8 del paseo. A su lado perduraba a‚îú‚ïën el antiguo n‚î¨‚ïë 10, edilicio vestigio de cuando aconteciera la enso‚îú‚ñíaci‚îú‚îÇn de que este vial acaso fuera durante un tiempo remedo de la parisina rue de Rivoli. La diferencia de escala (l‚îú¬Æase aprovechamiento edificable) era demasiado golosa como para que fuera posible su perdurancia. Quedan im‚îú√≠genes como esta, eso s‚îú¬°, recuerdo material y objetivo de esa ciudad imaginada que no fue posible porque no se quiso. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65101800, -0.88220200, '0101000020E6100000C5E74EB0FF3AECBFBD8DCD8E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39819291185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39819291185.webp', 'https://www.flickr.com/photos/zaragozaantigua/39819291185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25363, 'P.‚î¨‚ïë de la Independencia 1979', 'Imagen capturada en el paseo de la Independencia desalojado de su rutinaria ocupaci‚îú‚îÇn de veh‚îú¬°culos, y pateado por peatones de forma ins‚îú‚îÇlita durante las primeras Fiestas del Pilar tras la recuperaci‚îú‚îÇn de la democracia municipal. Las programaci‚îú‚îÇn festiva inaugur‚îú‚îÇ la inclusi‚îú‚îÇn de este paseo como escenario al aire libre de m‚îú‚ïësica en directo, en este caso de orquestas de verbena, donde la concurrencia se pod‚îú¬°a dar un baile sin que nadie objetara nada. Otros actos de car‚îú√≠cter abierto promovieron la participaci‚îú‚îÇn ciudadana como filosof‚îú¬°a que vertebrara unas fiestas que hasta entonces giraban en torno a ceremonias religiosas y actos de regodeo de la elite local. El cambio de paso intent‚îú‚îÇ ser zancadilleado por los poderes hegem‚îú‚îÇnicos hasta ese momento, como fue el caso del gobernador Civil Francisco La‚îú¬°na Garc‚îú¬°a, elegido en tiempos predemocr‚îú√≠ticos y todav‚îú¬°a en funciones. Fue el primer e improvisado paso hacia otro modelo de fiestas. La escena tiene lugar en el tramo del paseo flanqueado entre los grandes almacenes de Galer‚îú¬°as Preciados, a la izquierda, y el Sepu a la derecha, con la plaza de Arag‚îú‚îÇn al fondo.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65115800, -0.88191000, '0101000020E6100000D47D00529B38ECBFAF43352559D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48793549668.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48793549668.webp', 'https://www.flickr.com/photos/zaragozaantigua/48793549668/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25494, 'Arco de San Roque a‚îú‚ñíos 20', 'Archivo RUIZ VERNACCI. 1910-1950. "Arco de San Roque". Era el arco de mayor tr‚îú√≠fico humano de la ciudad, antiguo lugar de paso para el movimiento de personas y mercanc‚îú¬°as entre el Coso alto, la plazuela de San Roque, la calle de Palomeque, la plazuela de Sant‚îú√≠ngel, y la calle del Azoque. Fue derribado en 1942 para ensanche al tr‚îú√≠fico rodado de la calle Tte. Cnel. Valenzuela. En la imagen, el arco visto desde el Coso, con una sastrer‚îú¬°a a su izquierda, una camiser‚îú¬°a a su derecha, y un se‚îú‚ñíor fumando tabaco en medio, unos ni‚îú‚ñíos jugando... vida, en suma.', 1920, 1920, 1929, 'Anos 20', 'CENTRO', 41.65315400, -0.88265500, '0101000020E610000002D4D4B2B53EECBF34A0DE8C9AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14680155020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14680155020.webp', 'https://www.flickr.com/photos/zaragozaantigua/14680155020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25519, 'Calle de la Independencia 1903', 'Imagen centrada en el ef‚îú¬°mero arco triunfal patrocinado por el Ayuntamiento de Zaragoza y erigido en la calle de la Independencia con motivo de la primera visita oficial del rey Alfonso XIII a la ciudad. Fue dise‚îú‚ñíado por el arquitecto municipal Ricardo Magdalena en el estilo neog‚îú‚îÇtico al gusto de la ‚îú¬Æpoca con detalles ornamentales vegetales modernistas, destacando por su rareza el parab‚îú‚îÇlico arco central de insp‚îú¬ºraci‚îú‚îÇn gaudiana. Al fondo, el tambi‚îú¬Æn ef‚îú¬°mero arco de la Real Maestranza dise‚îú‚ñíado por el ingeniero Manuel de Isasi Isasmendi en las inmediaciones a la plaza de la Constituci‚îú‚îÇn. A la derecha, airoso frontispicio que indica la ubicaci‚îú‚îÇn del antiguo convento de Jerusal‚îú¬Æn de las hermanas Franciscanas Clarisas. Fuente visual: fot. Agust‚îú¬°n Lorente Bernal, en Mar‚îú¬°a Pilar Poblador Muga, "La influencia del modernismo catal‚îú√≠n en la arquitectura de Zaragoza", IFC, 2013.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65101800, -0.88220200, '0101000020E6100000C5E74EB0FF3AECBFBD8DCD8E54D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29392351398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29392351398.webp', 'https://www.flickr.com/photos/zaragozaantigua/29392351398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25692, 'Aparcamiento de Miguel Salamero 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/Febrero 1974. Imagen capturada durante la ampliaci‚îú‚îÇn del aparcamiento de la plaza de Miguel Salamero en la zona de ingreso desde la nueva V‚îú¬°a Imperial, trazada entre este espacio donde estuviera la derribada manzana de viviendas delimitada por la calle del Azoque y la iglesia de Santiago el Mayor, que al fondo ya muestra recrecida su torre derecha.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65228800, -0.88430800, '0101000020E6100000D9EA724A404CECBF60C9552C7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14905237655.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14905237655.webp', 'https://www.flickr.com/photos/zaragozaantigua/14905237655/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25699, 'Calle Azoque 1976', 'Es setiembre, y ese a‚îú‚ñío la ma‚îú‚ñíana refrescaba. Desde la plaza de Salamero, antigua de Santa Fe, una mirada por la calle Azoque hacia la plaza del Carmen, al fondo, cuyo entorno estaba mudando aceleradamente desde la operaci‚îú‚îÇn "Cuarteles", y el que fuera de artiller‚îú¬°a del Carmen fuera derribado y urbanizado luego con nuevos y altos bloques, un hotel, dos cines... La calle de la Vieja Guardia, de forma especial, estaba en plena ebullici‚îú‚îÇn constructiva, en ambas aceras, llev‚îú√≠ndose por delante, por a‚îú‚ñíadidura, todas las casonas de siglos pasados, incluyendo la "Casa del Obispo". La higienizaci‚îú‚îÇn y modernizaci‚îú‚îÇn de la vieja ciudad marchaba viento en popa, al menos al mismo ritmo que el crecimiento de beneficios de los emprendedores inmobiliarios implicados Fuente visual: Archivo P‚îú‚ïëblico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65203200, -0.88420600, '0101000020E6100000CAA99D616A4BECBF05F9D9C875D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19087800601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19087800601.webp', 'https://www.flickr.com/photos/zaragozaantigua/19087800601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25268, 'Pl. de la Constituci‚îú‚îÇn 1902', 'Fuente de la Princesa, o Neptuno. Fuente visual: Ignacio Coyne, Archivo Coyne, AHPZ', 1902, 1902, 1902, 'Anos 1900', 'CENTRO', 41.65214400, -0.88088500, '0101000020E6100000C72E51BD3530ECBF2D24607479D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14699563488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14699563488.webp', 'https://www.flickr.com/photos/zaragozaantigua/14699563488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25704, 'Calle Azoque 1976', 'Desde la plaza de N‚î¨¬¨ S‚î¨¬¨ del Carmen, una vista de la bulliciosa callle Azoque. A la izquierda, entrada al cine "Fleta", que en esos momentos proyectaba "La batalla de Midway" con el novedoso sistema "Sensurround", un apabullante vibrador sonoro que dejaba temblando a los cines, y a sus espectadores. Al fondo, la plaza de Salamero, antigua de Santa Fe. A la derecha, la manzana parcialmente pendiente de construcci‚îú‚îÇn en la esquina entre la antigua calleja de San Jer‚îú‚îÇnimo con la calle de C‚îú√≠diz. Fuente: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65121300, -0.88458200, '0101000020E6100000302B14E97E4EECBF72DD94F25AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23699796369.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23699796369.webp', 'https://www.flickr.com/photos/zaragozaantigua/23699796369/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25705, 'Plaza de Salamero 1976', 'Imagen de la plaza de Salamero, antigua de la Santa Fe, cuando sobre la original calle Azoque estaba emergiendo la estructura de acero, cemento y cristal del moderno "Edificio Residencial-Comercial Salamero", una de las cimas de la nueva Zaragoza, en casi todas sus contrastadas acepciones. Al fondo, a la derecha, la calle Valenzuela, y la reciente sede del Banco de Arag‚îú‚îÇn, con su sirena-reloj semoviente. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65246300, -0.88418500, '0101000020E6100000ECA353573E4BECBFCE6C57E883D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23800373339.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23800373339.webp', 'https://www.flickr.com/photos/zaragozaantigua/23800373339/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25708, 'Calle Cinco de Marzo 1923', 'Calle del Cinco de Marzo. Al fondo, plaza de Salamero e iglesia de Santiago. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1923, 1923, 1923, 'Anos 20', 'CENTRO', 41.65200600, -0.88345600, '0101000020E61000002A8F6E844545ECBFDC65BFEE74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24289293743.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24289293743.webp', 'https://www.flickr.com/photos/zaragozaantigua/24289293743/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25712, 'Plaza de Salamero 1974', 'Imagen del derribo del antiguo n‚î¨‚ïë 2 (*) de la calle del 5 de marzo, redenominada "Requet‚îú¬Æ Aragon‚îú¬Æs" por el componente carlista del r‚îú¬Ægimen franquista, y que tuvo que esperar hasta la recuperaci‚îú‚îÇn de la democracia municipal, en 1979, para recuperar su nombre. Este edificio era esquinero a la plaza de Salamero, antigua de Santa Fe, desde donde se ha capturado la imagen. Posiblemente dise‚îú‚ñíado por Fernando de Yarza en 1905, fue uno de los m‚îú‚ïëltiples ejemplos del trato dado al patrimonio urban‚îú¬°stico de la ciudad en los convulsos a‚îú‚ñíos 70 del pasado siglo. (*) Posteriormente, la numeraci‚îú‚îÇn de la calle fue "traslocada" de forma radical: pares e impares se cambiaron de acera, y comenzaron desde el paseo de la Independencia, cosa que antes hac‚îú¬°an desde la plaza de Salamero. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65205800, -0.88375400, '0101000020E6100000A3B1F677B647ECBF2E8CF4A276D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26435116022.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26435116022.webp', 'https://www.flickr.com/photos/zaragozaantigua/26435116022/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25715, 'Plaza de Salamero 1974', 'Imagen capturada, posiblemente, desde la recrecida torre sur de la iglesia parroquial de Santiago el Mayor, y centrada en las obras de construcci‚îú‚îÇn de la singular y gran torre de oficinas comerciales y viviendas de la plaza de Salamero, antigua de Santa Fe. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.65269900, -0.88426900, '0101000020E610000062BB7B80EE4BECBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33838883892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33838883892.webp', 'https://www.flickr.com/photos/zaragozaantigua/33838883892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25716, 'Pl. de Salamero 1929', 'Imagen capturada desde cierta altura en la plaza de Salamero (antigua de Santa Fe), y centrada en la fachada que a ella ofrec‚îú¬°a el tramo de la calle de Azoque, desde la calle de Telesforo Peromarta (a la derecha, fuera de plano), y hasta la calle de la Biblioteca (hacia a la izquierda, lo mismo). Ya en esta ‚îú¬Æpoca se especulaba con la posibilidad de embellecer la ciudad eliminando rincones provincianos y antiest‚îú¬Æticos, y este parec‚îú¬°a ser uno de ellos. Unas d‚îú¬Æcadas despu‚îú¬Æs, esta manzana fue derribada para dar paso a un necesario vial de gran capacidad para el tr‚îú√≠fico rodado, y espacio a un singular megabloque de oficinas comerciales. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65242900, -0.88396100, '0101000020E610000006103E946849ECBF22FB20CB82D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35182409746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35182409746.webp', 'https://www.flickr.com/photos/zaragozaantigua/35182409746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25717, 'Calle de C‚îú√≠diz 1911', 'Imagen capturada en la calle de C‚îú√≠diz durante las tareas de extinci‚îú‚îÇn del incendio que el 19 de noviembre de ese a‚îú‚ñío asol‚îú‚îÇ la droguer‚îú¬°a y ferreter‚îú¬°a del Carmen, cuyo titular era Enrique Lamana, sita en el local comercial del inmueble del n‚î¨‚ïë 5 de esa calle, frente al convento de las Recogidas. En la fotograf‚îú¬°a aparecen guardias de seguridad y elementos del arma de Artiller‚îú¬°a y de Ingenieros del cercano cuartel del Carmen, que reforzaron a la brigada municipal de bomberos. Entre el mojado adoquinado, v‚îú¬°as de la tranviaria l‚îú¬°nea de Madrid que hacia la izquierda conducen a la plaza del Pueblo. Al fondo y a la izquierda, tambi‚îú¬Æn, balcones del inmueble del n‚î¨‚ïë 106 de la calle del Azoque.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.65108600, -0.88425900, '0101000020E61000007F32C687D94BECBF15713AC956D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50133110698.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50133110698.webp', 'https://www.flickr.com/photos/zaragozaantigua/50133110698/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25908, 'Coso Alto ca. 1970', 'Unidad del tranv‚îú¬°a de la l‚îú¬°nea 5 Venecia-Delicias, a su paso por la confluencia del Coso Alto con la plaza de San Roque. Al fondo, edificio de La Adri‚îú√≠tica. Fuente: Agencia EFE.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.65318500, -0.88243700, '0101000020E6100000A5F8F884EC3CECBF6F9EEA909BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24503955812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24503955812.webp', 'https://www.flickr.com/photos/zaragozaantigua/24503955812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25912, 'Coso Alto c.1905', 'Vista, desde cierta altura, del tramo del Coso Alto desde su emboque en la plaza de la Constituci‚îú‚îÇn. con una interesante panor‚îú√≠mica del lado de los pares, con visual de los antiguos palacios de S‚îú√≠stago, del marqu‚îú¬Æs de Campo Franco, y del conde Fuentes. Casi a continuaci‚îú‚îÇn, el arco de San Roque, con acceso a la plazuela del mismo nombre. Por delante de esta edilicia fachada, transita la unidad n‚î¨‚ïë 7, posiblemente de la tranviaria y electrificada l‚îú¬°nea 2, o "Madrid". Inmediata, en la acera de los impares, parada de galeras de alquiler, y la met‚îú√≠lica estructura sobre la que se desplegaban los toldos que proteg‚îú¬°an a los comercios de ese lado de la inclemente y severa solana. Huecograbado de la serie "Arag‚îú‚îÇn" de postales editadas por el librero Cecilio Gasca. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'CENTRO', 41.65292400, -0.88195200, '0101000020E61000008F899466F338ECBF02637D0393D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27411584795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27411584795.webp', 'https://www.flickr.com/photos/zaragozaantigua/27411584795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25929, 'Coso Alto 1968', 'Imagen del tramo alto del Coso desde su arranque (al fondo) y hasta la plaza de la Manter‚îú¬°a (a la izquierda, fuera de plano), con una interesante panor‚îú√≠mica en los principios del verano que incluye el colegio de los PP. Escolapios, la antigua Casa de las Monas que marca el inicio de la manzana entre las calles Cerd‚îú√≠n y Escuelas P‚îú¬°as, el edificio de la Audiencia Territorial, el hotel Oriente y el cine Coso, donde se proyecta la simp‚îú√≠tica comedia a la espa‚îú‚ñíola Cuarenta grados a la sombra, dirigida por Mariano Ozores y con destacado elenco encabezado por Jos‚îú¬Æ Luis L‚îú‚îÇpez V‚îú√≠zquez, Alfredo Landa, Antonio Ozores, Gracita Morales, Julieta Serrano, Laly Soldevila. Centra la imagen una composici‚îú‚îÇn tranviaria (posiblemente de la serie 50) en servicio en la l‚îú¬°nea 5 Venecia Delicias encaminada hacia la plaza de Huesca (antigua de Rocasolano). Unos pardales viajan de gratis con cierto riesgo subidos en el parachoques trasero del remolque o trabuca. A la izquierda, vista parcial del gran solar resultante del derribo de los antiguos edificios del lado de los pares comprendidos entre los n‚îú‚ïëmeros 24 y 34. Fuente visual: Colecci‚îú‚îÇn JAHL (Zaragoza), en Zaragoza estereosc‚îú‚îÇpica. Fotograf‚îú¬°a profesional y comercial 1850-1970, PUZ.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65346900, -0.88282100, '0101000020E6100000C11A67D31140ECBF94F947DFA4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37573472676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37573472676.webp', 'https://www.flickr.com/photos/zaragozaantigua/37573472676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20953, 'Puente del G‚îú√≠llego 1824', 'Litograf‚îú¬°a dibujada por Louis Albert Guillain, Bar‚îú‚îÇn de Bacler d''Albe en 1824. Arcadas del puente sobre el r‚îú¬°o G‚îú√≠llego en Zaragoza, que se supuso romano y en realidad fue edificado entre 1563 y 1588, sito en el emplazamiento del actual puente de hierro al final de la avenida de Catalu‚îú‚ñía. La caseta del cobro del peaje (izquierda) se construy‚îú‚îÇ en 1813. A la derecha, pasarela algo m‚îú√≠s modesta, de tres siglos despu‚îú¬Æs. Historia de Zaragoza, 1988. Fuente visual: Colecci‚îú‚îÇn Jos‚îú¬Æ Luis Cintora.', 1824, 1824, 1824, 'Siglo XIX', 'EL RABAL', 41.67089800, -0.84220400, '0101000020E6100000AAEE91CD55F3EABFD57954FCDFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15237850881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15237850881.webp', 'https://www.flickr.com/photos/zaragozaantigua/15237850881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20993, 'R‚îú¬°o G‚îú√≠llego 1820', 'Plano de la porci‚îú‚îÇn del r‚îú¬°o G‚îú√≠llego en el Camino Real a Barcelona (abajo a la derecha) y Santa Isabel. Est‚îú√≠ dibujado el antiguo puente de piedra renacentista que se encontraba derruido, sirviendo de dique involuntario para desviar las aguas del r‚îú¬°o. Fuente: Centro Geogr‚îú√≠fico del Ej‚îú¬Ærcito.', 1820, 1820, 1820, 'Siglo XIX', 'EL RABAL', 41.67107800, -0.84236800, '0101000020E61000003C4D66BCADF4EABF558847E2E5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31369321281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31369321281.webp', 'https://www.flickr.com/photos/zaragozaantigua/31369321281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21194, 'Hermanos Villuendas 1893', 'Imagen capturada posiblemente bajo la estructura del puente colgante de Santa Isabel sobre el r‚îú¬°o G‚îú√≠llego, y centrada en los que podr‚îú¬°an ser los hermanos Hilari‚îú‚îÇn y Enrique Villuendas, realizando a su vez una fotograf‚îú¬°a a dos pardales. Estos dos zaragozanos, desconocidos hasta hace pocos a‚îú‚ñíos, pertenecen al grupo de pioneros de la fotograf‚îú¬°a en la ciudad, fundamentalmente por un impagable grupo de fotograf‚îú¬°as realizadas al hilo de la construcci‚îú‚îÇn del edificio que albergar‚îú¬°a a la Facultad de Medicina y Ciencias (1887-1893).', 1893, 1893, 1893, 'Siglo XIX', 'EL RABAL', 41.67094000, -0.84209500, '0101000020E6100000FC00A43671F2EABF04CAA65CE1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50278175768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50278175768.webp', 'https://www.flickr.com/photos/zaragozaantigua/50278175768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21582, 'Azucarera del G‚îú√≠llego c.1920', 'Aspecto parcial de la Azucarera del G‚îú√≠llego. Al fondo, sus dos chimeneas. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24528232779.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24528232779.webp', 'https://www.flickr.com/photos/zaragozaantigua/24528232779/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21590, 'Puente de Santa Isabel c.1920', 'Acceso desde la margen derecha del r‚îú¬°o G‚îú√≠llego al puente de Santa Isabel, con tr‚îú√≠nsito de un reba‚îú‚ñío de ovejas. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.67108200, -0.84225800, '0101000020E6100000766B990CC7F3EABF9677D503E6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803301391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803301391.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803301391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21597, 'Azucarera del G‚îú√≠llego c.1920', 'Instalaciones de la Azucarera del G‚îú√≠llego. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24896073885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24896073885.webp', 'https://www.flickr.com/photos/zaragozaantigua/24896073885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21652, 'Puente del G‚îú√≠llego c.1925', 'Imagen capturada junto a la ribera de la margen izquierda del r‚îú¬°o G‚îú√≠llego y centrada en el decimon‚îú‚îÇnico puente colgante que salvaba el r‚îú¬°o para dar continuidad a la carretera de Madrid a Barcelona y llegar hasta Santa Isabel, y al que poco despu‚îú¬Æs acompa‚îú‚ñíar‚îú¬°a a su izquierda un moderno puente de hierro y cemento. A su derecha, restos del antiguo puente de piedra. Al fondo y a la izquierda emerge una chimenea de la azucarera del G‚îú√≠llego sita en la margen derecha.', 1925, 1925, 1925, 'Anos 20', 'EL RABAL', 41.67121200, -0.84229900, '0101000020E61000001B834E081DF4EABF64575A46EAD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51489416585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51489416585.webp', 'https://www.flickr.com/photos/zaragozaantigua/51489416585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21728, 'Azucarera del G‚îú√≠llego 1931', 'Edificio de oficinas del complejo fabril de la Azucarera del G‚îú√≠llego. Tras el edificio, el muro que delimitaba la f‚îú√≠brica en un largo tramo de la carretera de Barcelona. Fuente visual: "A Don Benito Lewin y Auser como testimonio de sincero cari‚îú‚ñío y admiraci‚îú‚îÇn, con motivo del XXV Aniversario de su matrimonio le dedican este homenaje sus subordinados: Madrid, a 25 de Diciembre de 1931", en bibliotecavirtualmadrid.org/', 1931, 1931, 1931, 'Anos 30', 'EL RABAL', 41.67029300, -0.84513000, '0101000020E610000097CADB114E0BEBBF6EDE3829CCD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21095453598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21095453598.webp', 'https://www.flickr.com/photos/zaragozaantigua/21095453598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22316, 'R‚îú¬°o G‚îú√≠llego 1960', 'Vista a‚îú¬Ærea del puente sobre el r‚îú¬°o G‚îú√≠llego a su paso por Zaragoza y de la entrada del barrio de Santa Isabel (abajo). Fuente visual: Arxiu Nacional de Catalunya.', 1960, 1960, 1960, 'Anos 60', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15796511255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15796511255.webp', 'https://www.flickr.com/photos/zaragozaantigua/15796511255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22511, 'Vista a‚îú¬Ærea, c.1963', 'Vista a‚îú¬Ærea centrada en las antiguas instalaciones de Saica en la carretera de Huesca. Hacia el fondo, la factor‚îú¬°a de la Uni‚îú‚îÇn Alcoholera Espa‚îú‚ñíola, y los dep‚îú‚îÇsitos de combustible de Campsa. A la derecha, gran solar reservado para la urbanizaci‚îú‚îÇn del Grupo de Viviendas Balsas de Ebro Viejo.', 1963, 1963, 1963, 'Anos 60', 'EL RABAL', 41.67081200, -0.86982900, '0101000020E6100000A69883A0A3D5EBBFD6E1E82ADDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51054274293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51054274293.webp', 'https://www.flickr.com/photos/zaragozaantigua/51054274293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22533, 'Calle Anz‚îú√≠nigo 1970', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Enero 1970. Durante la Alcald‚îú¬°a-Presidencia de Jos‚îú¬Æ M‚î¨¬¨ S‚îú√≠nchez Ventura (1946-49), se emprende la construcci‚îú‚îÇn de la primera barriada obrera perif‚îú¬Ærica. Los terrenos elegidos estaban en el Picarral, entre el Camino de Juslibol y la Cra. de Huesca, donde construir un grupo de 6 manzanas con 645 viviendas ultrabaratas y varias tiendas, proyectado por los arquitectos municipales Jos‚îú¬Æ de Yarza y Jos‚îú¬Æ Beltr‚îú√≠n. El proyecto arranca en 1947, y las obras terminaron en 1949 aunque no se adjudicaron hasta 1952. El conjunto recibi‚îú‚îÇ el emotivo nombre de "Grupo de Viviendas Francisco Franco√î√á√ò. En la imagen, una de las calles del Grupo, denominada Anz‚îú√≠nigo, con el barrizal que se formaba los d‚îú¬°as de lluvia, y posteriores.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.67404100, -0.87280600, '0101000020E61000001A1538D906EEEBBFE294B9F946D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14731401410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14731401410.webp', 'https://www.flickr.com/photos/zaragozaantigua/14731401410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22542, 'San Juan de la Pe‚îú‚ñía c.1977', 'Transporte Oruga Acorazado M-113 pasa junto a un autob‚îú‚ïës urbano por la avenida de San Juan de la Pe‚îú‚ñía, en el barrio del Picarral, en su trayecto proveniente de las instalaciones militares de la carretera de Huesca. Durante d‚îú¬Æcadas, los vecinos de la zona tuvieron que soportar el amenazante paso de todo tipo de veh‚îú¬°culos militares en sus recorridos desde la Estaci‚îú‚îÇn del Arrabal hasta el campo de maniobras, y viceversa, como es el caso. La Asociaci‚îú‚îÇn de Vecinos del Picarral expresaba ante las autoridades civiles y militares su rechazo a esta actividad, que imposibilitaba la urbanizaci‚îú‚îÇn de la zona: Cada vez que que se hacen maniobras en el campo de San Gregorio, todo el equipo es descargado en la estaci‚îú‚îÇn (del Arrabal). Las movilizaciones y el transcurso del tiempo los eliminaron del paisaje. En la imagen, y hacia la derecha, comienza el camino de los Molinos.', 1977, 1977, 1977, 'Anos 70', 'EL RABAL', 41.67228900, -0.87116300, '0101000020E610000027874F3A91E0EBBFF33AE2900DD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14939266259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14939266259.webp', 'https://www.flickr.com/photos/zaragozaantigua/14939266259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22683, 'Calle del Gral. Monasterio 1979', 'Imagen capturada desde la calle Monte Perdido y centrada en la calle del General Monasterio (Grupo de Viviendas "Francisco Franco"), con el firme levantado por reformas. Al fondo, el camino de Juslibol y naves industriales de la textil CAITASA. En 2009, la denominaci‚îú‚îÇn de esta calle fue sustituida por la de Mar‚îú¬°a Dom‚îú¬°nguez Rem‚îú‚îÇn, pozuelera que en 1932 fue la primera mujer espa‚îú‚ñíola al frente de una alcald‚îú¬°a (Gallur), y que en 1936 ser‚îú¬°a fusilada en las tapias del cementerio de Fuendejal‚îú‚îÇn por los facciosos levantados en armas el 18-19 de julio de ese a‚îú‚ñío. Fuente visual: Banco de Im‚îú√≠genes/Asociaci‚îú‚îÇn de Vecinos Barrio de San Jos‚îú¬Æ, amablemente cedida para el', 1979, 1979, 1979, 'Anos 70', 'EL RABAL', 41.67329800, -0.87287500, '0101000020E61000003BDF4F8D97EEEBBF2A3BFDA02ED64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26612097959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26612097959.webp', 'https://www.flickr.com/photos/zaragozaantigua/26612097959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22705, 'C.‚î¨‚ïë de Juslibol c.1970', 'Imagen del antiguo camino de Juslibol en su natural faceta de barrizal tras unas lluvias, en el tramo comprendido entre la parcela del n‚î¨‚ïë 20 y el Grupo de viviendas "Teniente Polanco". Al fondo, el colegio p‚îú‚ïëblico San Braulio, algunas viviendas del Grupo de viviendas "Teniente Ortiz de Z‚îú√≠rate" y tras la calle del Valle de Broto, uno de los altos bloques del Grupo de viviendas "Balsas de Ebro Viejo". La chiquiller‚îú¬°a transita con ordinaria determinaci‚îú‚îÇn hacia al cole evitando los charcos mayores y el barro blando. Fuente visual: fotosdelpicarral.blogspot.com/', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66961200, -0.87390500, '0101000020E6100000BBF2599E07F7EBBF2C8194D8B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27807222877.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27807222877.webp', 'https://www.flickr.com/photos/zaragozaantigua/27807222877/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22710, 'Calle de San Juan de la Pe‚îú‚ñía c.1970', 'Imagen capturada en la calle de San Juan de la Pe‚îú‚ñía a la altura del inmueble del n‚îú‚ïëmero 155, esquinero con la calle del General Yag‚îú‚ïùe. A la derecha, vista parcial de la gran factor‚îú¬°a desmotadora de la Algodonera del Ebro, donde trabajara como mec‚îú√≠nico Manuel Rotellar Mata. Sobre el firme, en primer plano y entre el adoquinado, tendido viario de la l‚îú¬°nea 10 del tranv‚îú¬°a "Arrabal-Academia". En el centro de la imagen, una de las habituales zonas de agua de lluvia estancada de longeva duraci‚îú‚îÇn en el barrio del Picarral, junto a una cabina de tel‚îú¬Æfono p‚îú‚ïëblico. Fuente visual: fotosdelpicarral.blogspot.com/', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.67429400, -0.87145800, '0101000020E61000005BCD3AE3FBE2EBBFCCF10A444FD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28753111818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28753111818.webp', 'https://www.flickr.com/photos/zaragozaantigua/28753111818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22711, 'C.‚î¨‚ïë de Juslibol c.1970', 'Camino de Juslibol en una imagen capturada en el tramo entre el Grupo de viviendas Teniente Polanco y la calle de Juslibol, al fondo, donde destaca la achaflanada esquina de Talleres Unidos S.A., Tusa. A la izquierda, parcelas cuyas traseras daban al campo de f‚îú‚ïëtbol de la Federaci‚îú‚îÇn. A la derecha, parcelas de los n‚îú‚ïëmeros 10-36 del camino, de las que perduran la n‚î¨‚ïë 16 y la n‚î¨‚ïë 14, recrecida una altura. Sobre el terroso e irregular firme, caracter‚îú¬°stico de las barriadas perif‚îú¬Æricas, el autob‚îú‚ïës Seddon n‚î¨‚ïë 23 en servicio en la l‚îú¬°nea 28. Lonja-Picarral, que fue inaugurada en 1964 para sustituir a la provisional Murallas Romanas-Ortilla, establecida a su vez para paliar la supresi‚îú‚îÇn de la pasarela de Macanaz con motivo de la construcci‚îú‚îÇn del puente de Santiago. Fue suprimida en 1977 al integrarse su recorrido en la nueva l‚îú¬°nea 36. Valdefierro-Picarral.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.66961200, -0.87390500, '0101000020E6100000BBF2599E07F7EBBF2C8194D8B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28770223898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28770223898.webp', 'https://www.flickr.com/photos/zaragozaantigua/28770223898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22757, 'San Juan de la Pe‚îú‚ñía 1972', 'Imagen capturada en la avenida de San Juan de la Pe‚îú‚ñía, poco antes de llegar a la enlazadora avenida del Alcalde Francisco Caballero. Al fondo, el puente de la autopista del Nordeste en construcci‚îú‚îÇn, la f‚îú√≠brica de maquinaria CALSA, y la antigua carretera de Huesca que contin‚îú‚ïëa ascendente en direcci‚îú‚îÇn norte. En primer plano, obras de alcantarillado, adoquines levantados del firme y tendido tranviario de la recientemente clausurada l‚îú¬°nea 10 "Arrabal-Academia".', 1972, 1972, 1972, 'Anos 70', 'EL RABAL', 41.67704800, -0.87114800, '0101000020E6100000D2393FC571E0EBBF3EE94482A9D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32791001713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32791001713.webp', 'https://www.flickr.com/photos/zaragozaantigua/32791001713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22760, 'Monte Perdido 1978', 'Imagen de la calle Monte Perdido capturada desde cierta altura (posiblemente, desde el n‚î¨‚ïë 11 del bloque luego denominado "Jardines de la Concordia", recayente a San Juan de la Pe‚îú‚ñía), que acent‚îú‚ïëa el impacto (desde varios puntos de vista) de las industrias inmediatas, y al norte, de la calle Somport y el Grupo de Viviendas "Francisco Franco": Gesplasmetal, y Campo Ebro. Al fondo, vista parcial de algunos de los montes militarizados en el entorno a la AGM. Fuente visual: Banco de Im‚îú√≠genes/Asociaci‚îú‚îÇn de Vecinos Barrio de San Jos‚îú¬Æ, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.67450000, -0.87271400, '0101000020E6100000EE5C18E945EDEBBF7593180456D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32898657230.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32898657230.webp', 'https://www.flickr.com/photos/zaragozaantigua/32898657230/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22761, 'Av. San Juan de la Pe‚îú‚ñía 1978', 'Imagen del tramo de la avenida de San Juan de la Pe‚îú‚ñía que, casi desde la calle de Maella (a la derecha, fuera de plano), y hasta la avenida Alcalde Francisco Caballero (a las espaldas del fot‚îú‚îÇgrafo), fue impactado por una de las tremendas colmenas humanas realizadas en la ciudad por la famosa empresa Construcciones Colmenero SA. Al "mejor piso" en este sector, seg‚îú‚ïën reza el comercial, parece no acompa‚îú‚ñíarle una urbanizaci‚îú‚îÇn que est‚îú¬Æ a su vertiginosa altura. Fuente visual: Banco de Im‚îú√≠genes/Asociaci‚îú‚îÇn de Vecinos Barrio de San Jos‚îú¬Æ, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.67684800, -0.87090100, '0101000020E6100000E1B721C66BDEEBBF772E8CF4A2D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32976402762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32976402762.webp', 'https://www.flickr.com/photos/zaragozaantigua/32976402762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22765, 'Monte Perdido 1978', 'Imagen capturada en la calle Monte Perdido, con vista parcial del Grupo de Viviendas "Francisco Franco", y el arranque de los viales General Valera (luego M‚î¨¬¨ S‚îú√≠nchez Arb‚îú‚îÇs), General Moscard‚îú‚îÇ (Luego Juan Cabrt‚îú¬Æ Aguil‚îú‚îÇ), General Jos‚îú¬Æ Monasterio (luego M‚î¨¬¨ Dom‚îú¬°nguez Rem‚îú‚îÇn), Batalla del Ebro (luego Arturo Bressel Marca), y Posici‚îú‚îÇn San Sim‚îú‚îÇn (luego Teresa Ag‚îú‚ïùesca). Todas estas calles, otro ejercicio de la abrumadora y oficial memoria hist‚îú‚îÇrica del r‚îú¬Ægimen franquista, conflu‚îú¬°an hacia la izquierda en el Camino de Juslibol y las instalaciones de CAITASA. Al fondo, muros perimetrales de la empresa Geplasmetal. Fuente visual: Banco de Im‚îú√≠genes/Asociaci‚îú‚îÇn de Vecinos Barrio de San Jos‚îú¬Æ, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'EL RABAL', 41.67301000, -0.87276800, '0101000020E6100000BAD91F28B7EDEBBFC3F0113125D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33225793916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33225793916.webp', 'https://www.flickr.com/photos/zaragozaantigua/33225793916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22794, 'Calle del General Yag‚îú‚ïùe c.1970', 'Imagen capturada en la calle del General Yag‚îú‚ïùe. A la izquierda, vista parcial del bloque del Grupo de viviendas "General Franco" (inmuebles 2 y 4), y tras la calle del Monte Perdido, la gran factor‚îú¬°a desmotadora de la Algodonera del Ebro. Al fondo, la calle de San Juan de la Pe‚îú‚ñía, donde emergen las monta‚îú‚ñías de paja de SAICA y el esquinero inmueble del n‚î¨‚ïë 155. A la derecha, parcelas de los n‚îú‚ïëmeros 1 a 19 de General Yag‚îú‚ïùe, incluyendo el local del mercadillo "el Pilar", y fuera de plano, traseras de la f‚îú√≠brica TUSA. El acu‚îú√≠tico y terroso centro de la imagen incorpora una de las habituales escenas de las barriadas de la ciudad hasta hace no demasiado tiempo: ni‚îú‚ñíos que juegan en la calle interactuando libre y literalmente con cualquier elemento del entorno.', 1970, 1970, 1970, 'Anos 70', 'EL RABAL', 41.67269700, -0.87319700, '0101000020E6100000D6E3BED53AF1EBBF048F6FEF1AD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42731518741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42731518741.webp', 'https://www.flickr.com/photos/zaragozaantigua/42731518741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23468, 'P.‚î¨‚ïë de Ruise‚îú‚ñíores c.1950', 'Imagen de la que fuera originalmente vivienda unifamiliar de Raimundo Balet proyectada por Manuel Isasi Isasmendi en 1903 y sita en el "barrio de Ruise‚îú‚ñíores", ya notablemente reformada por intervenciones como la de 1919 con dise‚îú‚ñío de Miguel ‚îú√ºngel Navarro P‚îú¬Ærez, y alguna otra posterior que le a‚îú‚ñíadi‚îú‚îÇ su elemento arquitect‚îú‚îÇnico m‚îú√≠s reconocible: el modernista y esquinero torreoncillo a la izquierda de la imagen. Cuando era propiedad de Ram‚îú‚îÇn de Pedro, esta fotograf‚îú¬°a fue realizada para publicitar el edificio como colegio de bachillerato "Los ‚îú√ºngeles" en el paseo de Ruise‚îú‚ñíores n‚î¨‚ïë 39. Tras unos a‚îú‚ñíos en desuso, a finales de la d‚îú¬Æcada de los a‚îú‚ñíos cincuenta el edificio cambi‚îú‚îÇ de propietarios y fue convertido en el nuevo colegio Santo Tom‚îú√≠s de Aquino de bachillerato masculino, lo que conllev‚îú‚îÇ una ampliaci‚îú‚îÇn edilicia en las ajardinadas traseras, y una reforma interna y de la fachada. As‚îú¬° continu‚îú‚îÇ hasta su clausura en 1986. Fuente visual: www.todocoleccion.net/', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.63651000, -0.88907700, '0101000020E61000007D06D49B5173ECBFDAC9E02879D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30474886347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30474886347.webp', 'https://www.flickr.com/photos/zaragozaantigua/30474886347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22939, 'Av. de Salvador Allende c.1981', 'Desde la altura de la autopista a Barcelona, vista del tramo final de la avenida de Salvador Allende hasta su desemboque en la avenida de San Juan de la Pe‚îú‚ñía, a la izquierda, donde se elevan los bloques de los n‚îú‚ïëmeros 181-195 de la irracional manzana que hacia el fondo llega hasta la actual calle de Ob‚îú‚îÇn. A su derecha e inmediatas, las descomunales instalaciones de la transformadora industrial del ma‚îú¬°z Campo Ebro Industrial, fundada en 1964 y que perdura como Tereos Syral, uno de los tradicionales focos de contaminaci‚îú‚îÇn y malos olores del Picarral. En primer plano, terraplenes y montoneras que anuncian el inicio de las obras de urbanizaci‚îú‚îÇn de la m‚îú√≠s norte‚îú‚ñía intervenci‚îú‚îÇn del Actur-Puente de Santiago, vertebrada por la actuales calles de Federico Engels y de Jean-Paul Sartre. Junto a la carretera, una parada de la l‚îú¬°nea 29. Plaza del Pilar-Academia General Militar del autob‚îú‚ïës urbano reclama publicidad. Fuente visual: Banco de Im‚îú√≠genes/Asociaci‚îú‚îÇn de Vecinos Barrio de San Jos‚îú¬Æ, amablemente cedida para el', 1981, 1981, 1981, 'Anos 80', 'EL RABAL', 41.67810800, -0.87182200, '0101000020E6100000B1DD3D40F7E5EBBFF793313ECCD64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32857688880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32857688880.webp', 'https://www.flickr.com/photos/zaragozaantigua/32857688880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22941, 'Av. de San Juan de la Pe‚îú‚ñía c.1981', 'Imagen capturada posiblemente desde la altura de la reciente autopista del Nordeste, con una interesante visual del entronque de las avenidas Alcalde Francisco Caballero, con la de San Juan de la Pe‚îú‚ñía, y su continuaci‚îú‚îÇn hacia la MAZ y la AGM. A la izquierda, e inmediata, la factor‚îú¬°a de maquinaria CALSA. Al fondo, chimeneas de la papelera SAICA. Esta zona fue considerada por un tiempo el "nec plus ultra" en t‚îú¬Ærminos de ciudad, hasta que a finales de siglo fue presentado el Plan Parcial de las ‚îú√≠reas 2, 4, 5 y 6, o "Ciudad Jard‚îú¬°n Puerta de los Pirineos", luego Parque Goya I, y II. Fuente visual: Banco de Im‚îú√≠genes/Asociaci‚îú‚îÇn de Vecinos Barrio de San Jos‚îú¬Æ, amablemente cedida para el', 1981, 1981, 1981, 'Anos 80', 'EL RABAL', 41.67829100, -0.87109400, '0101000020E610000006BD378600E0EBBFE8154F3DD2D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33170074526.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33170074526.webp', 'https://www.flickr.com/photos/zaragozaantigua/33170074526/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22949, 'Margen izquierda 1981', 'Ortofoto de 1981 de los barrios de la margen izquierda del r‚îú¬°o Ebro, al norte de Zaragoza: Picarral, Cogullada, Arrabal y La Jota. M‚îú√≠s al norte, San Gregorio y Mercazaragoza. Fuente: Instituto Geogr‚îú√≠fico de Arag‚îú‚îÇn.', 1981, 1981, 1981, 'Anos 80', 'EL RABAL', 41.67442400, -0.87573000, '0101000020E6100000D908C4EBFA05ECBF9AD18F8653D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39665105410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39665105410.webp', 'https://www.flickr.com/photos/zaragozaantigua/39665105410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23008, 'Picarral 1990', 'Imagen del antiguo campo de la Federaci‚îú‚îÇn en el Picarral, en activo desde 1957, donde jugaban como locales aquellos equipos cercanos que carec‚îú¬°an de campo propio. En 1992, dos de ellos, el C.D. Picarral y la U.D. Balsas Ebro Viejo se unificaron en el U.D. Balsas Picarral, y a finales de esa d‚îú¬Æcada este campo fue derribado y construido uno de titularidad municipal, nueva planta, y orientaci‚îú‚îÇn: de la original W-E, se pas‚îú‚îÇ a la actual N-S. A la izquierda de la imagen, bloques de la calle Pantano de la Sotonera. Al fondo, construcciones en el entorno de la avenida de Salvador Allende y la paralela calle de Alberto Casa‚îú‚ñíal Shakery. A la derecha, fuera de plano, la calle de Juslibol. El lagunazo a la izquierda, resultado de la natural acumulaci‚îú‚îÇn de precipitaciones en forma de agua. Fuente visual: Antonio Calvo Pedr‚îú‚îÇs, AMZ.', 1990, 1990, 1990, 'Anos 90', 'EL RABAL', 41.66959600, -0.87458100, '0101000020E6100000C87E164B91FCEBBF26C45C52B5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30740957455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30740957455.webp', 'https://www.flickr.com/photos/zaragozaantigua/30740957455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23009, 'Picarral c.1991', 'Imagen a‚îú¬Ærea del entorno de la estaci‚îú‚îÇn de ferrocarril "Arrabal Clasificaci‚îú‚îÇn", centrada en las instalaciones fabriles de la metal‚îú‚ïërgica "Rico y Echeverr‚îú¬°a S.A." (desaparecida), y la papelera "Saica" (perdura). A la derecha, el mar de v‚îú¬°as ferroviario, y el pol‚îú¬°gono "Cogullada". Fuente visual: ‚îú√ºngel Gonz‚îú√≠lez, a trav‚îú¬Æs de www.forotrenes.com/', 1991, 1991, 1991, 'Anos 90', 'EL RABAL', 41.67111000, -0.86828300, '0101000020E61000005187156EF9C8EBBF6002B7EEE6D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31005690961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31005690961.webp', 'https://www.flickr.com/photos/zaragozaantigua/31005690961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23034, 'Actur 1992', 'A‚îú¬Ærea vista del noreste del Actur con el desarrollo edilicio del momento, capturada con el fondo de la ciudad consolidada donde a la izquierda se destaca la silueta del templo del Pilar. En el centro de la escena, la Autopista del Ebro o A-2 se‚îú‚ñíala de izquierda a derecha el l‚îú¬°mite del desarrollo urbano. A‚îú‚ñíos despu‚îú¬Æs, donde los campos de herb‚îú√≠ceas de primer t‚îú¬Ærmino, comenzar‚îú√≠ a desarrollarse el proyecto "Ciudad Jard‚îú¬°n Puerta de los Pirineos", luego Parque Goya. Vertebra la imagen de sur a norte la avenida de los Pirineos, que tras el cruce con la A-2 contin‚îú‚ïëa como carretera de Huesca, unos a‚îú‚ñíos despu‚îú¬Æs convertida en autov‚îú¬°a. Entre las calles de Federico Engels y de las Islas Canarias se destacan todav‚îú¬°a por su decreciente soledad los pioneros centros educativos de esta perif‚îú¬Ærica zona de la ciudad, ambos en funcionamiento desde 1980, cuando el panorama estaba bastante m‚îú√≠s despejado: el Instituto de Educaci‚îú‚îÇn Secundaria Avempace, denominaci‚îú‚îÇn de 1988 del original Instituto de Bachillerato Mixto n‚î¨‚ïë 10, durante muchos a‚îú‚ñíos ‚îú‚ïënico centro de ense‚îú‚ñíanzas medias de la margen izquierda; y el Colegio de Educaci‚îú‚îÇn Infantil y Primaria Zalfonada, que comenz‚îú‚îÇ siendo colegio Arrabal-Picarral.', 1992, 1992, 1992, 'Anos 90', 'EL RABAL', 41.67991500, -0.87824100, '0101000020E6100000E833A0DE8C1AECBFA987687407D74440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50209951253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50209951253.webp', 'https://www.flickr.com/photos/zaragozaantigua/50209951253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23162, 'Avenida Catalu‚îú‚ñía 2007', 'Edificio de oficinas y ventas del concesionario Opel Iglesias, en la avenida de Catalu‚îú‚ñía 243. Se inaugur‚îú‚îÇ en 2007 seg‚îú‚ïën proyecto de J1 Arquitectos. Gan‚îú‚îÇ el XXIX Premio Ricardo Magdalena de la Instituci‚îú‚îÇn Fernando el Cat‚îú‚îÇlico. Fue abandonado en 2013, y demolido en 2016. Fuente visual: j1arquitectos.com/', 2007, 2007, 2007, 'Siglo XXI', 'EL RABAL', 41.66998800, -0.84951300, '0101000020E6100000F0DB10E3352FEBBF315BB22AC2D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32549229466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32549229466.webp', 'https://www.flickr.com/photos/zaragozaantigua/32549229466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23258, 'Acequia Urdana c.1920', 'Molino del Mosnillo y acequia Urdana en Movera. Al fondo, puente de Santa Isabel sobre el r‚îú¬°o G‚îú√≠llego. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'EL RABAL', 41.66985700, -0.84089400, '0101000020E61000004CE2AC889AE8EABF93FFC9DFBDD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24796545782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24796545782.webp', 'https://www.flickr.com/photos/zaragozaantigua/24796545782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23743, 'Puente sobre el G‚îú√≠llego c.1907', 'Se‚îú‚ñíora (posiblemente ‚îú√ángela Llinars, esposa del fot‚îú‚îÇgrafo de la imagen) cruzando el puente colgante sobre el r‚îú¬°o G‚îú√≠llego. Al fondo, a la izquierda, la antigua harinera de Villarroya y Castellano, constituida en el a‚îú‚ñío 1848 con ocho muelas sobre un antiguo bat‚îú√≠n del siglo XVI sito en la bifurcaci‚îú‚îÇn del camino de Monta‚îú‚ñíana con el camino de Barcelona. Se incendi‚îú‚îÇ en 1855, y dos a‚îú‚ñíos despu‚îú¬Æs fue reconstruida. En 1881 fue pionera en la introducci‚îú‚îÇn en Espa‚îú‚ñía de mejoras t‚îú¬Æcnicas, como el sistema austroh‚îú‚ïëngaro. En 1899 fue reconvertida en f‚îú√≠brica azucarera denominada "Nueva Azucarera de Zaragoza", cuya sociedad ser‚îú¬°a disuelta en 1908 por muy malos resultados econ‚îú‚îÇmicos. Fuente visual: foto Miquel Pons Bernareggi, en Arxiu Nacional de Catalunya.', 1907, 1907, 1907, 'Anos 1900', 'EL RABAL', 41.67089500, -0.84201500, '0101000020E6100000E0B9F770C9F1EABF64062AE3DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14923233091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14923233091.webp', 'https://www.flickr.com/photos/zaragozaantigua/14923233091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23751, 'Puente del G‚îú√≠llego 1897', 'El G‚îú√≠llego era un r‚îú¬°o que se sal‚îú¬°a de madre con natural frecuencia, llev‚îú√≠ndose por delante puentes de madera y de piedra, fueran del tama‚îú‚ñío que fueran. En 1844 se inaugur‚îú‚îÇ una nueva modalidad, en hierro, y colgante, para salvar los 136 metros de trinchera fluvial en la estrat‚îú¬Ægica carretera de Madrid a Francia. Fue terminado en 1844, pero ya en 1846 tuvo que ser reparado, y en 1862 hubo que construir defensas en las m‚îú√≠rgenes del r‚îú¬°o. En 1869 finaliz‚îú‚îÇ la contrata de 25 a‚îú‚ñíos para explotar aranceles y portazgos, y pas‚îú‚îÇ a titularidad p‚îú‚ïëblica. En 1871 la magna crecida del Ebro tuvo su tremendo correlato en las aguas que por aqu‚îú¬° ven‚îú¬°an de Francia, y hubo que hacer m‚îú√≠s reparaciones, como en 1878. En 1888 se plante‚îú‚îÇ un nuevo gran proyecto, cuyo resultado es el que la imagen recoge. En los a‚îú‚ñíos 20 del pasado siglo este puente fue sustituido por uno nuevo, tambi‚îú¬Æn met‚îú√≠lico, sobre cimientos hasta 15 metros por debajo del nivel del r‚îú¬°o, y capaz de soportar el creciente tr‚îú√≠fico rodado. Mientras ‚îú¬Æste se constru‚îú¬°a, el m‚îú√≠s antiguo garantizaba la continuidad del tr‚îú√≠nsito. Cuando el nuevo fue terminado e inaugurado en 1930, el viejo ser‚îú√≠ luego derribado. En la imagen, visual del puente colgante de Santa Isabel, mirando desde la ribera derecha. Al fondo, a la izquierda, chimenea e instalaciones de la antigua harinera de "Villarroya y Castellano", poco antes de convertirse en azucarera. A la derecha, el comienzo de los barrios de Santa Isabel, y Movera. Fuente visual: "Delimitaci‚îú‚îÇn Comarcal de Zaragoza" (Colecci‚îú‚îÇn Territorio), DGA, 2011.', 1897, 1897, 1897, 'Siglo XIX', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18957678321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18957678321.webp', 'https://www.flickr.com/photos/zaragozaantigua/18957678321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23754, 'Puente de Santa Isabel 1844', '"Puente colgante de hierro sobre el r‚îú¬°o G‚îú√≠llego, en Zaragoza. Inaugurado el d‚îú¬°a 18 de Noviembre de 1844, con el nombre de Santa Isabel", litograf‚îú¬°a de L. Cuevas para el ‚îú√ºlbum art‚îú¬°stico de los grandes monumentos de Zaragoza, 1838-1844. Imagen del reci‚îú¬Æn construido puente de Santa Isabel sobre el r‚îú¬°o G‚îú√≠llego. Fuente: ‚îú√ºlbum gr‚îú√≠fico de Zaragoza, 1985.', 1844, 1844, 1844, 'Siglo XIX', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19318574589.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19318574589.webp', 'https://www.flickr.com/photos/zaragozaantigua/19318574589/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23759, 'Puente de Santa Isabel 1913', 'Foto: Lorenzo Almarza. Dos militares contemplan los bajos del puente colgante de Santa Isabel sobre el r‚îú¬°o G‚îú√≠llego, en 1913. Al fondo, el barrio de Santa Isabel. Fuente: Archivo Diputaci‚îú‚îÇn Provincial de Huesca.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67094700, -0.84216000, '0101000020E6100000C2FA3F87F9F2EABFB62C5F97E1D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21439051996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21439051996.webp', 'https://www.flickr.com/photos/zaragozaantigua/21439051996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23762, 'Vacas en el G‚îú√≠llego c.1913', 'Vista del Puente de Santa Isabel sobre el r‚îú¬°o G‚îú√≠llego, con vacas en la orilla izquierda. Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag‚îú‚îÇn", UGT, 2000.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67076200, -0.84186000, '0101000020E61000001CF0F96184F0EABF25B37A87DBD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23981044001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23981044001.webp', 'https://www.flickr.com/photos/zaragozaantigua/23981044001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23763, 'Puente Santa Isabel 1890', 'Imagen capturada durante las obras de construcci‚îú‚îÇn del nuevo puente "colgado" (sic) de Santa Isabel sobre el r‚îú¬°o G‚îú√≠llego, que ven‚îú¬°a a sustituir al anterior de mediados de siglo, bastante necesitado de reparaciones y mejoras. Fuente visual: Revista de Obras P‚îú‚ïëblicas.', 1890, 1890, 1890, 'Siglo XIX', 'EL RABAL', 41.67076200, -0.84186000, '0101000020E61000001CF0F96184F0EABF25B37A87DBD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24211362313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24211362313.webp', 'https://www.flickr.com/photos/zaragozaantigua/24211362313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23769, 'Puente de Santa Isabel 1916', 'Aspecto del puente colgante sobre el r‚îú¬°o G‚îú√≠llego, con el barrio de Santa Isabel al fondo, durante una carrera automovil‚îú¬°stica desde Barcelona hasta Madrid. Fuente: foto Josep Maria Co i de Triola, en Arxiu Fotogr‚îú√°fic Centre Excursionista de Catalunya.', 1916, 1916, 1916, 'Anos 10', 'EL RABAL', 41.67107800, -0.84236800, '0101000020E61000003C4D66BCADF4EABF558847E2E5D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30514280615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30514280615.webp', 'https://www.flickr.com/photos/zaragozaantigua/30514280615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23770, 'Puente de Santa Isabel 1917', 'Imagen del antiguo puente colgante de hierro por el que la carretera de Madrid a Francia salvaba el r‚îú¬°o G‚îú√≠llego desde 1888. La captura se ha realizado desde el disminuido cauce, cuando un carro est‚îú√≠ cruzando a contraluz desde Santa Isabel, hacia Zaragoza. Fuente visual: Carles Batlle Ensesa, Ajuntament de Girona.', 1917, 1917, 1917, 'Anos 10', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30998469254.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30998469254.webp', 'https://www.flickr.com/photos/zaragozaantigua/30998469254/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23778, 'Puente del G‚îú√≠llego c.1905', 'Imagen del reciente puente colgante del G‚îú√≠llego, por donde pasaba la carretera de Madrid a Francia. Al fondo, el barrio de Santa Isabel, en la margen izquierda de dicho r‚îú¬°o. Fuente visual: www.todocoleccion.net/', 1905, 1905, 1905, 'Anos 1900', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33429955892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33429955892.webp', 'https://www.flickr.com/photos/zaragozaantigua/33429955892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23779, 'Puente de Santa Isabel 1908', 'Imagen del reciente puente colgante sobre el G‚îú√≠llego, por donde pasaba la carretera de Madrid a Francia. Al fondo, el barrio rural de Santa Isabel, en la margen izquierda de dicho r‚îú¬°o, con las instalaciones de la Nueva Azucarera de Zaragoza, que fuera antigua harinera de Villarroya y Castellano. Fuente visual: "Zaragoza art‚îú¬°stica ‚îú¬Æ industrial. Album de la Exposici‚îú‚îÇn. 1908."', 1908, 1908, 1908, 'Anos 1900', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33883343163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33883343163.webp', 'https://www.flickr.com/photos/zaragozaantigua/33883343163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23780, 'Puente sobre el G‚îú√≠llego c.1913', 'Imagen capturada en el puente colgante sobre el r‚îú¬°o G‚îú√≠llego, por donde transitaba la carretera de Madrid a Francia por Barcelona. Al fondo, el barrio de Santa Isabel. Esta fue la ‚îú‚ïëltima de las versiones de este puente colgante, ubicado en una muy antigua localizaci‚îú‚îÇn que conoci‚îú‚îÇ diversos modelos de puente desde al menos la Alta Edad Media. A finales de la d‚îú¬Æcada de los a‚îú‚ñíos veinte fue sustituido por un puente de nueva f‚îú√≠brica dise‚îú‚ñíado para soportar el moderno tr‚îú√≠fico rodado a motor de explosi‚îú‚îÇn. Fuente visual: El fot‚îú‚îÇgrafo Luis Gand‚îú‚ïë Mercadal. Una cr‚îú‚îÇnica visual 1910-1930.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67086900, -0.84209700, '0101000020E610000029E9616875F2EABF3B730F09DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37010935270.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37010935270.webp', 'https://www.flickr.com/photos/zaragozaantigua/37010935270/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23782, 'Puente del G‚îú√≠llego c.1915', 'Imagen capturada desde la margen izquierda del r‚îú¬°o G‚îú√≠llego y centrada en el hom‚îú‚îÇnimo puente colgante. En primer t‚îú¬Ærmino, y aprovechando el estival bajo nivel del r‚îú¬°o, varios canteros extraen cantos rodados de la gravera fluvial, que luego cargar‚îú√≠n en los carros situados en la margen derecha para emplearlos en obras varias en la ciudad. En este di‚îú√≠fano espacio en 1926 se emprender‚îú√≠n las obras de construcci‚îú‚îÇn del moderno puente met‚îú√≠lico tendido entre el desaparecido medieval y el puente colgante, para habilitar un paso m‚îú√≠s seguro a la creciente circulaci‚îú‚îÇn motorizada de la carretera nacional.', 1915, 1915, 1915, 'Anos 10', 'EL RABAL', 41.67087600, -0.84181600, '0101000020E610000033FCA71B28F0EABFEDD5C743DFD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47984410946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47984410946.webp', 'https://www.flickr.com/photos/zaragozaantigua/47984410946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23785, 'Puente del G‚îú√≠llego viejo 1913', 'Imagen centrada en la arcada superviviente del antiguo y desaparecido medieval puente de piedra sobre el r‚îú¬°o G‚îú√≠llego, junto al que en 1890 se construy‚îú‚îÇ el moderno puente "colgado" o colgante de Santa Isabel, desde donde se ha capturado la foto en la margen derecha, no muy lejos de la azucarera del G‚îú√≠llego.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.67127100, -0.84260900, '0101000020E6100000A5164A26A7F6EABF69E04735ECD54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51691098725.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51691098725.webp', 'https://www.flickr.com/photos/zaragozaantigua/51691098725/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24459, 'Azucarera del G‚îú√≠llego 1913', 'Azucarera del G‚îú√≠llego en 1913. Esta azucarera se puso en marcha en 1913 y cerr‚îú‚îÇ en 1967. Estaba situada en la orilla del r‚îú¬°o G‚îú√≠llego, en Zaragoza. En la foto vemos el puente colgante, a la izquierda. Fuente: M‚î¨¬¨ Pilar Biel Ib‚îú√≠‚îú‚ñíez, Zaragoza y la industrializaci‚îú‚îÇn: la arquitectura industrial 1875-1936, IFC, 2004.', 1913, 1913, 1913, 'Anos 10', 'EL RABAL', 41.66970600, -0.84465800, '0101000020E6100000A9C0C9367007EBBFADF71BEDB8D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19705751651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19705751651.webp', 'https://www.flickr.com/photos/zaragozaantigua/19705751651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24502, 'Picarral 1984', 'Imagen en altura desde el reciente n‚î¨‚ïë 7-9 de la calle Antonio Tramullas (antiguo Camino de Juslibol) del impresionante aspecto de la factor‚îú¬°a de Campo Ebro Industrial, cuya impronta sobre el barrio del Picarral era extraordinaria. Fue instalada a comienzos de la d‚îú¬Æcada de los a‚îú‚ñíos 60 como una potente iniciativa para la transformaci‚îú‚îÇn industrial del ma‚îú¬°z. Tras la recuperaci‚îú‚îÇn de la democracia municipal, el vecindario se moviliz‚îú‚îÇ para solicitar su cierre y traslado. El Plan General de Ordenaci‚îú‚îÇn Urbana aprobado en 1984, mantuvo la calificaci‚îú‚îÇn de este suelo como "industrial", con los votos favorables de la mayor‚îú¬°a socialista, y los votos de la derecha estatal. La derecha regionalista se abstuvo, y vot‚îú‚îÇ en contra el concejal comunista. En la imagen, parece evidente que los limpios y verdes colores con los que la empresa pint‚îú‚îÇ sus instalaciones, no atenuaban el impacto ambiental sobre el entorno. A la derecha, los bloques de viviendas del entorno de la calle Ob‚îú‚îÇn, y San Juan de la Pe‚îú‚ñía. El humo no deja ver mucho m‚îú√≠s. A la izquierda, al fondo, el complejo de la MAZ. Fuente visual: Banco de Im‚îú√≠genes Picarral fotosdelpicarral.blogspot.com.es/', 1984, 1984, 1984, 'Anos 80', 'EL RABAL', 41.67635100, -0.87361500, '0101000020E6100000F870C971A7F4EBBFF6CE68AB92D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31087168441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31087168441.webp', 'https://www.flickr.com/photos/zaragozaantigua/31087168441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24504, 'San Juan de la Pe‚îú‚ñía 1965', 'Imagen a‚îú¬Ærea sobrevolando las inmediaciones del achaflanado encuentro entre la avenida de San Juan de la Pe‚îú‚ñía, que luminosa asciende rectil‚îú¬°nea desde la ciudad, al fondo, y la tranquila y alabeada calle de Francisco Alcalde Caballero que entronca con ella desde la izquierda. En ese punto, la imagen se centra en las longitudinales instalaciones fabriles de CALSA (Construcciones Agromet‚îú√≠licas de Levante, S.A.), dedicadas al montaje de gr‚îú‚ïëas sobre veh‚îú¬°culos diversos, as‚îú¬° como tractores, remolques y palas cargadoras. Antes, y a ambos lados de San Juan de la Pe‚îú‚ñía, otras f‚îú√≠bricas como Coromina Industrial, junto al camino de los Molinos, y grupos de viviendas como el de Francisco Franco, junto a la CAITASA. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.67801200, -0.87036300, '0101000020E610000016C0948103DAEBBFD525E318C9D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31770132461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31770132461.webp', 'https://www.flickr.com/photos/zaragozaantigua/31770132461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24505, 'Alcalde Caballero 1965', 'Imagen capturada sobrevolando la despejada calle del Alcalde Francisco Caballero, muy cerca del antiguo camino de Cogullada (inmediato y a la derecha, fuera de plano), centrada en las nuevas instalaciones de "Manuzac", una de las empresas pioneras del pol‚îú¬°gono de Cogullada. A la izquierda, el paso elevado que salva la l‚îú¬°nea del ferrocarril a Huesca y Canfranc, poco antes de la construcci‚îú‚îÇn del nuevo enlace desde Miraflores. Al fondo, la zona industrial del camino de los Molinos y la Corbera Alta, el nuevo colegio de Cristo Rey, y los pabellones de la Academia General Militar junto a la carretera de Huesca. A la derecha, y al fondo, el original Sanatorio Antituberculoso del Cascajo, encaminado a su conversi‚îú‚îÇn en hospital de especialidades en enfermedades del t‚îú‚îÇrax. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'EL RABAL', 41.67217800, -0.86143700, '0101000020E61000002C0FD253E490EBBF9C8BBFED09D64440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31797966931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31797966931.webp', 'https://www.flickr.com/photos/zaragozaantigua/31797966931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
